function useSolidBackground() {
  React.useEffect(() => {
    let el = document.getElementById("solid-navy-bg");
    if (!el) {
      el = document.createElement("style");
      el.id = "solid-navy-bg";
      document.head.appendChild(el);
    }
    el.textContent = SOLID_BG_CSS;
  }, []);
}

/* -------------------- Hide the "Open Sandbox" overlay injected by the host -------------------- */

function useHideOpenSandbox() {
  React.useEffect(() => {
    const style = document.createElement("style");
    style.id = "hide-open-sandbox";
    style.textContent = `
      a[aria-label="Open Sandbox"],
      a[title="Open Sandbox"],
      button[aria-label="Open Sandbox"],
      .open-sandbox,
      .sandbox-open,
      [data-testid="open-sandbox"] {
        display: none !important;
        visibility: hidden !important;
        pointer-events: none !important;
      }
    `;
    document.head.appendChild(style);

    const nuke = () => {
      document.querySelectorAll("a,button,div").forEach((el) => {
        if ((el.textContent || "").trim() === "Open Sandbox") {
          el.style.display = "none";
          el.style.visibility = "hidden";
          el.style.pointerEvents = "none";
        }
      });
    };
    nuke();
    const obs = new MutationObserver(nuke);
    obs.observe(document.body, { childList: true, subtree: true });

    return () => {
      obs.disconnect();
      style.remove();
    };
  }, []);
}

