/* -------------------- BD&L licensing modal -------------------- */
const BDL_CSS = `
  .bdlModalOverlay{position:fixed;inset:0;z-index:999999;display:grid;place-items:center;padding:18px;background:rgba(2,6,23,.72);backdrop-filter:blur(10px);}
  .bdlModalCard{width:min(900px,calc(100vw - 24px));max-height:calc(100dvh - 28px);overflow:auto;border-radius:28px;padding:22px;color:#e5e7eb;background:linear-gradient(145deg,rgba(15,23,42,.98),rgba(30,41,59,.96));border:1px solid rgba(125,211,252,.24);box-shadow:0 30px 90px rgba(0,0,0,.55),0 0 0 1px rgba(255,255,255,.04) inset;}
  .bdlModalHead{display:flex;justify-content:space-between;gap:14px;align-items:flex-start;}
  .bdlKicker{letter-spacing:.16em;text-transform:uppercase;color:#38bdf8;font-weight:950;font-size:12px;}
  .bdlModalHead h2{margin:6px 0 8px;font-size:30px;line-height:1.05;color:#fff;}
  .bdlModalHead p{margin:0;color:#cbd5e1;line-height:1.45;}
  .bdlClose{border:1px solid rgba(148,163,184,.35);background:rgba(15,23,42,.85);color:#e5e7eb;border-radius:14px;width:38px;height:38px;font-size:24px;cursor:pointer;}
  .bdlLeadBox{margin:18px 0;padding:14px;border-radius:18px;background:rgba(2,6,23,.45);border:1px solid rgba(148,163,184,.22);}
  .bdlLeadClient{font-weight:950;color:#fff;font-size:18px;}
  .bdlLeadMeta{margin-top:5px;color:#94a3b8;font-weight:700;}
  .bdlGrid{display:grid;grid-template-columns:1fr 1fr;gap:14px;}
  .bdlField{display:grid;gap:8px;padding:14px;border-radius:18px;background:rgba(15,23,42,.76);border:1px solid rgba(148,163,184,.18);}
  .bdlField span{font-weight:950;color:#e2e8f0;}
  .bdlField input,.bdlField select{width:100%;box-sizing:border-box;border:1px solid rgba(125,211,252,.35);border-radius:14px;background:#020617;color:#fff;padding:12px 13px;font-weight:900;font-size:16px;}
  .bdlField select{appearance:auto;}
  .bdlWide{grid-column:1/-1;}
  .bdlTermNote{margin-top:12px;padding:12px 14px;border-radius:16px;background:rgba(14,165,233,.10);border:1px solid rgba(56,189,248,.22);color:#bae6fd;line-height:1.4;font-weight:750;}
  .bdlBreakdown{display:grid;gap:8px;margin:12px 0 16px;padding:12px;border-radius:18px;background:rgba(2,6,23,.35);border:1px solid rgba(148,163,184,.16);}
  .bdlBreakRow{display:grid;grid-template-columns:1.3fr .9fr 1.6fr;gap:10px;align-items:center;color:#cbd5e1;font-size:13px;}
  .bdlBreakRow b{color:#fff;}
  .bdlBreakRow span:first-child{color:#94a3b8;font-weight:900;}
  .bdlRisk{display:inline-flex;align-items:center;border-radius:999px;padding:5px 10px;font-size:12px;font-weight:950;border:1px solid rgba(148,163,184,.24);background:rgba(15,23,42,.7);color:#e5e7eb;}
  .bdlRisk.low{color:#86efac;border-color:rgba(34,197,94,.3);background:rgba(20,83,45,.22);}
  .bdlRisk.medium{color:#fde68a;border-color:rgba(251,191,36,.32);background:rgba(120,53,15,.22);}
  .bdlRisk.high{color:#fecaca;border-color:rgba(248,113,113,.35);background:rgba(127,29,29,.22);}
  .bdlField small{color:#94a3b8;line-height:1.3;}
  .bdlPills{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin:16px 0;}
  .bdlDealPill{padding:12px;border-radius:16px;background:rgba(15,23,42,.74);border:1px solid rgba(148,163,184,.18);display:grid;gap:4px;}
  .bdlDealPill span{font-size:11px;color:#94a3b8;font-weight:900;letter-spacing:.08em;text-transform:uppercase;}
  .bdlDealPill b{font-size:18px;color:#f8fafc;}
  .bdlDealPill.good{border-color:rgba(34,197,94,.35);background:rgba(20,83,45,.20);}
  .bdlDealPill.bad{border-color:rgba(248,113,113,.42);background:rgba(127,29,29,.22);}
  .bdlWarning{padding:13px 14px;border-radius:16px;border:1px solid rgba(251,191,36,.35);background:rgba(120,53,15,.28);color:#fde68a;line-height:1.45;}
  .bdlActions{display:flex;justify-content:flex-end;gap:10px;margin-top:18px;}
  .bdlBtn{border:0;border-radius:16px;padding:13px 16px;font-weight:950;cursor:pointer;}
  .bdlBtn.ghost{background:rgba(15,23,42,.75);color:#e2e8f0;border:1px solid rgba(148,163,184,.24);}
  .bdlBtn.primary{background:linear-gradient(135deg,#2563eb,#06b6d4);color:#fff;box-shadow:0 12px 30px rgba(14,165,233,.22);}
  .bdlTag{display:inline-flex;align-items:center;gap:6px;border-radius:999px;padding:4px 8px;margin-left:6px;background:rgba(14,165,233,.12);border:1px solid rgba(56,189,248,.28);color:#7dd3fc;font-size:11px;font-weight:950;}
  @media(max-width:720px){.bdlModalCard{padding:18px;border-radius:22px}.bdlModalHead h2{font-size:24px}.bdlGrid,.bdlPills{grid-template-columns:1fr}.bdlBreakRow{grid-template-columns:1fr;gap:3px}.bdlActions{display:grid;grid-template-columns:1fr}.bdlBtn{width:100%}}
`;

function usePlayableViewport() {
  React.useEffect(function () {
    var meta = document.querySelector('meta[name="viewport"]');
    if (!meta) {
      meta = document.createElement("meta");
      meta.setAttribute("name", "viewport");
      document.head.appendChild(meta);
    }
    meta.setAttribute(
      "content",
      "width=device-width, initial-scale=1, viewport-fit=cover"
    );
  }, []);
}

function btNavItems(state) {
  var dock = buildTopDockItems(state);
  return dock.map(function (it) {
    var iconMap = {
      hq: "🏠",
      inbox: "📥",
      leads: "🔽",
      pipeline: "💼",
      contracts: "📋",
      team: "👥",
      finance: "📊",
      office: "🏢",
      board: "🏛️",
      competitors: "🧭",
      expansion: "🌐",
      assets: "🏢",
    };
    return Object.assign({}, it, { icon: iconMap[it.id] || it.icon });
  });
}

function GameSidebar(props) {
  var state = props.state;
  var tab = props.tab;
  var setTab = props.setTab;
  var advanceWeek = props.advanceWeek;
  var autoAdvance = props.autoAdvance;
  var items = btNavItems(state);
  return React.createElement(
    "aside",
    { className: "bt-sidebar" },
    React.createElement(
      "div",
      { className: "bt-brand" },
      React.createElement("div", { className: "bt-brand-mark" }, "🧬"),
      React.createElement(
        "div",
        null,
        React.createElement(
          "div",
          { className: "bt-brand-name" },
          String(state.companyName || "CLINIGEN")
            .slice(0, 12)
            .toUpperCase()
        ),
        React.createElement(
          "div",
          { className: "bt-brand-sub" },
          "BUSINESS TYCOON"
        )
      )
    ),
    React.createElement(
      "nav",
      { className: "bt-side-nav" },
      items.map(function (it) {
        return React.createElement(
          "button",
          {
            key: it.id,
            type: "button",
            className:
              "bt-side-item" +
              (tab === it.id ? " active" : "") +
              (it.locked ? " bt-side-locked bt-side-locked-" + it.id : ""),
            disabled: !!it.locked,
            "data-tutorial-id": it.id,
            "data-tutorial-zone": "sidebar",
            onClick: function () {
              if (!it.locked) setTab(it.id);
            },
            title: it.locked ? it.lockReason : it.desc,
          },
          React.createElement("span", { className: "bt-side-icon" }, it.icon),
          React.createElement(
            "span",
            null,
            React.createElement(
              "div",
              { className: "bt-side-title" },
              it.label
            ),
            React.createElement("div", { className: "bt-side-desc" }, it.desc),
            it.locked && (it.id === "finance" || it.id === "expansion")
              ? React.createElement(
                  "div",
                  { className: "bt-side-lock-reason" },
                  "🔒 " + (it.lockReason || "Locked")
                )
              : null
          )
        );
      })
    ),
    React.createElement(
      "div",
      { className: "bt-side-bottom" },
      React.createElement(
        "div",
        { className: "bt-speed-card" },
        React.createElement(
          "div",
          { className: "bt-speed-title" },
          "GAME SPEED"
        ),
        React.createElement(
          "div",
          { className: "bt-speed-row" },
          ["Ⅱ", "x1", "x2", "x4", "x10"].map(function (x, i) {
            return React.createElement(
              "button",
              {
                key: x,
                className: "bt-speed-btn" + (i === 1 ? " active" : ""),
                type: "button",
              },
              x
            );
          })
        )
      ),
      React.createElement(
        "button",
        {
          className: "bt-advance-side",
          type: "button",
          onClick: advanceWeek,
          disabled: !state.hasStarted || state.gameOver,
        },
        "ADVANCE 1 WEEK  ›"
      )
    )
  );
}

function RedesignAlertRow(props) {
  var state = props.state;
  var quarter = props.quarter;
  var setTab = props.setTab;
  var openInbox = (state.mailbox || []).filter(function (m) {
    return !m.resolved;
  }).length;
  var expSlots = (state.unlockedGeos || []).length;
  return React.createElement(
    "div",
    { className: "bt-alert-row" },
    React.createElement(
      "button",
      {
        type: "button",
        className: "bt-alert-cell bt-alert-button",
        onClick: function () {
          if (setTab) setTab("inbox");
        },
      },
      React.createElement("span", { className: "bt-warn" }, "⚠ " + openInbox),
      " items to resolve"
    ),
    React.createElement(
      "div",
      { className: "bt-alert-cell" },
      "🌐 Expansion slots available: ",
      React.createElement("b", null, Math.max(0, expSlots - 1))
    ),
    React.createElement(
      "div",
      { className: "bt-alert-cell" },
      "🕒 Next Board Review: ",
      React.createElement("b", null, quarter || "Q1")
    )
  );
}

