function TopDock({ items, active, onChange, tutorialTarget }) {
  useInjectNavCss();
  return (
    <div className="topDockWrap">
      <div className="topDock" role="tablist" aria-label="Main sections">
        {items.map((it) => {
          const as = active === it.id;
          const disabled = !!it.locked;
          const tutorialHighlight = tutorialTarget && tutorialTarget === it.id;
          return (
            <button
              key={it.id}
              className="navTab"
              role="tab"
              aria-selected={as ? "true" : "false"}
              aria-disabled={disabled ? "true" : "false"}
              onClick={() => !disabled && onChange(it.id)}
              title={disabled ? it.lockReason || "Locked" : it.desc}
              type="button"
              data-tutorial-id={it.id}
              style={
                tutorialHighlight
                  ? {
                      boxShadow:
                        "0 0 0 4px rgba(56,189,248,.95), 0 0 38px rgba(56,189,248,.55), 0 18px 44px rgba(0,0,0,.35)",
                      transform: "scale(1.07)",
                      borderColor: "rgba(125,211,252,.95)",
                      background:
                        "linear-gradient(180deg, rgba(56,189,248,.30), rgba(255,255,255,.10))",
                      zIndex: 5,
                    }
                  : undefined
              }
            >
              <span className="navTabIcon">{it.icon}</span>
              <span className="navTabText">
                <span className="navTabLabel">{it.label}</span>
                <span className="navTabDesc">
                  {disabled ? it.lockReason || "Locked" : it.desc}
                </span>
              </span>
              {it.id === "hq" ? <span className="navLiveDot" /> : null}
              {!disabled && it.badge !== undefined && it.badge !== null ? (
                <span className="navTabBadge">{it.badge}</span>
              ) : null}
              {disabled ? <span className="navTabBadge">🔒</span> : null}
            </button>
          );
        })}
      </div>
    </div>
  );
}

function buildTickerItems(state) {
  const items = [];
  const week = (state && state.week) || 0;

  // Inbox
  const open = (state.mailbox || []).filter((m) => !m.resolved);
  if (open.length) {
    items.push({
      pill: "INBOX",
      text: `${open.length} unresolved decision${
        open.length > 1 ? "s" : ""
      } waiting`,
    });
  }

  // Active contracts / delivery pressure
  const activeContracts = (state.contracts || []).filter(
    (c) => (c && c.active) !== false
  );
  if (activeContracts.length) {
    items.push({
      pill: "DELIVERY",
      text: `${activeContracts.length} active contract${
        activeContracts.length > 1 ? "s" : ""
      } • keep quality high`,
    });
  } else {
    items.push({
      pill: "OPS",
      text: "No active delivery • stabilize the team • build pipeline",
    });
  }

  // Latest HQ feed
  const feed = (state.hqFeed || []).slice(-8).reverse();
  feed.forEach((e) => {
    const pill =
      e && e.urgency >= 3
        ? "FIRE"
        : e && e.urgency === 2
        ? "RISK"
        : e && e.kind === "slack"
        ? "SLACK"
        : e && e.kind === "people"
        ? "PEOPLE"
        : e && e.kind === "market"
        ? "MARKET"
        : "OPS";
    const txt = (e && (e.title || e.text)) || "";
    if (txt)
      items.push({
        pill,
        text: txt.length > 80 ? txt.slice(0, 77) + "…" : txt,
      });
  });

  // Quick KPIs
  const headcount = (state.team || []).length;
  const cash = Math.round(valOr(state.cash, 0));
  items.push({
    pill: "W" + week,
    text: `Headcount ${headcount} • Cash €${cash.toLocaleString()}`,
  });

  return items.slice(0, 12);
}

function TopTicker({ items }) {
  if (!items || !items.length) return null;
  const doubled = items.concat(items);
  return (
    <div className="topTicker" role="status" aria-label="Live ticker">
      <div className="tickerRow">
        {doubled.map((it, idx) => (
          <span className="tickerItem" key={idx}>
            <span className="tickerPill">{it.pill}</span>
            <span>{it.text}</span>
          </span>
        ))}
      </div>
    </div>
  );
}

function buildAlerts(state) {
  const alerts = [];

  // 1) Unresolved inbox items
  const unread = (state.mailbox || []).filter((m) => !m.resolved).length;
  if (unread > 0) {
    alerts.push({
      id: "inbox",
      tab: "inbox",
      text: `${unread} inbox item${unread > 1 ? "s" : ""} to resolve`,
      tone: "warn",
    });
  }

  // 2) Utilization overload (if you have state.utilization)
  if (state.utilization) {
    Object.keys(state.utilization).forEach((role) => {
      const u = state.utilization[role];
      if (u > 1) {
        const pct = Math.round(u * 100);
        alerts.push({
          id: "over_" + role,
          tab: "team",
          text: `Overload: ${ROLE_LABEL(role)} at ${pct}% (delays + rep risk)`,
          tone: "danger",
        });
      }
    });
  }

  // 3) Expansion shock active
  if (state.expansionShock && state.expansionShock.weeks > 0) {
    var cp = Math.round((state.expansionShock.costPenalty || 0) * 100 || 0);
    var dr = Math.round((state.expansionShock.delayRisk || 0) * 100 || 0);
    alerts.push({
      id: "shock",
      tab: "expansion",
      text: `Expansion shock active (${state.expansionShock.weeks} weeks left) — Costs +${cp}% · ${dr}%/wk delay risk (+1w)`,
      tone: "warn",
    });
  }

  // Keep it short
  return alerts.slice(0, 3);
}

function AlertsStrip({ alerts, onJump }) {
  if (!alerts || alerts.length === 0) return null;

  const toneStyle = (tone) => {
    if (tone === "danger")
      return {
        background: "rgba(239,68,68,.12)",
        borderColor: "rgba(239,68,68,.20)",
      };
    if (tone === "warn")
      return {
        background: "rgba(250,204,21,.10)",
        borderColor: "rgba(250,204,21,.18)",
      };
    return {
      background: "rgba(255,255,255,.08)",
      borderColor: "rgba(255,255,255,.14)",
    };
  };

  return (
    <div
      style={{
        display: "flex",
        gap: 8,
        flexWrap: "wrap",
        margin: "10px 0 12px",
      }}
    >
      {alerts.map((a) => (
        <button
          key={a.id}
          type="button"
          onClick={() => onJump && onJump(a.tab)}
          style={{
            borderRadius: 999,
            padding: "10px 12px",
            border: "1px solid rgba(255,255,255,.14)",
            color: "#fff",
            cursor: "pointer",
            fontWeight: 800,
            fontSize: 13,
            ...toneStyle(a.tone),
          }}
          title="Jump"
        >
          {a.text}
        </button>
      ))}
    </div>
  );
}

