/* -------------------- Difficulty presets -------------------- */
const DIFFICULTY_PRESETS = {
  Easy: {
    key: "Easy",
    startingCash: 2500000,
    winRateMultiplier: 1.7,
    integrationRiskMultiplier: 0.7,
  },
  Normal: {
    key: "Normal",
    startingCash: 1200000,
    winRateMultiplier: 1.2,
    integrationRiskMultiplier: 0.9,
  },
  Hard: {
    key: "Hard",
    startingCash: 700000,
    winRateMultiplier: 0.9,
    integrationRiskMultiplier: 1.1,
  },
};

const TAX_RATES = { Easy: 0.08, Normal: 0.22, Hard: 0.38 };
const isHardDifficulty = (difficulty) =>
  String(difficulty || "Normal").toLowerCase() === "hard";
// Player-adjustable annual salary raise (YoY). Baseline is 2%.
const BASELINE_SALARY_RAISE_PCT = 0.02;
const SALARY_RAISE_BY_DIFFICULTY = {
  Easy: 0.03,
  Normal: 0.02,
  Hard: 0.015,
};

/* -------------------- Tiny helpers -------------------- */
const rand = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min;

// Minimum time (in weeks) before a pipeline item can be accepted/rejected.
// Reality check: BD cycles take months, not 1–2 weeks.
const pipelineMinDecisionWeeks = (tier) => {
  const t = String(tier || "small").toLowerCase();
  if (t === "large") return rand(12, 20);
  if (t === "medium") return rand(4, 16);
  return rand(8, 16);
};

// Global helper: processWeek (defined outside App) needs this in scope.
const minDecisionWeeksFromReq = (req) => {
  const totalStaff = Object.keys(req || {}).reduce(
    (sum, k) => sum + valOr(req[k], 0),
    0
  );
  if (totalStaff >= 8) return 8;
  if (totalStaff >= 5) return 6;
  if (totalStaff >= 3) return 4;
  return 3;
};

const makePipelineItemGlobal = (lead, req) => {
  const minDecisionWeeks = minDecisionWeeksFromReq(req);
  const decisionAtWeeks = minDecisionWeeks + Math.floor(Math.random() * 6) + 2;

  const estWeeklyRevenue = valOr(
    lead.estWeeklyRevenue,
    lead.monthly ? Math.round(lead.monthly / 4) : 0
  );
  const durationWeeks = valOr(lead.durationWeeks, 8);
  const winChance = valOr(
    lead.winChance,
    lead.winRateBase ? Math.round(lead.winRateBase * 100) : 12
  );

  return {
    id: uid("pipe"),
    leadId: lead.id,
    title: lead.title,
    client: lead.client,
    geo: lead.geo,
    area: lead.area,
    companyType: lead.companyType,
    tier: lead.tier,
    dealType: lead.dealType || null,
    bdlTerms: lead.bdlTerms || null,
    grossEstWeeklyRevenue: lead.grossEstWeeklyRevenue || null,
    // lead provenance (for Inbox notifications)
    source: lead.source || null,
    sourceCompletedArea: lead.sourceCompletedArea || null,
    estWeeklyRevenue,
    durationWeeks,
    winChance,
    req: req || {},
    weeksInPipeline: 0,
    progressWeeks: 0,
    minDecisionWeeks,
    decisionAtWeeks,
  };
};

/* -------------------- BD&L licensing deal helpers -------------------- */
function isBDLLicensingDeal(x) {
  return !!(x && (x.dealType === "bdl_licensing" || x.area === "Licensing"));
}

var BDL_TERRITORIES = {
  single: {
    label: "Single country",
    frLabel: "Un pays",
    mult: 1.0,
    penalty: 0,
    complexity: "Low",
  },
  eu5: {
    label: "EU5",
    frLabel: "EU5",
    mult: 1.65,
    penalty: 5,
    complexity: "Medium",
  },
  europe: {
    label: "Europe",
    frLabel: "Europe",
    mult: 2.15,
    penalty: 9,
    complexity: "High",
  },
  global_ex_us: {
    label: "Global ex-US",
    frLabel: "Monde hors US",
    mult: 2.8,
    penalty: 14,
    complexity: "High",
  },
};

var BDL_MILESTONES = {
  none: {
    label: "None",
    frLabel: "Aucun",
    rate: 0,
    boost: 0,
    note: "No future milestone liability.",
  },
  light: {
    label: "Light",
    frLabel: "Léger",
    rate: 0.04,
    boost: 2,
    note: "Small future payment if the deal performs.",
  },
  balanced: {
    label: "Balanced",
    frLabel: "Équilibré",
    rate: 0.08,
    boost: 5,
    note: "Standard milestone package.",
  },
  aggressive: {
    label: "Aggressive",
    frLabel: "Agressif",
    rate: 0.14,
    boost: 8,
    note: "More attractive offer, but heavier future liability.",
  },
};

var BDL_LAUNCH_PLANS = {
  lean: {
    label: "Lean",
    frLabel: "Lean",
    cost: 0,
    boost: 0,
    note: "Minimal launch spend.",
  },
  standard: {
    label: "Standard",
    frLabel: "Standard",
    cost: 150000,
    boost: 4,
    note: "Normal launch preparation.",
  },
  aggressive: {
    label: "Aggressive",
    frLabel: "Agressif",
    cost: 400000,
    boost: 8,
    note: "More launch support, more cash at risk.",
  },
};

function bdlDefaultTerritory(lead) {
  var tier = (lead && lead.tier) || "small";
  if (tier === "large") return "europe";
  if (tier === "medium") return "eu5";
  return "single";
}

function bdlSuggestedUpfront(lead) {
  var monthly = valOr(lead && lead.estWeeklyRevenue, 50000);
  var months = Math.max(
    6,
    Math.round(valOr(lead && lead.durationWeeks, 52) / 4)
  );
  return Math.max(50000, Math.round((monthly * months * 0.08) / 10000) * 10000);
}

function bdlNormalizeTerms(lead, termsOrUpfront, royaltyMaybe) {
  var t =
    typeof termsOrUpfront === "object" && termsOrUpfront !== null
      ? termsOrUpfront
      : { upfrontPayment: termsOrUpfront, royaltyRate: royaltyMaybe };
  var territory = t.territory || bdlDefaultTerritory(lead);
  if (!BDL_TERRITORIES[territory]) territory = "single";
  var milestoneLevel = t.milestoneLevel || "balanced";
  if (!BDL_MILESTONES[milestoneLevel]) milestoneLevel = "balanced";
  var launchInvestment = t.launchInvestment || "standard";
  if (!BDL_LAUNCH_PLANS[launchInvestment]) launchInvestment = "standard";
  return {
    upfrontPayment: Math.max(
      0,
      Math.round(
        valOr(
          t.upfrontPayment,
          valOr(lead && lead.suggestedUpfront, bdlSuggestedUpfront(lead))
        )
      )
    ),
    royaltyRate: clamp(
      Math.round(
        valOr(t.royaltyRate, valOr(lead && lead.suggestedRoyalty, 15))
      ),
      0,
      50
    ),
    territory: territory,
    milestoneLevel: milestoneLevel,
    exclusivity: !!t.exclusivity,
    launchInvestment: launchInvestment,
  };
}

function bdlDealEconomics(lead, termsOrUpfront, royaltyMaybe) {
  var terms = bdlNormalizeTerms(lead, termsOrUpfront, royaltyMaybe);
  var terr = BDL_TERRITORIES[terms.territory] || BDL_TERRITORIES.single;
  var ms = BDL_MILESTONES[terms.milestoneLevel] || BDL_MILESTONES.balanced;
  var launch =
    BDL_LAUNCH_PLANS[terms.launchInvestment] || BDL_LAUNCH_PLANS.standard;
  var baseGrossMonthly = valOr(lead && lead.estWeeklyRevenue, 0);
  var grossMonthly = Math.round(baseGrossMonthly * terr.mult);
  var netMonthly = bdlNetRevenueAfterRoyalty(grossMonthly, terms.royaltyRate);
  var months = Math.max(
    1,
    Math.round(valOr(lead && lead.durationWeeks, 4) / 4)
  );
  var grossContractValue = grossMonthly * months;
  var netContractRevenue = netMonthly * months;
  var milestonePayment = Math.round(grossContractValue * ms.rate);
  var signingCashOut = terms.upfrontPayment + launch.cost;
  var approxNetValue = netContractRevenue - signingCashOut - milestonePayment;
  var riskScore =
    terr.penalty +
    (terms.exclusivity ? 4 : 0) +
    (launch.cost > 300000 ? 3 : 0) +
    (ms.rate >= 0.14 ? 3 : 0);
  var risk = riskScore >= 16 ? "High" : riskScore >= 8 ? "Medium" : "Low";
  return {
    terms: terms,
    territoryMeta: terr,
    milestoneMeta: ms,
    launchMeta: launch,
    grossMonthly: grossMonthly,
    netMonthly: netMonthly,
    months: months,
    grossContractValue: grossContractValue,
    netContractRevenue: netContractRevenue,
    milestonePayment: milestonePayment,
    launchCost: launch.cost,
    signingCashOut: signingCashOut,
    approxNetValue: approxNetValue,
    risk: risk,
    riskScore: riskScore,
  };
}

function bdlWinChanceFromTerms(lead, termsOrUpfront, royaltyMaybe) {
  var terms = bdlNormalizeTerms(lead, termsOrUpfront, royaltyMaybe);
  var econ = bdlDealEconomics(lead, terms);
  var base = valOr(
    lead && lead.baseWinChance,
    valOr(lead && lead.winChance, 18)
  );
  var upfrontBoost = Math.min(32, Math.floor(terms.upfrontPayment / 50000));
  var royaltyBoost = Math.min(
    9,
    Math.max(0, Math.round((terms.royaltyRate - 10) * 0.55))
  );
  var milestoneBoost = (
    BDL_MILESTONES[terms.milestoneLevel] || BDL_MILESTONES.balanced
  ).boost;
  var exclusivityBoost = terms.exclusivity ? 6 : 0;
  var launchBoost = (
    BDL_LAUNCH_PLANS[terms.launchInvestment] || BDL_LAUNCH_PLANS.standard
  ).boost;
  var territoryPenalty = (
    BDL_TERRITORIES[terms.territory] || BDL_TERRITORIES.single
  ).penalty;
  var valuePenalty = econ.approxNetValue < 0 ? 4 : 0;
  return clamp(
    Math.round(
      base +
        upfrontBoost +
        royaltyBoost +
        milestoneBoost +
        exclusivityBoost +
        launchBoost -
        territoryPenalty -
        valuePenalty
    ),
    5,
    92
  );
}

function bdlNetRevenueAfterRoyalty(monthlyRevenue, royaltyRate) {
  var royalty = clamp(valOr(royaltyRate, 0), 0, 95);
  return Math.max(
    0,
    Math.round(valOr(monthlyRevenue, 0) * (1 - royalty / 100))
  );
}

function bdlTermsSummary(terms) {
  if (!terms) return "No BD&L terms set";
  var terr = BDL_TERRITORIES[terms.territory] || BDL_TERRITORIES.single;
  var ms = BDL_MILESTONES[terms.milestoneLevel] || BDL_MILESTONES.none;
  return (
    "Upfront €" +
    Math.round(valOr(terms.upfrontPayment, 0)).toLocaleString() +
    " · Royalty " +
    valOr(terms.royaltyRate, 0) +
    "% · " +
    terr.label +
    (terms.exclusivity ? " · Exclusive" : "") +
    (terms.milestoneLevel ? " · Milestones: " + ms.label : "")
  );
}

// -------------------- Simulation helpers (NEW) --------------------
function reputationMultiplier(rep) {
  if (rep < 300) return 0.5;
  if (rep < 800) return 0.8;
  if (rep < 1500) return 1.0;
  if (rep < 3000) return 1.15;
  return 1.3;
}

// Delay a random active contract by +weeks (simple tension lever)
function delayRandomContract(state, weeks) {
  var contracts = getAllActiveContracts(state);
  if (!contracts || contracts.length === 0) return false;
  var c = choice(contracts);
  if (!c) return false;

  // Find it back in state.contracts and mutate
  for (var i = 0; i < state.contracts.length; i++) {
    if (state.contracts[i].id === c.id) {
      state.contracts[i].remainingWeeks =
        (state.contracts[i].remainingWeeks || 0) + (weeks || 1);
      return true;
    }
  }
  return false;
}

// Basic utilization: required FTE vs available FTE per role
function computeUtilization(state) {
  var used = {};
  var cap = {};

  // capacity from team (fte defaults to 1)
  (state.team || []).forEach(function (m) {
    var role = m.role;
    var fte = typeof m.fte === "number" ? m.fte : 1;
    cap[role] = (cap[role] || 0) + fte;
  });

  // demand from active contracts (we rely on c.req being stored when contract is created)
  var contracts = getAllActiveContracts(state);
  contracts.forEach(function (c) {
    if (!c || !c.req) return;
    Object.keys(c.req).forEach(function (role) {
      used[role] = (used[role] || 0) + (c.req[role] || 0);
    });
  });

  // compute utilization ratio
  var util = {};
  Object.keys(cap).forEach(function (role) {
    util[role] = (used[role] || 0) / Math.max(0.0001, cap[role] || 0);
  });

  return util;
}

const choice = (arr) => arr[rand(0, arr.length - 1)];
const clamp = (n, a, b) => Math.max(a, Math.min(b, n));
const id = () => Math.random().toString(36).slice(2, 9);

function ipoEligibility(s) {
  const reasons = [];
  if ((s.cash || 0) < IPO_CFG.MIN_CASH) {
    reasons.push(`Cash ≥ €${IPO_CFG.MIN_CASH.toLocaleString()}`);
  }
  const free = freeByRole(s.team, s.fteReserved || {});
  Object.entries(IPO_CFG.REQUIRE).forEach(([role, need]) => {
    const have = free[role] || 0;
    if (have < need)
      reasons.push(`${ROLE_LABEL(role)} x${need} free (have ${have})`);
  });
  return { ok: reasons.length === 0, reasons };
}

// Shared pro-rata splitter for sellers
function splitProRata(investors, totalToTake) {
  const totalAvail = investors.reduce((a, b) => a + (b.shares || 0), 0);
  if (totalAvail <= 0 || totalToTake <= 0) return { takes: [], taken: 0 };

  const want = Math.min(totalToTake, totalAvail);
  const raw = investors.map((h) => ({
    id: h.id,
    base: Math.floor((h.shares * want) / totalAvail),
  }));
  let assigned = raw.reduce((a, b) => a + b.base, 0);
  const bySize = investors
    .map((h, i) => ({ i, shares: h.shares }))
    .sort((a, b) => b.shares - a.shares);

  let idx = 0;
  while (assigned < want) {
    const k = bySize[idx % bySize.length].i;
    raw[k].base += 1;
    assigned += 1;
    idx += 1;
  }
  return {
    takes: raw.map((r, i) => ({ id: investors[i].id, amount: r.base })),
    taken: want,
  };
}

// Biggest competitor accumulates weekly until 70%
function aiAccumulationTick(state) {
  const events = [];
  if (
    !state.isPublic ||
    !Array.isArray(state.shareholders) ||
    state.shareholders.length < 2
  )
    return events;
  if (!state.sharesOutstanding || state.sharesOutstanding <= 0) return events;

  const holders = state.shareholders.slice();
  const nonYou = holders.filter((h) => h.name !== "You");
  if (!nonYou.length) return events;

  const acquirer = nonYou.slice().sort((a, b) => b.shares - a.shares)[0];
  const acqIdx = holders.findIndex((h) => h.id === acquirer.id);
  if (acqIdx < 0) return events;

  const curPct = acquirer.shares / state.sharesOutstanding;
  if (curPct >= 0.7) return events;

  const sellers = holders.filter((h) => h.id !== acquirer.id && h.shares > 0);
  const freeFloat = sellers.reduce((s, h) => s + h.shares, 0);
  if (freeFloat <= 0) return events;

  const buyPct = (0.005 + Math.random() * 0.015) / 3; // 0.167%–0.667% / week (slowed ×3)
  const want = Math.max(1, Math.floor(freeFloat * buyPct));
  const { takes, taken } = splitProRata(sellers, want);
  if (taken <= 0) return events;

  const mapT = new Map(takes.map((t) => [t.id, t.amount]));
  for (let i = 0; i < holders.length; i++) {
    const h = holders[i];
    const amt = mapT.get(h.id) || 0;
    if (amt > 0) holders[i] = { ...h, shares: Math.max(0, h.shares - amt) };
  }
  holders[acqIdx] = {
    ...holders[acqIdx],
    shares: holders[acqIdx].shares + taken,
  };
  state.shareholders = holders;

  const bump = Math.min(0.02, (taken / state.sharesOutstanding) * 0.5);
  if (state.sharePrice && state.sharePrice > 0) {
    state.sharePrice = Math.round(state.sharePrice * (1 + bump) * 100) / 100;
  }

  const newPct = (holders[acqIdx].shares / state.sharesOutstanding) * 100;
  events.push(
    `Competitor accumulation: ${
      acquirer.name
    } bought ${taken.toLocaleString()} shares — now at ${newPct.toFixed(1)}%`
  );

  if (newPct >= 50 && !state.gameOver) {
    state.gameOver = true;
    state.gameOverReason = {
      type: "hostile",
      title: "Hostile Takeover — Game Over",
      body: `${acquirer.name} exceeded 50% ownership. Restart required.`,
    };
    events.push(
      `⚠️ Hostile takeover: ${acquirer.name} exceeded 50%. Restart required.`
    );
  }
  return events;
}

// Allocate the IPO float across ~20 funds with random weights
function allocateIPOFloat(totalNewShares) {
  const n = 20;
  if (totalNewShares <= 0) {
    return Array.from({ length: n }, (_, i) => ({
      id: id(),
      name: INVESTOR_POOL[i] || `Fund ${i + 1}`,
      shares: 0,
    }));
  }
  function holderPct(h, totalShares) {
    if (!totalShares) return 0;
    return (h.shares / totalShares) * 100;
  }

  const weights = Array.from({ length: n }, () => Math.random() + 0.01);
  const sum = weights.reduce((a, b) => a + b, 0);
  const base = weights.map((w) => Math.floor((w / sum) * totalNewShares));
  let remainder = totalNewShares - base.reduce((a, b) => a + b, 0);
  for (let i = 0; remainder > 0; i = (i + 1) % n) {
    base[i] += 1;
    remainder--;
  }
  return base.map((shares, i) => ({
    id: id(),
    name: INVESTOR_POOL[i] || `Fund ${i + 1}`,
    shares,
  }));
}

function getClientSat(state, client) {
  const map = state.clientSatisfaction || (state.clientSatisfaction = {});
  const v = map[client];
  return Number.isFinite(v) ? v : SAT_INIT;
}
function setClientSat(state, client, value) {
  const map = state.clientSatisfaction || (state.clientSatisfaction = {});
  map[client] = clamp(Math.round(value), 0, SAT_MAX);
}
function bumpClientSat(state, client, delta) {
  setClientSat(state, client, getClientSat(state, client) + delta);
}

function satBucket(s) {
  const v = Math.round(s);
  if (v >= 85) return { label: "Delighted", color: "#16a34a" };
  if (v >= 70) return { label: "Happy", color: "#22c55e" };
  if (v >= 50) return { label: "Neutral", color: "#f59e0b" };
  return { label: "At risk", color: "#b91c1c" };
}

// ---- Renewal / cross-sell probability helpers (quality-aware) ----
function qualityAdjForArea(team, area) {
  var req = (typeof REQUIREMENTS === "object" && REQUIREMENTS[area]) || {};
  var roles = Object.keys(req || {});
  if (!roles.length) return 0;

  var vp = 0;
  var intern = 0;

  for (var i = 0; i < (team || []).length; i++) {
    var e = team[i];
    if (!e) continue;
    if (roles.indexOf(e.role) === -1) continue;
    if (e.seniority === "VP") vp += 1;
    else if (e.seniority === "Intern") intern += 1;
  }

  // Additive adjustment (keeps model simple & predictable)
  var vpAdj = Math.min(0.15, vp * 0.05); // up to +15pp
  var internAdj = Math.min(0.12, intern * 0.04); // up to -12pp
  return vpAdj - internAdj;
}

function baseRenewChanceFromSat(sat) {
  // Mirrors UI: base renew increases with satisfaction (cap 85%)
  var s = Math.round(sat || 0);
  return clamp(0.2 + s / 150, 0, 0.85);
}

function baseCrossChanceFromSat(sat) {
  // Mirrors UI: base cross-sell increases with satisfaction (cap 55%)
  var s = Math.round(sat || 0);
  return Math.min(0.55, s / 180);
}

function renewChanceFor(state, client, area) {
  var sat = getClientSat(state, client);
  var base = baseRenewChanceFromSat(sat);
  var adj = qualityAdjForArea((state && state.team) || [], area);
  return clamp(base + adj, 0, 0.95);
}

function crossChanceFor(state, client, area) {
  var sat = getClientSat(state, client);
  var base = baseCrossChanceFromSat(sat);
  var adj = qualityAdjForArea((state && state.team) || [], area);
  return clamp(base + adj, 0, 0.75);
}

function bestAreaForClient(state, client) {
  var best = null;
  var cs = (state && state.contracts) || [];
  for (var i = 0; i < cs.length; i++) {
    var c = cs[i];
    if (!c) continue;
    if (c.client !== client) continue;
    if (!best) best = c;
    else if ((c.weeklyRevenue || 0) > (best.weeklyRevenue || 0)) best = c;
  }
  return (best && best.area) || "Regulatory";
}

/* ---- Date helpers ---- */
function formatDateShort(input) {
  // Accept a Date object or a timestamp (ms)
  const d = input instanceof Date ? input : new Date(input);
  if (Number.isNaN(d.getTime())) return "";
  // "1 Jan 2025" style
  return d.toLocaleDateString("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

/* ---- YTD helpers (place near Date helpers) ---- */
function monthKey(ts) {
  const d = new Date(ts);
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  return `${y}-${m}`;
}
function initRevYTD(year) {
  return {
    year,
    monthly: {}, // { "YYYY-MM": { clients:{}, bu:{}, geo:{} } }
    clientsTotal: {}, // client -> YTD €
    buTotal: {}, // BU -> YTD €
    geoTotal: {}, // country -> YTD €   << NEW
  };
}

