function defaultOfficeState() {
  return {
    location: "paris",
    deskArea: 0,
    meetingRoom: 0,
    breakRoom: 0,
    floorExpansion: 0,
    decorBranding: 0,
    itInfrastructure: 0,
    lastOfficePulseWeek: 0,
  };
}

function ensureOfficeState(state) {
  var base = defaultOfficeState();
  var current =
    state && state.office && typeof state.office === "object"
      ? state.office
      : {};
  var next = Object.assign({}, base, current);
  if (!OFFICE_LOCATIONS[next.location]) next.location = "paris";
  OFFICE_UPGRADES.forEach(function (u) {
    var v = Number(next[u.key]);
    next[u.key] = Number.isFinite(v) ? clamp(Math.round(v), 0, u.max) : 0;
  });
  return next;
}

function officeUpgradeCost(office, key) {
  var u = OFFICE_UPGRADES.find(function (x) {
    return x.key === key;
  });
  if (!u) return 0;
  var level = valOr(office && office[key], 0);
  return Math.round(u.baseCost * Math.pow(1.22, level));
}

