function officeRoomType(type) {
  return OFFICE_ROOM_TYPES[type] || OFFICE_ROOM_TYPES.open;
}

function defaultOfficeLayoutRooms() {
  return [
    { id: "room-open-1", type: "open", x: 0, y: 0, w: 4, h: 3, level: 1 },
    { id: "room-private-1", type: "private", x: 4, y: 0, w: 2, h: 2, level: 1 },
    { id: "room-exec-1", type: "executive", x: 6, y: 0, w: 2, h: 2, level: 1 },
    { id: "room-board-1", type: "boardroom", x: 8, y: 0, w: 2, h: 3, level: 1 },
    { id: "room-break-1", type: "break", x: 0, y: 3, w: 3, h: 2, level: 1 },
    { id: "room-it-1", type: "it", x: 3, y: 3, w: 2, h: 2, level: 1 },
    { id: "room-hr-1", type: "hr", x: 5, y: 3, w: 2, h: 2, level: 1 },
    { id: "room-meeting-1", type: "meeting", x: 7, y: 3, w: 3, h: 2, level: 1 },
    {
      id: "room-reception-1",
      type: "reception",
      x: 3,
      y: 5,
      w: 4,
      h: 2,
      level: 1,
    },
    { id: "room-lounge-1", type: "lounge", x: 7, y: 5, w: 3, h: 2, level: 1 },
  ];
}

function normalizeOfficeRoom(room, idx) {
  room = room || {};
  var type = officeRoomType(room.type || "open").key;
  var def = officeRoomType(type);
  var w = clamp(
    Math.round(valOr(room.w, def.defaultW || 2)),
    1,
    OFFICE_GRID_COLS
  );
  var h = clamp(
    Math.round(valOr(room.h, def.defaultH || 2)),
    1,
    OFFICE_GRID_ROWS
  );
  var x = clamp(
    Math.round(valOr(room.x, idx % OFFICE_GRID_COLS)),
    0,
    Math.max(0, OFFICE_GRID_COLS - w)
  );
  var y = clamp(
    Math.round(valOr(room.y, Math.floor(idx / OFFICE_GRID_COLS))),
    0,
    Math.max(0, OFFICE_GRID_ROWS - h)
  );
  return {
    id:
      room.id ||
      "room-" + type + "-" + idx + "-" + Math.random().toString(36).slice(2, 7),
    type: type,
    x: x,
    y: y,
    w: w,
    h: h,
    level: clamp(Math.round(valOr(room.level, 1)), 1, 5),
  };
}

function normalizeOfficeLayout(office) {
  var rooms = arr(office && office.layoutRooms);
  if (!rooms.length) rooms = defaultOfficeLayoutRooms();
  return rooms.slice(0, 36).map(normalizeOfficeRoom);
}

function officeRoomAreaCells(room) {
  return Math.max(1, valOr(room && room.w, 1) * valOr(room && room.h, 1));
}

function officeRoomLabel(room, fr) {
  var def = officeRoomType(room && room.type);
  return fr ? def.frName || def.name : def.name;
}

function officeLayoutMetrics(rooms) {
  rooms = arr(rooms);
  var metrics = {
    capacity: 0,
    meetingSeats: 0,
    rent: 0,
    morale: 0,
    productivity: 0,
    prestige: 0,
    budgetValue: 0,
    occupiedCells: 0,
    flowScore: 0,
    roomCounts: {},
  };
  rooms.forEach(function (r) {
    var def = officeRoomType(r.type);
    var cells = officeRoomAreaCells(r);
    var level = clamp(valOr(r.level, 1), 1, 5);
    metrics.occupiedCells += cells;
    metrics.roomCounts[r.type] = (metrics.roomCounts[r.type] || 0) + 1;
    metrics.capacity += Math.round(
      valOr(def.capacity, 0) *
        Math.max(
          1,
          cells / Math.max(1, (def.defaultW || 2) * (def.defaultH || 2))
        ) *
        (1 + (level - 1) * 0.12)
    );
    if (def.seats)
      metrics.meetingSeats += Math.round(
        def.seats *
          Math.max(
            1,
            cells / Math.max(1, (def.defaultW || 2) * (def.defaultH || 2))
          )
      );
    metrics.rent += Math.round(
      cells *
        OFFICE_CELL_M2 *
        valOr(def.rentPerCell, 500) *
        (1 + (level - 1) * 0.08)
    );
    metrics.morale += valOr(def.morale, 0) * level;
    metrics.productivity += valOr(def.productivity, 0) * level;
    metrics.prestige += valOr(def.prestige, 0) * level;
    metrics.budgetValue += Math.round(
      cells * OFFICE_CELL_M2 * valOr(def.rentPerCell, 500) * 12 * 0.18 * level
    );
  });
  var hasReception = metrics.roomCounts.reception > 0;
  var hasOpen = metrics.roomCounts.open > 0;
  var hasMeeting =
    metrics.roomCounts.meeting > 0 || metrics.roomCounts.boardroom > 0;
  var hasBreak = metrics.roomCounts.break > 0 || metrics.roomCounts.lounge > 0;
  metrics.flowScore = clamp(
    Math.round(
      45 +
        (hasReception ? 12 : -8) +
        (hasOpen ? 8 : -12) +
        (hasMeeting ? 10 : -8) +
        (hasBreak ? 8 : -5) +
        Math.min(14, rooms.length)
    ),
    0,
    100
  );
  metrics.capacity = Math.max(1, metrics.capacity);
  return metrics;
}

function officeLayoutIssues(state, metrics, headcount, utilization) {
  var issues = [];
  metrics = metrics || officeLayoutMetrics([]);
  var counts = metrics.roomCounts || {};
  if (utilization > 1)
    issues.push({
      tone: "danger",
      title: "Office is over capacity",
      text: "Add open space, private offices, or expand before hiring more.",
    });
  else if (utilization > 0.88)
    issues.push({
      tone: "warn",
      title: "Office is close to full",
      text: "Add capacity before morale and productivity drop.",
    });
  if (!counts.open && !counts.private)
    issues.push({
      tone: "danger",
      title: "No work area",
      text: "Add open space or private offices so employees can work.",
    });
  if (headcount > 8 && metrics.meetingSeats < Math.ceil(headcount / 6))
    issues.push({
      tone: "warn",
      title: "Meeting capacity is low",
      text: "Add meeting rooms or a boardroom for client and team work.",
    });
  if (!counts.break && headcount > 10)
    issues.push({
      tone: "warn",
      title: "No break area",
      text: "Add a break room or lounge to support morale.",
    });
  if (!counts.it && headcount > 16)
    issues.push({
      tone: "warn",
      title: "No IT room",
      text: "Add IT infrastructure before systems become a bottleneck.",
    });
  if (!counts.reception && headcount > 6)
    issues.push({
      tone: "warn",
      title: "No reception",
      text: "Add reception to improve client visits and office prestige.",
    });
  if (issues.length === 0)
    issues.push({
      tone: "good",
      title: "Office layout works",
      text: "Capacity, meeting space, and flow are under control.",
    });
  return issues;
}

function officeStats(state) {
  state = state || {};
  var office = ensureOfficeState(state);
  var loc = OFFICE_LOCATIONS[office.location] || OFFICE_LOCATIONS.paris;
  var headcount =
    (arr(state.team).length || 0) + valOr(state.acquiredHeadcount, 0);
  var rooms = normalizeOfficeLayout(office);
  var layoutMetrics = officeLayoutMetrics(rooms);
  var legacyCapacity =
    loc.baseCapacity +
    valOr(office.deskArea, 0) * 16 +
    valOr(office.floorExpansion, 0) * 48;
  var capacity = Math.max(1, layoutMetrics.capacity, legacyCapacity);
  var utilization = headcount / capacity;
  var overcrowdPenalty = Math.max(0, utilization - 0.88) * 42;
  var meetingPenalty =
    Math.max(
      0,
      headcount -
        Math.max(
          2,
          layoutMetrics.meetingSeats + valOr(office.meetingRoom, 0) * 4
        )
    ) * 0.14;
  var satisfaction = clamp(
    Math.round(
      58 +
        loc.prestige * 1.2 +
        Math.min(22, layoutMetrics.morale) +
        valOr(office.breakRoom, 0) * 3 +
        valOr(office.decorBranding, 0) * 2.5 -
        overcrowdPenalty -
        meetingPenalty
    ),
    0,
    100
  );
  var productivity = clamp(
    Math.round(
      loc.prestige * 0.7 +
        Math.min(32, layoutMetrics.productivity) +
        Math.round(layoutMetrics.flowScore / 12) +
        valOr(office.itInfrastructure, 0) * 2.5 +
        valOr(office.meetingRoom, 0) * 1.2 -
        Math.max(0, utilization - 0.95) * 35
    ),
    -25,
    55
  );
  var rent = Math.round(
    loc.baseRent +
      Math.max(0, layoutMetrics.rent * 0.08) +
      valOr(office.floorExpansion, 0) * loc.baseRent * 0.18 +
      valOr(office.deskArea, 0) * 600 +
      valOr(office.meetingRoom, 0) * 450 +
      valOr(office.itInfrastructure, 0) * 600
  );
  var issues = officeLayoutIssues(state, layoutMetrics, headcount, utilization);
  return {
    office: office,
    location: loc,
    rooms: rooms,
    layoutMetrics: layoutMetrics,
    headcount: headcount,
    capacity: capacity,
    utilization: utilization,
    utilizationPct: Math.round(utilization * 100),
    satisfaction: satisfaction,
    productivity: productivity,
    rent: rent,
    issues: issues,
  };
}

function officeMonthlyMoraleDelta(state) {
  var st = officeStats(state);
  var delta = 0;
  if (st.utilization > 1) delta -= 3;
  else if (st.utilization > 0.9) delta -= 1;
  if (st.satisfaction >= 82) delta += 2;
  else if (st.satisfaction >= 72) delta += 1;
  else if (st.satisfaction < 45) delta -= 2;
  return clamp(delta, -4, 3);
}

function fmtOfficeEuro(n) {
  n = Math.round(Number(n) || 0);
  return "€" + n.toLocaleString("fr-FR").replace(/\u202f/g, " ");
}

