const SENIORITY_RANK = { Intern: 0, Junior: 1, Senior: 2, VP: 3 };

function hasVPFor(s, roleKey) {
  return (s.team || []).some(function (e) {
    return (
      e.role === roleKey &&
      (SENIORITY_RANK[e.seniority] || 0) >= SENIORITY_RANK.VP
    );
  });
}

function execCoversRole(s, roleKey) {
  // A filled executive seat should unlock the related module even if the person was not originally in that exact department.
  // Finance unlocks with CFO; Expansion unlocks with Head of Growth.
  if (!s.executives) return false;
  var pickedId =
    roleKey === "finance"
      ? s.executives.cfo
      : roleKey === "hr"
      ? s.executives.cpo
      : roleKey === "corp"
      ? s.executives.hog
      : null;
  if (!pickedId) return false;
  return (s.team || []).some(function (e) {
    return e && e.id === pickedId;
  });
}

function isUnlocked(s, roleKey) {
  // Unlock if you have a VP in that role OR you’ve nominated the matching executive
  return hasVPFor(s, roleKey) || execCoversRole(s, roleKey);
}

