// --- Company-type helpers (biotech/law/architect) ---
function companyTypeKey(v) {
  return v === "law" || v === "architect" || v === "biotech" ? v : "biotech";
}
function serviceAreasForType(type) {
  const t = companyTypeKey(type);
  return t === "law" ? LAW_SERVICE_AREAS : SERVICE_AREAS;
}
function projectTypesByAreaForType(type) {
  const t = companyTypeKey(type);
  return t === "law" ? LAW_PROJECT_TYPES_BY_AREA : PROJECT_TYPES_BY_AREA;
}
function projectPrefixForType(type) {
  const t = companyTypeKey(type);
  return t === "law" ? LAW_PROJECT_PREFIX : PROJECT_PREFIX;
}
function clientsForType(type) {
  const t = companyTypeKey(type);
  return t === "law" ? LAW_CLIENTS : CLIENTS;
}
function requirementsForType(type) {
  const t = companyTypeKey(type);
  return t === "law" ? LAW_REQUIREMENTS : REQUIREMENTS;
}
function sltAreaMapForType(type) {
  const t = companyTypeKey(type);
  return t === "law" ? LAW_SLT_AREA : SLT_AREA;
}
function roleLabelForType(type, roleKey) {
  const t = companyTypeKey(type);
  if (t === "law") return LAW_ROLE_LABELS[roleKey] || ROLE_LABEL(roleKey);
  return ROLE_LABEL(roleKey);
}
function seniorityLabelForType(type, seniorityKey) {
  const t = companyTypeKey(type);
  if (t === "law") return LAW_SENIORITY_LABELS[seniorityKey] || seniorityKey;
  return seniorityKey;
}

