const TIER_REQ_MULT = { small: 1, medium: 2, large: 3 };
// --- Client satisfaction ---
const SAT_INIT = 0; // default when we first see a client
const SAT_MAX = 100;
const SAT_DECAY_PER_WEEK = 0.4; // no active work with them
const SAT_DECAY_IF_ACTIVE = 0.1; // we are serving them now
const SAT_WIN_PIPELINE = 2;
const SAT_LOSS_PIPELINE = -4;
const SAT_COMPLETE_SMALL = 1;
const SAT_COMPLETE_MED = 2;
const SAT_COMPLETE_LARGE = 4;

// scale staffing for mega
TIER_REQ_MULT.mega = 4;

const AREA_ALIASES = { "Clinical Trials Services": "Clinical Services" };

const baseReqForArea = (area, companyType) => {
  const canonical = AREA_ALIASES[area] || area;
  const type = companyTypeKey(companyType);

  const reqMap = requirementsForType(type);
  const req = reqMap ? reqMap[canonical] : null;

  // Defensive fallback: if an area isn't mapped, return a sensible default per company type.
  // Important: BD should never be required to *deliver* work (BD is for lead gen).
  if (!req) {
    if (type === "law") return { corp: 1 };
    if (type === "architect") return { arch: 1 };
    // biotech: default to Ops/Delivery as a generic delivery role
    return { ops: 1 };
  }

  const clamped = {};
  for (const [role, count] of Object.entries(req))
    clamped[role] = count < 1 ? 1 : count;
  return clamped;
};

const scaledReqForArea = (area, tier, companyType) => {
  const type = companyTypeKey(companyType);
  const base = baseReqForArea(area, type);
  const m = TIER_REQ_MULT[tier] || 1;

  const scaled = {};
  Object.keys(base).forEach((k) => (scaled[k] = base[k] * m));

  // Large projects need extra coordination, but the "extra roles" depend on the business model.
  if (tier === "large") {
    if (type === "biotech") {
      if (area !== "Quality") scaled.qa = (scaled.qa || 0) + 2;
      if (area !== "Clinical Services") scaled.ops = (scaled.ops || 0) + 2;
      scaled.cs = Math.max(4, scaled.cs || 0);
    } else if (type === "law") {
      scaled.ops = (scaled.ops || 0) + 1; // legal ops / case management
      scaled.cs = (scaled.cs || 0) + 1; // client services / docketing
    }
  }

  // Always return whole headcount requirements (rounded up).
  Object.keys(scaled).forEach((k) => (scaled[k] = Math.ceil(scaled[k])));

  return scaled;
};

