/* =========================
   Assets (M&A)
   ========================= */
const assetNames = [
  "Med Vigilance (CEE)",
  "Regulatory Nordics (Nordics)",
  "QMS Audit House (UK)",
  "Réseau d'Affaires Médicales (FR)",
  "Named-Patient Supply Hub (MENA)",
];

const makeAsset = (forcedName) => {
  const sectors = {
    "Med Vigilance (CEE)": "PV",
    "Regulatory Nordics (Nordics)": "Regulatory",
    "QMS Audit House (UK)": "Quality",
    "Réseau d'Affaires Médicales (FR)": "Medical Affairs",
    "Named-Patient Supply Hub (MENA)": "Supply",
  };
  const name = forcedName || choice(assetNames);

  // Keep integration cost random as before
  const integrationCost = rand(20000, 4000000);

  // Revenue per week (unchanged range)
  const revPerWeek = rand(40000, 80000);

  // NEW: random weekly cost, then EBITDA per week in currency
  // NEW: random weekly cost, then EBITDA per week in currency
  const weeklyCost = rand(
    Math.round(revPerWeek * 0.4),
    Math.round(revPerWeek * 0.9)
  );
  const ebitdaPerWeek = Math.max(0, revPerWeek - weeklyCost);

  // NEW: EBITDA multiple (real-life style, 12–20x)
  const ebitdaMultiple = rand(12, 20);

  // NEW: purchase price = LTM EBITDA × multiple
  const purchasePrice = Math.round(ebitdaPerWeek * 4 * 12 * ebitdaMultiple);

  const synergyPotential = rand(2, 25);
  const risk = rand(10, 40);
  return {
    id: id(),
    name,
    sector: sectors[name],
    purchasePrice,
    integrationCost,
    revPerWeek,
    ebitdaPerWeek, // NEW (replaces ebitdaMargin)
    ebitdaMultiple, // NEW
    synergyPotential,
    employeeCount: rand(12, 120), // NEW
    risk,
  };
};

const seedAssets = () => {
  const shuffled = assetNames.slice().sort(() => Math.random() - 0.5);
  const names = shuffled.slice(0, 6);
  return names.map((n) => makeAsset(n));
};

function acquisitionProfileForAsset(name, sector) {
  var n = String(name || "");
  if (n.indexOf("Vigilance") >= 0) {
    return {
      archetype: "PV boutique",
      capability: "Pharmacovigilance",
      geo: "CEE",
      clientCount: 8,
      why: "Adds recurring PV work, specialist staff, and regional client relationships.",
    };
  }
  if (n.indexOf("Regulatory") >= 0) {
    return {
      archetype: "Regulatory consultancy",
      capability: "Regulatory Affairs",
      geo: "Nordics",
      clientCount: 6,
      why: "Adds regulatory specialists and market-entry capability in Northern Europe.",
    };
  }
  if (n.indexOf("QMS") >= 0) {
    return {
      archetype: "Quality consultancy",
      capability: "Quality / Audit",
      geo: "UK",
      clientCount: 5,
      why: "Adds audit capability and quality-system credibility for larger clients.",
    };
  }
  if (n.indexOf("Affaires") >= 0 || n.indexOf("Medical") >= 0) {
    return {
      archetype: "Medical affairs agency",
      capability: "Medical Affairs",
      geo: "France",
      clientCount: 7,
      why: "Adds medical-affairs support and client-facing scientific expertise.",
    };
  }
  if (n.indexOf("Supply") >= 0 || n.indexOf("Patient") >= 0) {
    return {
      archetype: "Regional access distributor",
      capability: "Managed Access / Supply",
      geo: "MENA",
      clientCount: 9,
      why: "Adds distribution reach, supply relationships, and access-program capacity.",
    };
  }
  return {
    archetype: sector || "Specialist services firm",
    capability: sector || "Specialist capability",
    geo: "Europe",
    clientCount: 5,
    why: "Adds revenue, staff, and a specialist services capability.",
  };
}

function normalizeAcquisitionAsset(asset) {
  var a = asset || {};
  var profile = acquisitionProfileForAsset(a.name, a.sector);
  var rev = Math.max(0, valOr(a.revPerWeek, 0));
  var ebitda =
    typeof a.ebitdaPerWeek === "number"
      ? Math.max(0, a.ebitdaPerWeek)
      : Math.max(
          0,
          typeof a.weeklyCost === "number"
            ? rev - valOr(a.weeklyCost, 0)
            : Math.round((rev * valOr(a.ebitdaMargin, 25)) / 100)
        );
  var multiple = typeof a.ebitdaMultiple === "number" ? a.ebitdaMultiple : 16;
  var purchase =
    typeof a.purchasePrice === "number" && a.purchasePrice > 0
      ? a.purchasePrice
      : Math.round(ebitda * 4 * 12 * multiple);
  var employees = Math.max(0, Math.round(valOr(a.employeeCount, 0) || 25));
  var clients = Math.max(
    1,
    Math.round(valOr(a.clientCount, 0) || profile.clientCount || employees / 10)
  );
  return Object.assign({}, a, profile, {
    sector: a.sector || profile.capability || "Services",
    purchasePrice: purchase,
    integrationCost: Math.max(0, valOr(a.integrationCost, 0)),
    revPerWeek: rev,
    ebitdaPerWeek: ebitda,
    ebitdaMultiple: multiple,
    synergyPotential: Math.max(0, valOr(a.synergyPotential, 0)),
    risk: clamp(Math.round(valOr(a.risk, 25)), 1, 95),
    employeeCount: employees,
    clientCount: clients,
    corpRequired: Math.max(1, Math.round(valOr(a.corpRequired, 2))),
    integrationWeeks: Math.max(
      3,
      Math.round(valOr(a.integrationWeeks, 0) || 4)
    ),
  });
}

function acquisitionTotalCost(asset) {
  var a = normalizeAcquisitionAsset(asset);
  return Math.max(0, valOr(a.purchasePrice, 0) + valOr(a.integrationCost, 0));
}

/* =========================
   IPO MODEL
   ========================= */
const IPO_CFG = {
  MIN_CASH: 30000000, // need at least €30m to kick off
  RETAINER: 2000000, // non-refundable advisory retainer on start
  FEES_PCT: 0.07, // % of gross proceeds lost as fees
  OFFER_PCT: [0.18, 0.26], // % of post-money floated at IPO
  DURATION_WEEKS: 16, // ~4 months to list
  TARGET_PRICE: 20, // aim to price near €20 for share math
  VOLATILITY: 0.38, // “annualized-ish” for our weekly step
  BASE_DRIFT: 0.06, // long-run annual drift
  REQUIRE: { finance: 15, legal: 12 }, // FTE reserved for the whole process
};

// quick normal(0,1)
function randn() {
  const u = Math.random() || 1e-9;
  const v = Math.random() || 1e-9;
  return Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
}

// annualized revenue proxy from weekly run-rate
function annualizedRevenue(state) {
  const rr =
    state.contracts.reduce((s, c) => s + c.weeklyRevenue, 0) +
    state.assetsOwned.reduce((s, a) => s + a.revPerWeekBoosted, 0);
  return rr * 52;
}

// simple revenue multiple influenced by reputation & growth
function valuationFromState(state, last8Weeks) {
  const revA = annualizedRevenue(state);
  // growth from last 8 weeks (fallback 0)
  const prevRR =
    last8Weeks && last8Weeks.length >= 8 ? last8Weeks[0] || 0 : revA;
  const curRR = revA;
  const growth = prevRR ? (curRR - prevRR) / prevRR : 0; // ~8w growth
  const rep = Math.max(0, Math.min(REPUTATION_MAX, state.reputation || 0));
  // base multiple 2.2–4.8x, boosted by rep and growth
  const mult = Math.max(
    1.5,
    2.2 + 2.0 * (rep / REPUTATION_MAX) + 1.5 * Math.max(0, growth)
  );
  return Math.max(5000000, Math.round(revA * mult));
}

// next trading price (weekly GBM with drift from growth/cash health)
function nextMarketPrice(state, price, last8Weeks) {
  const dt = 1 / 52; // weekly step
  const curA = annualizedRevenue(state);
  const prevA =
    last8Weeks && last8Weeks.length >= 8 ? last8Weeks[0] || curA : curA;
  const growth = prevA ? (curA - prevA) / prevA : 0;

  // drift up if growing, down if cash stressed
  const cashStress = state.cash < 0 ? -0.1 : state.cash < 1000000 ? -0.02 : 0;
  const mu = IPO_CFG.BASE_DRIFT + 0.5 * growth + cashStress;
  const sigma = IPO_CFG.VOLATILITY;

  const z = randn();
  const next =
    price *
    Math.exp((mu - 0.5 * sigma * sigma) * dt + sigma * Math.sqrt(dt) * z);
  // keep in a plausible range
  return Math.max(0.5, Math.min(next, price * 1.8));
}

const REGIONS = Array.from(new Set(GEOS.map((g) => g.region)));

// Country -> Region map (module scope; must be after GEOS and REGIONS)
const GEO_REGION = GEOS.reduce((m, g) => {
  m[g.key] = g.region;
  return m;
}, {});

const getGMEffects = (team) => {
  const revBoostByGeo = {};
  const payrollCutByGeo = {};

  (team || [])
    .filter((t) => t.role === "gm")
    .forEach((gm) => {
      const revBoost = Number.isFinite(gm.gmRevBoost) ? gm.gmRevBoost : 0.08;
      const payCut = Number.isFinite(gm.gmPayrollCut) ? gm.gmPayrollCut : 0.05;

      if (gm.gmScope === "geo" && gm.gmTarget) {
        revBoostByGeo[gm.gmTarget] =
          (revBoostByGeo[gm.gmTarget] || 0) + revBoost;
        payrollCutByGeo[gm.gmTarget] =
          (payrollCutByGeo[gm.gmTarget] || 0) + payCut;
      } else if (gm.gmScope === "region" && gm.gmTarget) {
        GEOS.filter((g) => g.region === gm.gmTarget).forEach((g) => {
          revBoostByGeo[g.key] = (revBoostByGeo[g.key] || 0) + revBoost;
          payrollCutByGeo[g.key] = (payrollCutByGeo[g.key] || 0) + payCut;
        });
      }
    });

  // caps
  Object.keys(revBoostByGeo).forEach(
    (k) => (revBoostByGeo[k] = Math.min(revBoostByGeo[k], 0.12))
  );
  Object.keys(payrollCutByGeo).forEach(
    (k) => (payrollCutByGeo[k] = Math.min(payrollCutByGeo[k], 0.08))
  );

  return { revBoostByGeo, payrollCutByGeo };
};

const gmAdjustedPayroll = (basePayroll, revenueByGeo, payrollCutByGeo) => {
  const total = Object.values(revenueByGeo).reduce((a, b) => a + b, 0) || 0;
  if (!total) return basePayroll;
  let weightedCut = 0;
  for (const geo in revenueByGeo) {
    const w = revenueByGeo[geo] / total;
    weightedCut += w * (payrollCutByGeo[geo] || 0);
  }
  const cut = Math.min(Math.max(weightedCut, 0), 0.1); // cap GM payroll reduction at 10%
  return Math.round(basePayroll * (1 - cut));
};

/* =========================
   Core logic
   ========================= */
const monthlyPayroll = (team) => {
  const mult = (sen) => SENIORITY_MULT[sen] || 1;
  return team.reduce((sum, e) => {
    const r = findRole(e.role);
    const base = r ? r.baseMonthly : 2500;
    const slt = e.inSLT ? 1.25 : 1;
    const idx = typeof e.salaryIndex === "number" ? e.salaryIndex : 1; // annual raises
    return sum + Math.round(base * mult(e.seniority) * slt * idx);
  }, 0);
};

const bdEffect = (team) => {
  const bds = team.filter((t) => t.role === "bd");
  let genChance = 0;
  let winBoost = 0;
  for (let i = 0; i < bds.length; i++) {
    const b = bds[i];
    genChance += BD_LEAD_CHANCE[b.seniority] || 0;
    winBoost +=
      b.seniority === "Intern"
        ? 1
        : b.seniority === "Junior"
        ? 2
        : b.seniority === "Senior"
        ? 3
        : 5;
  }
  return { genChance, winBoost };
};

const sltEffect = (team) => {
  const sltCount = team.filter((t) => t.inSLT).length;
  return Math.min(10 + sltCount * 3, 20);
};

const hrEffects = (team) => {
  const hrs = team.filter((t) => t.role === "hr");
  const base = hrs.length;
  const hasSLT = hrs.some((h) => h.inSLT);
  return {
    churnReduction: base * 0.03 + (hasSLT ? 0.04 : 0),
    prodBoost: base * 0.5 + (hasSLT ? 1 : 0),
    autoHire: hasSLT ? 1 : 0,
  };
};

// Customer Service slows client satisfaction decay (retention lever)
const csEffects = (team) => {
  const css = team.filter((t) => t.role === "cs");
  const base = css.length;
  const hasSLT = css.some((c) => c.inSLT);
  // Each CS reduces decay ~6%; SLT adds extra ~8%. Cap at 40% reduction.
  const reduction = Math.min(0.4, base * 0.06 + (hasSLT ? 0.08 : 0));
  return { satDecayMult: 1 - reduction };
};

const financeEffects = (team) => {
  const f = team.filter((t) => t.role === "finance");
  if (!f.length) return { costRed: 0, prodBoost: 0, sltVP: false };
  const redBySen = { Intern: 0.01, Junior: 0.02, Senior: 0.04, VP: 0.06 };
  const prodBySen = { Intern: 0.2, Junior: 0.4, Senior: 0.8, VP: 1.2 };
  let costRed = 0;
  let prodBoost = 0;
  let sltVP = false;
  for (let i = 0; i < f.length; i++) {
    const x = f[i];
    costRed += redBySen[x.seniority] || 0;
    prodBoost += prodBySen[x.seniority] || 0;
    if (x.seniority === "VP" && x.inSLT) sltVP = true;
  }
  return {
    costRed: Math.min(costRed, 0.06),
    prodBoost: Math.min(prodBoost, 1.5),
    sltVP,
  };
};

// ---- IT Effects ----
const itEffects = (team) => {
  const it = (team || []).filter((t) => t.role === "it");
  if (!it.length) return { overheadRed: 0, sltVP: false };

  // small, permanent automation gain (caps ~6%)
  const bySeniority = {
    Intern: 0.004,
    Junior: 0.008,
    Senior: 0.014,
    VP: 0.02,
  };

  const overheadRed = it.reduce(function (acc, e) {
    return acc + (bySeniority[e.seniority] || 0.006);
  }, 0);

  const sltVP = it.some((e) => e.seniority === "VP" && e.inSLT);
  const bonus = sltVP ? 0.01 : 0;

  return {
    overheadRed: Math.min(overheadRed + bonus, 0.06),
    sltVP,
  };
};

// ---- General SLT Effects (for functional leaders like PV/RA/QA/etc.) ----
const sltGeneralEffects = (team) => {
  const slt = (team || []).filter(
    (t) =>
      t && t.inSLT && !["hr", "finance", "cs", "bd", "corp"].includes(t.role)
  );
  const count = slt.length;
  if (!count) return { winRateMult: 1 };

  const hasVP = slt.some((t) => t.seniority === "VP");
  const base = 1 + Math.min(0.03, count * 0.005); // +0.5% each, cap +3%
  const bonus = hasVP ? 0.01 : 0;
  return { winRateMult: Math.min(1.04, base + bonus) };
};

// ---- Loans (Finance) ----
const financeLoanMetrics = (state) => {
  const team = (state && state.team) || [];
  const finance = team.filter((t) => t.role === "finance");
  const weights = { intern: 1, junior: 2, senior: 4, vp: 7 };
  let score = 0;
  finance.forEach((t) => {
    const key = String(t.seniority || "").toLowerCase();
    score += weights[key] || 1;
    if (t.inSLT) score += 2;
  });
  return { headcount: finance.length, score };
};

const maxLoanAmount = (state) => {
  const rep = clamp(0, 5000, valOr(state && state.reputation, 0));
  const repFactor = rep / 5000; // 0..1
  const m = financeLoanMetrics(state);
  // base + rep-driven capacity + finance-team driven capacity
  return Math.round(20000 + repFactor * 180000 + m.score * 15000);
};

const computeLoanOffer = (state, amount) => {
  const max = maxLoanAmount(state);
  const amt = Math.floor(valOr(amount, 0));
  if (!amt || amt <= 0)
    return { ok: false, reason: "Enter a positive amount." };
  if (amt > max)
    return {
      ok: false,
      reason: "Amount exceeds your current borrowing limit.",
    };

  const rep = clamp(0, 5000, valOr(state && state.reputation, 0));
  const repFactor = rep / 5000;
  const m = financeLoanMetrics(state);
  const ratio = clamp(0, 1, amt / max); // bigger loans = worse terms

  // Better finance team + reputation => lower APR, longer duration
  let apr = 0.22 - m.score * 0.008 - repFactor * 0.04 + ratio * 0.06;
  apr = clamp(0.06, 0.28, apr);

  let weeks = Math.round(12 + m.score * 2 + ratio * 12);
  weeks = clamp(8, 104, weeks);

  const r = apr / 52;
  const payment =
    r === 0
      ? Math.ceil(amt / weeks)
      : Math.ceil((amt * r) / (1 - Math.pow(1 + r, -weeks)));

  return {
    ok: true,
    amount: amt,
    max,
    apr,
    weeks,
    termWeeks: weeks,
    weeklyPayment: payment,
  };
};

const countByRole = (team) =>
  team.reduce((map, e) => {
    map[e.role] = (map[e.role] || 0) + 1;
    return map;
  }, {});

const freeByRole = (team, reserved) => {
  const totals = countByRole(team);
  const free = {};
  Object.keys(totals).forEach((k) => {
    const used = (reserved[k] || []).length;
    free[k] = Math.max(0, totals[k] - used);
  });
  for (let i = 0; i < ROLES.length; i++) {
    const k = ROLES[i].key;
    if (!(k in free)) free[k] = 0;
  }
  return free;
};

const canStaff = (freeMap, req) => {
  const keys = Object.keys(req);
  for (let i = 0; i < keys.length; i++) {
    const k = keys[i];
    if ((freeMap[k] || 0) < req[k]) return false;
  }
  return true;
};

const reserveForLead = (team, reserved, req) => {
  const newReserved = { ...reserved };
  Object.keys(req).forEach((roleKey) => {
    const need = req[roleKey];
    const already = new Set(newReserved[roleKey] || []);
    const pool = team.filter((t) => t.role === roleKey && !already.has(t.id));
    const take = pool.slice(0, need).map((e) => e.id);
    newReserved[roleKey] = (newReserved[roleKey] || []).concat(take);
  });
  return newReserved;
};

const releaseForLead = (reserved, req) => {
  const next = { ...reserved };
  Object.keys(req).forEach((roleKey) => {
    const need = req[roleKey];
    const arr = next[roleKey] || [];
    next[roleKey] = arr.slice(need);
  });
  return next;
};

/* -------------------- NEW: monthly cost breakdown -------------------- */
function monthlyCostDetailed(state, revByGeo, payrollCutByGeo, fin) {
  const execEff = getExecEffects(state); // NEW
  const basePayroll = Math.round(
    monthlyPayroll(state.team) *
      (state.priceLevel || 1) *
      ((execEff && execEff.payrollMult) || 1)
  );

  const finCut = Math.round(basePayroll * ((fin && fin.costRed) || 0));
  const payrollAfterFin = basePayroll - finCut;

  const payrollAfterGM = gmAdjustedPayroll(
    payrollAfterFin,
    revByGeo,
    payrollCutByGeo
  );

  // NEW: fixed SG&A by difficulty
  const diffKey =
    (state.winRateMult || 1) > 1.05
      ? "Easy"
      : (state.winRateMult || 1) < 0.9
      ? "Hard"
      : "Normal";
  const BASE_SGNA =
    diffKey === "Easy" ? 500 : diffKey === "Normal" ? 2000 : 4000;

  const acquired = state.acquiredHeadcount || 0;
  const headcountForCosts = (state.team.length || 0) + acquired;
  const itEff = itEffects(state.team || []);
  const overhead0 = Math.round(headcountForCosts * OVERHEAD_PER_EMPLOYEE);
  const rent0 = BASE_SGNA;
  const itCut = (itEff && itEff.overheadRed) || 0;
  const overhead = Math.round(overhead0 * (1 - itCut));
  const office = officeStats(state);
  const basePlatformCost = Math.round(rent0 * (1 - itCut));
  const officeRent = Math.round((office && office.rent) || 0);
  const officeSystems = Math.round(Math.max(0, officeRent * 0.08));
  const rent = basePlatformCost + officeRent + officeSystems;

  // Small scale drag after you get big (+2% of payroll after GM per contract > 6)
  const contractsCount = (state.contracts && state.contracts.length) || 0;
  const extraSgna = Math.max(0, contractsCount - 8) * 0.02;
  const scaleDrag = Math.round(payrollAfterGM * extraSgna);

  // Travel: per extra country beyond the first, per head, per month
  const activeGeos = (state.unlockedGeos && state.unlockedGeos.length) || 1;
  const extraGeos = Math.max(0, activeGeos - 1);
  const travel = Math.round(
    headcountForCosts * extraGeos * TRAVEL_COST_PER_EMPLOYEE_PER_EXTRA_GEO
  );

  const sgaTotal = overhead + rent + travel + scaleDrag; // NEW
  const total = payrollAfterGM + sgaTotal; // NEW

  return {
    basePayroll,
    finCut,
    payrollAfterGM,
    overhead,
    rent,
    basePlatformCost,
    officeRent,
    officeSystems,
    travel,
    scaleDrag, // NEW
    sgaTotal, // NEW
    total,
  };
}

/* =========================
   DATES & QUARTERS (real dates)
   ========================= */
const GAME_START_DATE = Date.UTC(2025, 0, 1); // 1 Jan 2025 (UTC)

// --- quarter helpers ---
function getQuarterKey(dateOrTs) {
  const d = dateOrTs instanceof Date ? dateOrTs : new Date(dateOrTs);
  const q = Math.floor(d.getUTCMonth() / 3) + 1;
  return `Q${q} ${d.getUTCFullYear()}`;
}

// Make a Q objective for whatever date we're in.
// Board Objectives 2.0: one quarter = a portfolio of objectives, not one random task.
function boardMonthlyRevenue(state) {
  state = state || {};
  var contracts = Array.isArray(state.contracts) ? state.contracts : [];
  var contractRev = contracts.reduce(function (sum, c) {
    if (!c) return sum;
    if (c.active === false || c.status === "ended" || c.status === "lost")
      return sum;
    if (typeof c.remainingWeeks === "number" && c.remainingWeeks <= 0)
      return sum;
    if (typeof c.monthlyRevenue === "number") return sum + c.monthlyRevenue;
    if (typeof c.weeklyRevenue === "number") return sum + c.weeklyRevenue;
    if (typeof c.estWeeklyRevenue === "number") return sum + c.estWeeklyRevenue;
    if (typeof c.annualRevenue === "number") return sum + c.annualRevenue / 12;
    return sum;
  }, 0);

  var assets = Array.isArray(state.assetsOwned) ? state.assetsOwned : [];
  var assetRev = assets.reduce(function (sum, a) {
    return sum + valOr(a && a.revPerWeekBoosted, 0) * 4;
  }, 0);

  return Math.max(0, Math.round(contractRev + assetRev));
}

function boardMonthlyCost(state) {
  state = state || {};
  if (
    state.lastMonthlyCost &&
    typeof state.lastMonthlyCost.total === "number"
  ) {
    return Math.max(0, Math.round(state.lastMonthlyCost.total));
  }
  var team = Array.isArray(state.team) ? state.team : [];
  var employees = team.length || 0;
  var countries = Math.max(0, ((state.unlockedGeos || []).length || 1) - 1);
  var estRent = Math.round(
    BASE_RENT + employees * RENT_PER_EMPLOYEE + countries * RENT_PER_COUNTRY
  );
  return Math.max(
    0,
    Math.round(
      monthlyPayroll(team) + employees * OVERHEAD_PER_EMPLOYEE + estRent
    )
  );
}

function boardTeamAverage(state, key, fallback) {
  var team = Array.isArray(state && state.team) ? state.team : [];
  if (!team.length) return fallback || 0;
  return Math.round(
    team.reduce(function (sum, e) {
      var v = e && typeof e[key] === "number" ? e[key] : fallback || 0;
      return sum + v;
    }, 0) / team.length
  );
}

function boardFinanceSnapshot(state) {
  var revenue = boardMonthlyRevenue(state);
  var cost = boardMonthlyCost(state);
  var opProfit = revenue - cost;
  var taxRate = TAX_RATES[(state && state.difficulty) || "Normal"] || 0.25;
  var tax = opProfit > 0 ? Math.round(opProfit * taxRate) : 0;
  var netIncome = opProfit - tax;
  return {
    cash: Math.round(valOr(state && state.cash, 0)),
    revenue: revenue,
    cost: cost,
    operatingProfit: opProfit,
    tax: tax,
    netIncome: netIncome,
    netMargin: revenue > 0 ? (netIncome / revenue) * 100 : 0,
    activeContracts: Array.isArray(state && state.contracts)
      ? state.contracts.length
      : 0,
    pipelineCount: Array.isArray(state && state.pipeline)
      ? state.pipeline.length
      : 0,
    headcount: Array.isArray(state && state.team) ? state.team.length : 0,
    morale: boardTeamAverage(state, "morale", 72),
    burnout: boardTeamAverage(state, "burnout", 0),
    reputation: valOr(state && state.reputation, 0),
  };
}

function boardObjectiveValue(state, stats, obj) {
  stats = stats || {};
  var snap = boardFinanceSnapshot(state || {});
  if (!obj) return 0;
  switch (obj.type) {
    case "revenue":
      return snap.revenue;
    case "net_income":
      return snap.netIncome;
    case "net_margin":
      return snap.netMargin;
    case "cash":
      return snap.cash;
    case "contracts":
      return valOr(stats.contractsWon, 0);
    case "active_contracts":
      return snap.activeContracts;
    case "pipeline":
      return valOr(stats.pipelineAdded, 0);
    case "hires":
      return valOr(stats.hires, 0);
    case "geos":
      return valOr(stats.geosUnlocked, 0);
    case "morale":
      return snap.morale;
    case "burnout_max":
      return snap.burnout;
    case "reputation":
      return snap.reputation;
    case "runrate":
      return Math.round(snap.revenue / 4);
    default:
      return 0;
  }
}

function boardObjectiveTarget(obj) {
  if (!obj) return 0;
  return valOr(
    obj.target,
    valOr(
      obj.targetValue,
      valOr(
        obj.targetWeeklyRevenue,
        valOr(
          obj.targetContracts,
          valOr(
            obj.targetHires,
            valOr(
              obj.targetGeos,
              valOr(obj.targetPipelineAdded, valOr(obj.targetReputation, 0))
            )
          )
        )
      )
    )
  );
}

function boardObjectiveProgress(state, stats, obj) {
  var current = boardObjectiveValue(state, stats, obj);
  var target = boardObjectiveTarget(obj);
  var pct;
  if (!obj || !target) pct = 0;
  else if (obj.direction === "max")
    pct =
      current <= target
        ? 100
        : Math.max(0, 100 - ((current - target) / Math.max(1, target)) * 100);
  else pct = Math.max(0, Math.min(100, (current / Math.max(1, target)) * 100));
  var achieved =
    obj && obj.direction === "max" ? current <= target : current >= target;
  return { current: current, target: target, pct: pct, achieved: !!achieved };
}

function boardScoreFor(state, stats, boardObj) {
  if (!boardObj) return 0;
  if (!Array.isArray(boardObj.objectives) || boardObj.objectives.length === 0) {
    return evalLegacyObjective(state, stats || {}, boardObj) ? 100 : 0;
  }
  var totalWeight =
    boardObj.objectives.reduce(function (sum, o) {
      return sum + valOr(o.weight, 1);
    }, 0) || 1;
  var weighted = boardObj.objectives.reduce(function (sum, o) {
    var p = boardObjectiveProgress(state, stats, o).pct;
    return sum + Math.min(100, Math.max(0, p)) * valOr(o.weight, 1);
  }, 0);
  return Math.round(weighted / totalWeight);
}

function boardRating(score) {
  if (score >= 90) return { label: "Excellent", tone: "great", icon: "🏆" };
  if (score >= 75) return { label: "Approved", tone: "good", icon: "✅" };
  if (score >= 55) return { label: "Under pressure", tone: "warn", icon: "⚠️" };
  return { label: "Board concern", tone: "bad", icon: "🚨" };
}

function makeQuarterObjectiveFor(ts, weeklyRunRate, state) {
  if (typeof ts !== "number" && !(ts instanceof Date))
    ts = (state && state.currentDate) || GAME_START_DATE;
  state = state || {};

  var d = new Date(ts);
  var year = d.getUTCFullYear();
  var month = d.getUTCMonth();
  var quarter = Math.floor(month / 3) + 1;
  var nextQMonth = (Math.floor(month / 3) * 3 + 3) % 12;
  var nextQYear = year + (month >= 9 ? 1 : 0);
  var dueAt = Date.UTC(nextQYear, nextQMonth, 1);
  var qKey = "Q" + quarter + " " + year;
  var isLaw = companyTypeKey(state && state.companyType) === "law";
  var contractNoun = isLaw ? "matters" : "contracts";
  var dealNoun = isLaw ? "matters" : "deals";
  var snap = boardFinanceSnapshot(state);
  var rev = Math.max(0, snap.revenue);
  var margin = Math.max(0, snap.netMargin);
  var currentCash = Math.max(0, snap.cash);
  var teamSize = Math.max(0, snap.headcount);
  var unlocked = (state.unlockedGeos || []).length || 1;

  function mk(type, title, target, weight, why, lever, direction) {
    return {
      id: id(),
      type: type,
      title: title,
      target: target,
      weight: weight,
      why: why,
      lever: lever,
      direction: direction || "min",
    };
  }

  var growthTarget = Math.max(
    40000,
    Math.round(Math.max(rev * 1.18, rev + 120000) / 10000) * 10000
  );
  var incomeTarget = Math.max(
    20000,
    Math.round(Math.max(snap.netIncome * 1.12, rev * 0.18) / 10000) * 10000
  );
  var marginTarget =
    rev > 0
      ? Math.max(12, Math.min(38, Math.round(Math.max(15, margin + 3))))
      : 10;
  var cashTarget = Math.max(
    150000,
    Math.round(
      Math.max(currentCash * 0.82, boardMonthlyCost(state) * 3) / 10000
    ) * 10000
  );
  var contractTarget = Math.max(1, Math.min(6, Math.ceil((teamSize || 4) / 5)));
  var pipelineTarget = Math.max(3, Math.min(10, Math.ceil(contractTarget * 2)));
  var moraleTarget = teamSize > 0 ? 68 : 60;
  var burnoutMax = teamSize > 0 ? 42 : 70;

  var pool = [
    mk(
      "revenue",
      "Reach €" + growthTarget.toLocaleString() + " monthly revenue",
      growthTarget,
      2.0,
      "Growth keeps the company fundable.",
      "Win higher-value contracts and protect renewals."
    ),
    mk(
      "net_income",
      "Deliver €" + incomeTarget.toLocaleString() + " monthly net income",
      incomeTarget,
      1.8,
      "The board wants profitable growth, not vanity revenue.",
      "Control payroll, delivery costs, discounts and failed renewals."
    ),
    mk(
      "net_margin",
      "Keep net income margin above " + marginTarget + "%",
      marginTarget,
      1.4,
      "Margin discipline proves the model scales.",
      "Avoid low-quality contracts and manage SG&A."
    ),
    mk(
      "cash",
      "Keep cash above €" + cashTarget.toLocaleString(),
      cashTarget,
      1.2,
      "Cash gives you strategic room to hire, expand and survive shocks.",
      "Delay non-essential spend and convert pipeline faster."
    ),
    mk(
      "contracts",
      "Sign " + contractTarget + " new " + contractNoun,
      contractTarget,
      1.5,
      "New logos validate commercial momentum.",
      "Prioritize staffable leads with strong probability."
    ),
    mk(
      "pipeline",
      "Add " + pipelineTarget + " qualified " + dealNoun + " to pipeline",
      pipelineTarget,
      1.0,
      "Pipeline is the future revenue engine.",
      "Use BD capacity and conferences intelligently."
    ),
    mk(
      "morale",
      "Keep average morale above " + moraleTarget + "%",
      moraleTarget,
      1.0,
      "Execution quality collapses when the team disengages.",
      "Promote, pay fairly and avoid overload."
    ),
    mk(
      "burnout_max",
      "Keep average burnout below " + burnoutMax + "%",
      burnoutMax,
      1.0,
      "Burnout creates attrition and missed delivery.",
      "Hire capacity before signing everything.",
      "max"
    ),
  ];

  if (unlocked < 3)
    pool.push(
      mk(
        "geos",
        "Unlock 1 new geography",
        1,
        1.1,
        "The board wants a credible expansion story.",
        "Use a Head of Growth / Corporate Dev capacity."
      )
    );

  var objectives = [pool[0], pool[1]];
  var cursor = Math.abs(
    (year * 7 + quarter * 11 + teamSize * 3 + Math.round(rev / 10000)) %
      pool.length
  );
  while (objectives.length < 4) {
    var candidate = pool[cursor % pool.length];
    if (
      !objectives.some(function (o) {
        return o.type === candidate.type;
      })
    )
      objectives.push(candidate);
    cursor += 2;
  }

  var rewardCash =
    Math.round(
      (growthTarget * 0.18 + incomeTarget * 0.35 + contractTarget * 45000) /
        10000
    ) * 10000;
  var penaltyRep = Math.max(
    120,
    Math.min(
      900,
      Math.round(220 + objectives.length * 55 + (rev > 500000 ? 120 : 0))
    )
  );

  return {
    id: id(),
    type: "board_v2",
    title: "Board Objectives 2.0",
    quarter: qKey,
    dueAt: dueAt,
    settled: false,
    objectives: objectives,
    rewardCash: rewardCash,
    penaltyRep: penaltyRep,
    passScore: 75,
    excellenceScore: 90,
  };
}

function evalLegacyObjective(state, stats, obj) {
  if (!obj) return false;
  if (obj.type === "runrate")
    return (
      Math.round(boardMonthlyRevenue(state) / 4) >=
      valOr(obj.targetWeeklyRevenue, 0)
    );
  if (obj.type === "contracts")
    return (stats.contractsWon || 0) >= obj.targetContracts;
  if (obj.type === "geos") return (stats.geosUnlocked || 0) >= obj.targetGeos;
  if (obj.type === "hires") return (stats.hires || 0) >= obj.targetHires;
  if (obj.type === "pipeline")
    return (stats.pipelineAdded || 0) >= obj.targetPipelineAdded;
  if (obj.type === "reputation")
    return (state.reputation || 0) >= obj.targetReputation;
  if (obj.type === "active_contracts")
    return (state.contracts || []).length >= obj.targetActiveContracts;
  return false;
}

const evalObjective = (state, stats, obj) => {
  if (!obj) return false;
  if (Array.isArray(obj.objectives))
    return boardScoreFor(state, stats || {}, obj) >= valOr(obj.passScore, 75);
  return evalLegacyObjective(state, stats || {}, obj);
};

function finalizeQuarter(state) {
  var cur =
    state.boardCurrent ||
    (state.board && (state.board.current || state.board.currentObjective));
  if (!cur) return;
  var score = boardScoreFor(state, state.boardStats || {}, cur);
  var rating = boardRating(score);
  var success = score >= valOr(cur.passScore, 75);
  var excellent = score >= valOr(cur.excellenceScore, 90);
  var reward = 0;
  var repLoss = 0;
  var cashPenalty = 0;

  // Board pressure is now a board-patience meter: 100 = comfortable, 0 = fired on Hard.
  // Good quarters rebuild trust; weak quarters burn remaining patience.
  if (excellent) {
    reward = cur.rewardCash || 0;
    state.cash += reward;
    state.reputation = clamp((state.reputation || 0) + 60, 0, REPUTATION_MAX);
    state.boardPressure = clamp(valOr(state.boardPressure, 70) + 16, 0, 100);
  } else if (success) {
    reward = Math.round((cur.rewardCash || 0) * 0.55);
    state.cash += reward;
    state.reputation = clamp((state.reputation || 0) + 20, 0, REPUTATION_MAX);
    state.boardPressure = clamp(valOr(state.boardPressure, 70) + 8, 0, 100);
  } else if (score >= 55) {
    repLoss = Math.round((cur.penaltyRep || 0) * 0.45);
    state.reputation = clamp(
      (state.reputation || 0) - repLoss,
      0,
      REPUTATION_MAX
    );
    state.boardPressure = clamp(valOr(state.boardPressure, 70) - 18, 0, 100);
  } else {
    repLoss = cur.penaltyRep || 0;
    cashPenalty = Math.round(
      Math.min(Math.max(0, state.cash || 0) * 0.04, 250000)
    );
    state.reputation = clamp(
      (state.reputation || 0) - repLoss,
      0,
      REPUTATION_MAX
    );
    state.cash = Math.round((state.cash || 0) - cashPenalty);
    state.boardPressure = clamp(valOr(state.boardPressure, 70) - 32, 0, 100);
  }

  var objectiveResults = Array.isArray(cur.objectives)
    ? cur.objectives.map(function (o) {
        var p = boardObjectiveProgress(state, state.boardStats || {}, o);
        return {
          title: o.title,
          type: o.type,
          current: p.current,
          target: p.target,
          pct: Math.round(p.pct),
          achieved: p.achieved,
        };
      })
    : [];

  state.boardHistory = (state.boardHistory || [])
    .concat([
      {
        quarter: cur.quarter,
        title: cur.title || "Board objectives",
        success: success,
        score: score,
        rating: rating.label,
        reward: reward,
        repLoss: repLoss,
        cashPenalty: cashPenalty,
        objectives: objectiveResults,
      },
    ])
    .slice(-12);
  state.boardLastOutcome = {
    success: success,
    score: score,
    rating: rating.label,
    reward: reward,
    repLoss: repLoss,
    cashPenalty: cashPenalty,
    boardPressure: state.boardPressure,
    objectives: objectiveResults,
  };

  if (
    isHardDifficulty(state.difficulty) &&
    !state.gameOver &&
    valOr(state.boardPressure, 70) <= 0
  ) {
    state.gameOver = true;
    state.gameOverReason = {
      type: "board_pressure",
      title: "Board Confidence Lost — Game Over",
      body: "Board pressure hit 0 on Hard difficulty. The board has lost patience and removed you as CEO.",
    };
  }
}

/* =========================
   HR CAPACITY
   ========================= */
const BASE_CAPACITY = 10;
const HR_CAPACITY_BY_SENIORITY = { Intern: 5, Junior: 10, Senior: 15, VP: 25 };
const calcCapacity = (team) => {
  const hrs = team.filter((t) => t.role === "hr");
  const extra = hrs.reduce(
    (sum, h) => sum + (HR_CAPACITY_BY_SENIORITY[h.seniority] || 0),
    0
  );
  return BASE_CAPACITY + extra;
};

function recordTeamMetricSnapshot(state) {
  var team = Array.isArray(state && state.team) ? state.team : [];
  function avg(getter) {
    if (!team.length) return 0;
    return Math.round(
      team.reduce(function (sum, e) {
        return sum + Number(getter(e) || 0);
      }, 0) / team.length
    );
  }
  var snapshot = {
    week: state.week || 0,
    ts: state.currentDate || Date.now(),
    employees: team.length,
    morale: avg(function (e) {
      return e && typeof e.morale === "number" ? e.morale : 0;
    }),
    burnout: avg(function (e) {
      return e && typeof e.burnout === "number" ? e.burnout : 0;
    }),
    flight: avg(function (e) {
      return e && typeof e.flightRisk === "number" ? e.flightRisk : 0;
    }),
  };
  var hist = Array.isArray(state.teamMetricHistory)
    ? state.teamMetricHistory
    : [];
  if (hist.length && hist[hist.length - 1].week === snapshot.week) {
    hist = hist.slice(0, -1);
  }
  state.teamMetricHistory = hist.concat([snapshot]).slice(-52);
}

function refreshApplicantsWeekly(s) {
  // keep at least this many per role (varies by company type)
  const MIN_BY_ROLE =
    companyTypeKey(s.companyType) === "law"
      ? { reg: 3, corp: 3, pv: 2, qa: 2, ops: 2, bd: 1, gm: 1 }
      : { reg: 2, pv: 2, ma: 2, qa: 2, ops: 2, corp: 2 };

  const MAX_POOL = 28;
  // age existing applicants and randomly cull older ones
  s.applicants = s.applicants
    .map((a) => ({ ...a, _age: (a._age || 0) + 1 }))
    .filter((a) => (a._age || 0) <= 8 || Math.random() > 0.35);

  // ensure floors by role
  const counts = {};
  s.applicants.forEach((a) => (counts[a.role] = (counts[a.role] || 0) + 1));
  ROLES.forEach((r) => {
    const floor = MIN_BY_ROLE[r.key] || 1;
    while ((counts[r.key] || 0) < floor) {
      const newbie = { ...makeApplicant(r.key), _age: 0 };
      s.applicants.push(newbie);
      counts[r.key] = (counts[r.key] || 0) + 1;
    }
  });

  // small random trickle each week (1–3)
  const extra = rand(1, 3);
  for (let i = 0; i < extra && s.applicants.length < MAX_POOL; i++) {
    const role = choice(ROLES).key;
    s.applicants.push({ ...makeApplicant(role), _age: 0 });
  }
}

// ========== ORG SYSTEM (Blueprints, Units, Centralization, Spans) ==========

// Safely ensure we have org data in state
function contractMonthlyRevenue(c) {
  if (!c) return 0;
  if (typeof c.monthlyRevenue === "number") return c.monthlyRevenue;
  if (typeof c.weeklyRevenue === "number") return c.weeklyRevenue; // your code uses this as monthly in places
  if (typeof c.estWeeklyRevenue === "number") return c.estWeeklyRevenue;
  return 0;
}

// per-employee monthly cost (mirrors Team calc)
function empMonthlyCost(state, e) {
  if (!e) return 0;
  // direct fields first (weekly -> monthly)
  if (typeof e.weeklyCost === "number") return Math.round(e.weeklyCost * 4);
  if (typeof e.costPerWeek === "number") return Math.round(e.costPerWeek * 4);
  if (typeof e.salaryPerWeek === "number")
    return Math.round(e.salaryPerWeek * 4);
  if (typeof e.salary === "number") return Math.round(e.salary * 4);

  // derive from role table
  var roleObj = typeof findRole === "function" ? findRole(e.role) || {} : {};
  var base =
    typeof roleObj.baseMonthly === "number" ? roleObj.baseMonthly : 2500;
  var idx = typeof e.salaryIndex === "number" ? e.salaryIndex : 1;
  var slt = e.inSLT === true ? 1.25 : 1;
  var mult =
    typeof SENIORITY_MULT === "object" && SENIORITY_MULT[e.seniority]
      ? SENIORITY_MULT[e.seniority]
      : 1;
  var level = mult * slt * idx;
  var price = (state && state.priceLevel) || 1;
  return Math.round(base * level * price);
}

// Compute per-OU headcount, direct cost, revenue, SSC allocation, margin (all MONTHLY)
// ---- Canonical mapping for areas (teams) and geos
// ---- Canonical mapping for areas (teams) and geos
function canonicalAreaName(x) {
  if (!x) return "";
  var s = String(x).toLowerCase();
  // normalize common spellings / synonyms
  if (s.indexOf("regul") >= 0 || s.trim() === "ra") return "Regulatory";
  if (s.indexOf("pv") >= 0 || s.indexOf("pharmacovigil") >= 0) return "PV";
  if (s.indexOf("medical") >= 0) return "Medical Affairs";
  if (s === "qa" || s.indexOf("quality") >= 0) return "Quality";
  if (s.indexOf("clinical") >= 0) return "Clinical Services";
  if (
    s.indexOf("finance") >= 0 ||
    s.indexOf("account") >= 0 ||
    s.indexOf("cfo") >= 0
  )
    return "Finance";
  if (
    s === "bd" ||
    s.indexOf("business dev") >= 0 ||
    s.indexOf("growth") >= 0 ||
    s.indexOf("sales") >= 0
  )
    return "BD";
  if (s === "corp" || s.indexOf("corporate") >= 0 || s.indexOf("strategy") >= 0)
    return "Corp";
  if (s.indexOf("human") >= 0 || s.indexOf("people") >= 0 || s.trim() === "hr")
    return "HR";
  if (
    s.trim() === "it" ||
    s.indexOf("tech") >= 0 ||
    s.indexOf("tools") >= 0 ||
    s.indexOf("systems") >= 0
  )
    return "IT";
  if (
    s.indexOf("ops") >= 0 ||
    s.indexOf("operation") >= 0 ||
    s.indexOf("delivery") >= 0
  )
    return "Ops & Delivery";
  if (s.indexOf("legal") >= 0 || s.indexOf("contract") >= 0) return "Legal";
  if (
    s.indexOf("customer") >= 0 ||
    s.indexOf("support") >= 0 ||
    s.indexOf("service") >= 0 ||
    s.indexOf("success") >= 0
  )
    return "Customer Service";
  return "";
}

function canonicalGeoName(x) {
  if (!x) return "";
  var s = String(x).toLowerCase().trim();
  if (!s) return "";
  if (s.indexOf("global") >= 0) return "Global";
  if (s.indexOf("emea") >= 0) return "EMEA";
  if (
    s.indexOf("amer") >= 0 ||
    s.indexOf("na") >= 0 ||
    s.indexOf("north america") >= 0 ||
    s === "us"
  )
    return "AMER";
  if (s.indexOf("apac") >= 0 || s.indexOf("asia") >= 0 || s.indexOf("anz") >= 0)
    return "APAC";
  if (s.indexOf("nordic") >= 0) return "Nordics";
  if (s.indexOf("france") >= 0 || s === "fr") return "France";
  if (
    s === "uk" ||
    s.indexOf("united kingdom") >= 0 ||
    s.indexOf("britain") >= 0
  )
    return "UK";
  if (s.indexOf("germany") >= 0 || s === "de") return "Germany";
  if (s.indexOf("italy") >= 0 || s === "it") return "Italy";
  if (s.indexOf("spain") >= 0 || s === "es") return "Spain";
  return s.toUpperCase(); // fallback
}

// Pull an employee's logical team and geo from whatever fields exist in your schema
// Contract-side area/geo
// Find the best BU given area/geo; ignores Shared Services; 'Global' in OU accepts all geos
// Shared-services-only lookup (route HR/IT/Finance/etc. into Shared Service cards)
var SUPPORT_AREAS = [
  "HR",
  "IT",
  "Finance",
  "Legal",
  "Customer Service",
  "Corp",
  "Ops & Delivery",
  "BD",
];

function findSharedOuByAreaGeo(state, area, geo) {
  if (!state.org || !Array.isArray(state.org.orgUnits)) return null;
  var ous = state.org.orgUnits;
  var bestId = null,
    bestScore = -1;
  for (var i = 0; i < ous.length; i++) {
    var ou = ous[i];
    if (!ou || ou.type !== "SharedService") continue; // ONLY Shared Services
    var sc = 0;
    var areas = ou.scope && Array.isArray(ou.scope.areas) ? ou.scope.areas : [];
    var geos =
      ou.scope && Array.isArray(ou.scope.geos) ? ou.scope.geos : ["Global"];
    if (area && areas.indexOf(area) >= 0) sc += 3;
    if (geo) {
      if (geos.indexOf("Global") >= 0) sc += 1;
      if (geos.indexOf(geo) >= 0) sc += 3;
    } else {
      sc += 1;
    }
    if (sc > bestScore) {
      bestScore = sc;
      bestId = ou.id;
    }
  }
  return bestId;
}

// ---- Leader / Exec perks + helpers
function employeeKey(p) {
  return p && (p.id || p.email || (p.name ? "id:" + p.name : ""));
}
function isVP(p) {
  var s = (
    (p.role || "") +
    " " +
    (p.title || "") +
    " " +
    (p.position || "")
  ).toLowerCase();
  var senior = (p.seniority || "").toString().toLowerCase();
  if (senior === "vp") return true;
  return s.indexOf("vice president") >= 0 || /\bvp\b/.test(s);
}
function isExecTitle(p) {
  var s = ((p.role || "") + " " + (p.title || "")).toLowerCase();
  if (s.indexOf("cfo") >= 0 || s.indexOf("chief financial") >= 0) return true;
  // treat CPO as Chief People Officer here (adjust if your game uses Product)
  if (s.indexOf("cpo") >= 0 || s.indexOf("chief people officer") >= 0)
    return true;
  if (s.indexOf("head of growth") >= 0 || s.indexOf("growth lead") >= 0)
    return true;
  return false;
}
function applyLeadershipPerks(state) {
  ensureOrgInit(state);
  var leaders = {};
  var ous = state.org && state.org.orgUnits ? state.org.orgUnits : [];
  for (var i = 0; i < ous.length; i++) {
    var m = ous[i] && ous[i].managerId;
    if (m) leaders[m] = true;
  }
  var emps = getAllEmployees(state);
  for (var j = 0; j < emps.length; j++) {
    var e = emps[j] || {};
    var key = employeeKey(e);
    var isLeader = !!leaders[key];
    var isExec = isExecTitle(e);
    if (isLeader || isExec) {
      // apply 100% satisfaction perk
      e.satisfaction = 1;
      e.satisfactionPerk = 1;
      e.happiness = 1; // if your game uses this field instead
    }
  }
}

// Pull an employee's logical team and geo from whatever fields exist
function getEmployeeArea(e) {
  var candidates = [
    e.team,
    e.function,
    e.department,
    e.area,
    e.roleCategory,
    e.role,
    e.title,
  ];
  for (var i = 0; i < candidates.length; i++) {
    var c = canonicalAreaName(candidates[i]);
    if (c) return c;
  }
  return ""; // unknown
}
function getEmployeeGeo(e) {
  var candidates = [e.geo, e.region, e.country, e.location];
  for (var i = 0; i < candidates.length; i++) {
    var c = canonicalGeoName(candidates[i]);
    if (c) return c;
  }
  return ""; // unknown
}

// Contract-side area/geo
function getContractArea(c) {
  var candidates = [
    c.area,
    c.serviceArea,
    c.serviceLine,
    c.type,
    c.category,
    c.title,
  ];
  for (var i = 0; i < candidates.length; i++) {
    var cName = canonicalAreaName(candidates[i]);
    if (cName) return cName;
  }
  return ""; // unknown
}
function getContractGeo(c) {
  var candidates = [c.geo, c.region, c.country, c.market];
  for (var i = 0; i < candidates.length; i++) {
    var g = canonicalGeoName(candidates[i]);
    if (g) return g;
  }
  return ""; // unknown
}

// Find the best BU given area/geo; ignores Shared Services; 'Global' in OU accepts all geos
function findOuByAreaGeo(state, area, geo) {
  if (!state.org || !Array.isArray(state.org.orgUnits)) return null;
  var ous = state.org.orgUnits;
  var bestId = null,
    bestScore = -1;
  for (var i = 0; i < ous.length; i++) {
    var ou = ous[i];
    if (!ou || ou.type === "SharedService" || ou.id === "OU_CORP") continue;
    var sc = 0;
    var areas = ou.scope && Array.isArray(ou.scope.areas) ? ou.scope.areas : [];
    var geos =
      ou.scope && Array.isArray(ou.scope.geos) ? ou.scope.geos : ["Global"];
    if (area && areas.indexOf(area) >= 0) sc += 3;
    if (geo) {
      if (geos.indexOf("Global") >= 0) sc += 1;
      if (geos.indexOf(geo) >= 0) sc += 3;
    } else {
      sc += 1; // no geo info -> mild match
    }
    if (sc > bestScore) {
      bestScore = sc;
      bestId = ou.id;
    }
  }
  return bestId;
}

function getAllEmployees(state) {
  if (Array.isArray(state.team)) return state.team; // primary
  if (Array.isArray(state.employees)) return state.employees; // alt
  if (state.people && Array.isArray(state.people)) return state.people;
  if (state.hr && Array.isArray(state.hr.employees)) return state.hr.employees;
  return [];
}

// ---- Per-OU P&L (monthly) ----
function recomputeOrgPnl(state) {
  ensureOrgInit(state);
  try {
    recomputeOrgPnl(state);
  } catch (_e) {}

  var ous = state.org && state.org.orgUnits ? state.org.orgUnits : [];
  var i;

  // reset KPIs
  for (i = 0; i < ous.length; i++) {
    ous[i].kpis = {
      headcount: 0,
      revenue: 0,
      directCost: 0,
      sscAllocated: 0,
      margin: 0,
    };
  }

  // --- EMPLOYEES → direct cost & headcount (monthly cost)
  var emps = getAllEmployees(state);
  for (i = 0; i < emps.length; i++) {
    var e = emps[i] || {};
    var area = getEmployeeArea(e);
    var geo = getEmployeeGeo(e);
    var targetOuId = e.orgUnitId;

    if (!targetOuId) {
      if (area && SUPPORT_AREAS.indexOf(area) >= 0) {
        // Route HR/IT/Finance/etc. to Shared Service cards
        targetOuId = findSharedOuByAreaGeo(state, area, geo);
        if (!targetOuId) targetOuId = "OU_CORP";
      } else {
        // Route delivery/BU areas to BU/Division cards
        targetOuId = findOuByAreaGeo(state, area, geo);
        if (!targetOuId) targetOuId = "OU_CORP";
      }
    }

    // robust monthly cost
    var monthly = 0;
    if (typeof e.weeklyCost === "number")
      monthly = Math.round(e.weeklyCost * 4);
    else if (typeof e.costPerWeek === "number")
      monthly = Math.round(e.costPerWeek * 4);
    else if (typeof e.salaryPerWeek === "number")
      monthly = Math.round(e.salaryPerWeek * 4);
    else if (typeof e.salary === "number") monthly = Math.round(e.salary * 4);
    else {
      var roleObj =
        typeof findRole === "function" ? findRole(e.role) || {} : {};
      var base =
        typeof roleObj.baseMonthly === "number" ? roleObj.baseMonthly : 2500;
      var idx = typeof e.salaryIndex === "number" ? e.salaryIndex : 1;
      var slt = e.inSLT === true ? 1.25 : 1;
      var mult =
        typeof SENIORITY_MULT === "object" && SENIORITY_MULT[e.seniority]
          ? SENIORITY_MULT[e.seniority]
          : 1;
      var price = (state && state.priceLevel) || 1;
      monthly = Math.round(base * mult * slt * idx * price);
    }

    var idx = indexOfOu(ous, targetOuId);
    if (idx < 0) idx = indexOfOu(ous, "OU_CORP");
    if (idx >= 0) {
      ous[idx].kpis.headcount += 1;
      ous[idx].kpis.directCost += Math.max(0, monthly);
    }
  }

  // --- CONTRACTS → revenue (MONTHLY)
  var contracts = getAllActiveContracts(state);
  for (i = 0; i < contracts.length; i++) {
    var c = contracts[i] || {};

    // Normalize to MONTHLY revenue:
    // prefer explicit monthly, else weekly*4, else annual/12
    var monthlyRev = 0;
    if (typeof c.monthlyRevenue === "number") monthlyRev = c.monthlyRevenue;
    else if (typeof c.weeklyRevenue === "number")
      monthlyRev = c.weeklyRevenue * 4;
    else if (typeof c.estWeeklyRevenue === "number")
      monthlyRev = c.estWeeklyRevenue * 4;
    else if (typeof c.annualRevenue === "number")
      monthlyRev = c.annualRevenue / 12;
    else if (typeof c.revenue === "number") {
      // legacy: treat "revenue" as monthly if it looks monthly, else assume monthly
      monthlyRev = c.revenue;
    }

    var cid = c.orgUnitId;
    if (!cid) {
      var ca = getContractArea(c);
      var cg = getContractGeo(c);
      if (ca) cid = findOuByAreaGeo(state, ca, cg);
    }
    if (!cid) cid = "OU_CORP";

    var cIdx = indexOfOu(ous, cid);
    if (cIdx < 0) cIdx = indexOfOu(ous, "OU_CORP");
    if (cIdx >= 0) ous[cIdx].kpis.revenue += Math.max(0, monthlyRev);
  }

  // --- Shared Services allocation (headcount share, still monthly)
  var totalHC = 0;
  for (i = 0; i < ous.length; i++)
    if (ous[i].type !== "SharedService") totalHC += ous[i].kpis.headcount || 0;
  if (totalHC < 1) totalHC = 1;

  var ssTotal = 0;
  for (i = 0; i < ous.length; i++)
    if (ous[i].type === "SharedService") ssTotal += ous[i].kpis.directCost || 0;

  for (i = 0; i < ous.length; i++) {
    if (ous[i].type === "SharedService") continue;
    var share = (ous[i].kpis.headcount || 0) / totalHC;
    ous[i].kpis.sscAllocated = ssTotal * share;
  }

  // --- margins (Rev annual vs costs monthly → margin is illustrative only)
  for (i = 0; i < ous.length; i++) {
    var k = ous[i].kpis;
    if (ous[i].type === "SharedService") {
      k.margin = -Math.max(0, k.directCost || 0);
    } else {
      k.margin =
        Math.max(0, k.revenue || 0) -
        (Math.max(0, k.directCost || 0) + Math.max(0, k.sscAllocated || 0));
    }
  }
}

// Weekly org effects (span warnings, centralization placeholders)
// ===== Strategic Market Events (rare, lasting) =====
function randInt(a, b) {
  return Math.floor(Math.random() * (b - a + 1)) + a;
}
function clamp01(x) {
  return x < 0 ? 0 : x > 1 ? 1 : x;
}
function weeksToMs(w) {
  return w * 7 * 24 * 60 * 60 * 1000;
}

function ensureMarketIntelInit(state) {
  if (!state.marketIntel)
    state.marketIntel = { active: [], nextTs: null, lastId: 0 };
  if (typeof state.marketIntel.nextTs !== "number") {
    var now = new Date(state.currentDate || Date.now()).getTime();
    // first event scheduled 8–16 weeks out
    state.marketIntel.nextTs = now + weeksToMs(randInt(8, 16));
  }
}

function tickDownMarketIntel(state) {
  ensureMarketIntelInit(state);
  var arr = state.marketIntel.active || [];
  for (var i = arr.length - 1; i >= 0; i--) {
    arr[i].weeksLeft -= 1;
    if (arr[i].weeksLeft <= 0) arr.splice(i, 1);
  }
}

function aggregateMarketModifiers(state) {
  ensureMarketIntelInit(state);
  var mods = {
    revMult: 1,
    costMult: 1,
    reputationDelta: 0,
    marketShareDelta: 0,
  };
  var arr = state.marketIntel.active || [];
  for (var i = 0; i < arr.length; i++) {
    var e = arr[i] || {};
    var fx = e.effects || {};
    if (typeof fx.revMult === "number") mods.revMult *= fx.revMult;
    if (typeof fx.costMult === "number") mods.costMult *= fx.costMult;
    if (typeof fx.reputationDelta === "number")
      mods.reputationDelta += fx.reputationDelta;
    if (typeof fx.marketShareDelta === "number")
      mods.marketShareDelta += fx.marketShareDelta;
  }
  return mods;
}

function pushInbox(state, title, body) {
  if (!state.inbox) state.inbox = [];
  state.inbox.unshift({
    id: "intel_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
    title: title,
    from: "Corporate Dev",
    createdAt: Date.now(),
    unread: true,
    body: body,
  });
  if (state.inbox.length > 60) state.inbox.length = 60;
}

// Event-style emails (not gated by templates). Used for renewals / cross-sells.
function pushEventMail(state, from, subject, body) {
  state.mailbox = state.mailbox || [];
  state.mailbox.push({
    id: "mail_evt_" + Date.now() + "_" + Math.random().toString(36).slice(2, 7),
    from: from || "Sales",
    subject: subject || "Update",
    body: body || "",
    createdAt: Date.now(),
    resolved: false,
    options: [],
  });
  if (state.mailbox.length > 120) state.mailbox = state.mailbox.slice(-120);
}

function roleLabelForMail(state, role) {
  try {
    return roleLabelForType(state && state.companyType, role);
  } catch (e) {
    try {
      return ROLE_LABEL(role, state && state.companyType);
    } catch (err) {
      return String(role || "Role");
    }
  }
}

function formatStaffingBreakdownForMail(state, req, free) {
  req = req || {};
  free = free || {};
  var keys = Object.keys(req).sort(function (a, b) {
    return roleLabelForMail(state, a).localeCompare(roleLabelForMail(state, b));
  });
  if (!keys.length) {
    return {
      requiredText: "  - No specific staffing requirement",
      availableText: "  - Not applicable",
      missingText: "  - None",
      missingSummary: "None",
    };
  }
  var required = [];
  var available = [];
  var missing = [];
  keys.forEach(function (role) {
    var need = valOr(req[role], 0);
    var have = valOr(free[role], 0);
    var gap = Math.max(0, need - have);
    var label = roleLabelForMail(state, role);
    required.push("  - " + label + " x" + need);
    available.push("  - " + label + " x" + have);
    if (gap > 0) missing.push("  - " + label + " x" + gap);
  });
  return {
    requiredText: required.join("\n"),
    availableText: available.join("\n"),
    missingText: missing.length ? missing.join("\n") : "  - None",
    missingSummary: missing.length
      ? missing
          .map(function (x) {
            return x.replace(/^\s*-\s*/, "");
          })
          .join(", ")
      : "None",
  };
}

function opportunityEventMailBody(state, kind, outcome, data) {
  data = data || {};
  var lines = [];
  var area = data.area
    ? displayAreaName(data.area, state && state.buMap)
    : "N/A";
  var contractName = data.contractName || data.name || "N/A";
  lines.push(kind + " " + outcome + ".");
  lines.push("");
  lines.push("• Client: " + (data.client || "N/A"));
  lines.push("• Area: " + area);
  if (data.geo) lines.push("• Geography: " + data.geo);
  if (contractName !== "N/A") lines.push("• Contract: " + contractName);
  if (typeof data.weeklyRevenue === "number") {
    lines.push(
      "• Weekly revenue: €" +
        Math.round(data.weeklyRevenue).toLocaleString() +
        "/wk"
    );
  }
  if (typeof data.durationWeeks === "number") {
    lines.push("• Duration: " + data.durationWeeks + " weeks");
  }

  if (data.req) {
    var staffing = formatStaffingBreakdownForMail(
      state,
      data.req,
      data.free || {}
    );
    lines.push("");
    lines.push("Required people:");
    lines.push(staffing.requiredText);
    lines.push("");
    lines.push("Available at decision:");
    lines.push(staffing.availableText);
    lines.push("");
    lines.push(
      outcome.toLowerCase().indexOf("missed") >= 0
        ? "Missing to win:"
        : "Capacity check:"
    );
    lines.push(
      outcome.toLowerCase().indexOf("missed") >= 0
        ? staffing.missingText
        : "  - Ready / staffed"
    );
  }

  if (data.fix) {
    lines.push("");
    lines.push("Next action:");
    lines.push("  - " + data.fix);
  }
  return lines.join("\n");
}

function rollStrategicMarketEvent(state, logs) {
  ensureMarketIntelInit(state);
  tickDownMarketIntel(state);

  var now = new Date(state.currentDate || Date.now()).getTime();
  if (now < state.marketIntel.nextTs) return; // not time yet

  // Pool of meaningful events — each lasts 26–52 weeks
  var pool = [
    {
      key: "price_war",
      title: "Price war erupts in EMEA",
      body: "Aggressive discounting compresses achievable price across the market. Revenue −5% for 26 weeks.",
      effects: { revMult: 0.95 },
      weeks: 26,
    },
    {
      key: "reimb_uplift_fr",
      title: "Reimbursement uplift in France",
      body: "Payers increase reimbursement for CLS services. Revenue +8% for 52 weeks.",
      effects: { revMult: 1.08 },
      weeks: 52,
    },
    {
      key: "ai_breakthrough",
      title: "AI delivery breakthrough",
      body: "Automation improves throughput and upsell. Revenue +6% for 52 weeks.",
      effects: { revMult: 1.06 },
      weeks: 52,
    },
    {
      key: "marquee_win",
      title: "Marquee client awards multi-year deal",
      body: "Brand up, market share climbs +1.2pp over the next year. Reputation +150.",
      effects: { marketShareDelta: 0.012, reputationDelta: 150 },
      weeks: 52,
    },
    {
      key: "talent_tight_reg",
      title: "Regulatory talent market tightens",
      body: "Hiring/retention pressure increases delivery costs. Cost +5% for 26 weeks.",
      effects: { costMult: 1.05 },
      weeks: 26,
    },
    {
      key: "competitor_breach",
      title: "Competitor data breach",
      body: "Clients switch toward us. Revenue +4% for 26 weeks.",
      effects: { revMult: 1.04 },
      weeks: 26,
    },
  ];

  var pick = pool[randInt(0, pool.length - 1)];

  var ev = {
    id: ++state.marketIntel.lastId,
    title: pick.title,
    body: pick.body,
    createdAt: now,
    weeksLeft: pick.weeks,
    effects: pick.effects,
  };
  state.marketIntel.active.push(ev);

  // Next event: again in 8–16 weeks
  state.marketIntel.nextTs = now + weeksToMs(randInt(8, 16));

  // Surface once in Inbox + a log line
  pushInbox(state, "Market event", pick.title + " — " + pick.body);
  if (logs) logs.push("Market event: " + pick.title);
}

/* =========================
   Week processor
   ========================= */

// NEW — aggregate the effects of executive directives (CFO, CPO, Head of Growth)
function getExecEffects(state) {
  var choices = state.execPolicies || {};
  var has = state.executives || {};
  var eff = {
    revenueMult: 1, // multiplies per-contract weekly revenue
    winRateMult: 1, // multiplies pipeline win chances
    satDecayMult: 1, // multiplies client satisfaction decay
    attritionDelta: 0, // +/- changes chance to SKIP attrition event
    payrollMult: 1, // multiplies payroll inside monthlyCostDetailed
    leadGenMult: 1, // multiplies lead generation chance
  };

  // CFO directives
  if (has.cfo && choices.cfo) {
    if (choices.cfo === "cost_discipline") {
      eff.payrollMult *= 0.96; // -4% payroll
      eff.attritionDelta += 0.015; // more people pressure
    } else if (choices.cfo === "revenue_push") {
      eff.winRateMult *= 1.06; // win a bit more
      eff.revenueMult *= 0.95; // at a discount
    } else if (choices.cfo === "flex_billing") {
      eff.satDecayMult *= 0.85; // happier clients (slower decay)
      eff.revenueMult *= 0.98; // small price hit
    }
  }

  // CPO directives
  if (has.cpo && choices.cpo) {
    if (choices.cpo === "people_first") {
      eff.attritionDelta -= 0.02; // fewer quits
      eff.satDecayMult *= 0.85; // service feels better
      eff.winRateMult *= 0.97; // slightly less pushy
    } else if (choices.cpo === "high_performance") {
      eff.winRateMult *= 1.03; // sharper execution
      eff.attritionDelta += 0.02; // burnout risk
      eff.satDecayMult *= 1.15; // strain shows with clients
    }
  }

  // Head of Growth directives
  if (has.hog && choices.hog) {
    if (choices.hog === "outbound_heavy") {
      eff.leadGenMult *= 1.3; // more top-of-funnel
      eff.winRateMult *= 0.95; // lower lead quality
    } else if (choices.hog === "account_expansion") {
      eff.revenueMult *= 1.07; // upsell / expansion
      eff.leadGenMult *= 0.8; // fewer net-new leads
    } else if (choices.hog === "product_marketing") {
      eff.winRateMult *= 1.04; // better targeting/messaging
      eff.leadGenMult *= 0.9; // slower volume
    }
  }

  // Merge short-lived effects coming from Inbox decisions (if any)
  var inbox = state.inboxEffects || null;
  if (inbox) {
    if (inbox.revenueMult) eff.revenueMult *= inbox.revenueMult;
    if (inbox.winRateMult) eff.winRateMult *= inbox.winRateMult;
    if (inbox.satDecayMult) eff.satDecayMult *= inbox.satDecayMult;
    if (inbox.attritionDelta) eff.attritionDelta += inbox.attritionDelta;
    if (inbox.payrollMult) eff.payrollMult *= inbox.payrollMult;
    if (inbox.leadGenMult) eff.leadGenMult *= inbox.leadGenMult;
  }

  // NEW — merge competition effects (competitor tactics + our counter-move)
  var comp = competitionEffects(state);
  if (comp.revenueMult) eff.revenueMult *= comp.revenueMult;
  if (comp.winRateMult) eff.winRateMult *= comp.winRateMult;
  if (comp.leadGenMult) eff.leadGenMult *= comp.leadGenMult;

  // Company strategy positioning. This is intentionally modest: strategy nudges the business,
  // it does not magically replace hiring, delivery quality, and cash discipline.
  var strat = strategyEffects(state);
  if (strat.revenueMult) eff.revenueMult *= strat.revenueMult;
  if (strat.winRateMult) eff.winRateMult *= strat.winRateMult;
  if (strat.leadGenMult) eff.leadGenMult *= strat.leadGenMult;
  if (strat.satDecayMult) eff.satDecayMult *= strat.satDecayMult;
  if (strat.payrollMult) eff.payrollMult *= strat.payrollMult;
  if (strat.attritionDelta) eff.attritionDelta += strat.attritionDelta;

  return eff;
}

// ========== Competition effects helper ==========
function competitionEffects(state) {
  var comp = state.competition || {};
  var tactic = comp.tactic || "price_undercut";
  var counter = comp.counter || ""; // "match" | "specialize" | "references"
  var share = typeof comp.share === "number" ? comp.share : 0.25; // 25% share default

  // Base impact from competitor tactic
  var eff = { revenueMult: 1, winRateMult: 1, leadGenMult: 1 };

  if (tactic === "price_undercut") {
    // their promo hurts our close rate and nudges pricing down
    eff.winRateMult *= 0.96;
    eff.revenueMult *= 0.98;
  } else if (tactic === "spray_and_pray") {
    // they flood the market -> more noise
    eff.leadGenMult *= 0.95;
    eff.winRateMult *= 0.99;
  } else if (tactic === "enterprise_focus") {
    // they target whales; we see a bit more SMB volume
    eff.leadGenMult *= 1.05;
    eff.winRateMult *= 1.01;
  }

  // Our counter-move (you set via Competitors tab buttons)
  if (counter === "match") {
    eff.winRateMult *= 1.04;
    eff.revenueMult *= 0.97; // we discount a bit
  } else if (counter === "specialize") {
    eff.winRateMult *= 1.03;
    eff.leadGenMult *= 0.92; // narrower ICP
  } else if (counter === "references") {
    eff.winRateMult *= 1.03; // better social proof
  }

  // scale slightly by share (25% baseline)
  var scale = Math.max(0.6, Math.min(1.6, 0.6 + share * 4));
  eff.winRateMult = Math.pow(eff.winRateMult, scale);
  eff.leadGenMult = Math.pow(eff.leadGenMult, scale);
  eff.revenueMult = Math.pow(eff.revenueMult, scale);

  return eff;
}

