function resetOrgToBlueprint(state, blueprintName) {
  ensureOrgInit(state);
  state.org.blueprint = blueprintName;
  state.org.orgUnits = getOrgBlueprintPreset(blueprintName);
  // keep CORP guaranteed
  var hasCorp = false;
  for (var i = 0; i < state.org.orgUnits.length; i++) {
    if (state.org.orgUnits[i].id === "OU_CORP") {
      hasCorp = true;
      break;
    }
  }
  if (!hasCorp)
    state.org.orgUnits.unshift({
      id: "OU_CORP",
      name: "Corporate BU",
      type: "BU",
      scope: { areas: ["General"], geos: ["Global"], clients: [] },
      policies: { pricing: "standard" },
      kpis: {},
    });

  // soft-assign employees missing orgUnitId
  var emps = getAllEmployees(state);
  for (var eIdx = 0; eIdx < emps.length; eIdx++) {
    var ee = emps[eIdx];
    if (!ee) continue;
    if (!ee.orgUnitId) ee.orgUnitId = "OU_CORP";
  }

  // no hard mutation of contracts needed; recomputeOrgPnl will route revenue
}

// ---- Utilities used by P&L

function getAllActiveContracts(state) {
  if (Array.isArray(state.contracts)) return state.contracts;
  if (Array.isArray(state.activeContracts)) return state.activeContracts;
  return [];
}
function scoreOuForContract(ou, contract) {
  if (!ou || ou.type === "SharedService") return -1;
  var s = 0;
  var area = contract && contract.area ? String(contract.area) : "";
  var geo = contract && contract.geo ? String(contract.geo) : "";
  if (ou.scope && Array.isArray(ou.scope.areas) && area) {
    if (ou.scope.areas.indexOf("All") >= 0) s += 2;
    if (ou.scope.areas.indexOf(area) >= 0) s += 3;
  }
  if (ou.scope && Array.isArray(ou.scope.geos) && geo) {
    if (ou.scope.geos.indexOf("Global") >= 0) s += 2;
    if (ou.scope.geos.indexOf(geo) >= 0) s += 3;
  }
  return s;
}
function findBestOuIdForContract(state, contract) {
  var bestId = null,
    bestScore = -9999;
  var ous =
    state.org && Array.isArray(state.org.orgUnits) ? state.org.orgUnits : [];
  for (var i = 0; i < ous.length; i++) {
    var sc = scoreOuForContract(ous[i], contract);
    if (sc > bestScore) {
      bestScore = sc;
      bestId = ous[i].id;
    }
  }
  return bestId;
}

function indexOfOu(ous, id) {
  for (var i = 0; i < ous.length; i++) if (ous[i].id === id) return i;
  return -1;
}

// Spans + centralization (safe logging hooks)
function applyOrgWeeklyEffects(state, logs) {
  ensureOrgInit(state);
  var cap =
    state.org.spanCaps && typeof state.org.spanCaps.default === "number"
      ? state.org.spanCaps.default
      : 8;
  var ous = state.org.orgUnits || [];
  for (var i = 0; i < ous.length; i++) {
    var ou = ous[i];
    if (ou.type === "SharedService") continue;
    var hc = ou.kpis && ou.kpis.headcount ? ou.kpis.headcount : 0;
    var neededManagers = Math.ceil(hc / (cap > 0 ? cap : 8));
    var existingManagers = countManagersInOu(state, ou.id);
    if (existingManagers < neededManagers && hc > 0) {
      if (logs)
        logs.push(
          "Span pressure in " +
            ou.name +
            ": need " +
            neededManagers +
            " managers, have " +
            existingManagers +
            "."
        );
    }
  }
}

function countManagersInOu(state, ouId) {
  var emps = getAllEmployees(state),
    n = 0;
  for (var i = 0; i < emps.length; i++) {
    var e = emps[i] || {};
    if ((e.orgUnitId || "OU_CORP") !== ouId) continue;
    var role = e.role ? String(e.role) : "";
    var title = e.title ? String(e.title) : "";
    var isMgr = false;
    if (role.indexOf("Manager") >= 0 || role.indexOf("Head") >= 0) isMgr = true;
    if (title.indexOf("Manager") >= 0 || title.indexOf("Head") >= 0)
      isMgr = true;
    if (e.isManager === true) isMgr = true;
    if (isMgr) n += 1;
  }
  return n;
}

// ---- Org Builder (single column) with multi-select dropdowns + merge + overseer
function OrgPage({ state, setState }) {
  ensureOrgInit(state);
  try {
    recomputeOrgPnl(state);
  } catch (_e) {}

  var ous = state.org.orgUnits || [];

  // ----- UI: selected org unit (inspector)
  var _focus = React.useState("OU_CORP");
  var focusOuId = _focus[0];
  var setFocusOuId = _focus[1];

  function getOuById(id) {
    for (var i = 0; i < ous.length; i++)
      if (ous[i] && ous[i].id === id) return ous[i];
    return null;
  }

  function updateOu(id, patch) {
    setState(function (prev) {
      var next = Object.assign({}, prev);
      ensureOrgInit(next);
      var list = next.org.orgUnits || [];
      for (var i = 0; i < list.length; i++) {
        if (list[i] && list[i].id === id) {
          list[i] = Object.assign({}, list[i], patch);
          break;
        }
      }
      next.org.orgUnits = list;
      try {
        recomputeOrgPnl(next);
      } catch (_e) {}
      return next;
    });
  }

  function toggleInArray(arr, value) {
    var a = Array.isArray(arr) ? arr.slice() : [];
    var idx = -1;
    for (var i = 0; i < a.length; i++)
      if (String(a[i]) === String(value)) {
        idx = i;
        break;
      }
    if (idx >= 0) a.splice(idx, 1);
    else a.push(value);
    return a;
  }

  function safeScope(ou) {
    var sc = ou && ou.scope ? ou.scope : {};
    return {
      areas: Array.isArray(sc.areas) ? sc.areas : [],
      geos: Array.isArray(sc.geos) ? sc.geos : [],
      clients: Array.isArray(sc.clients) ? sc.clients : [],
    };
  }

  var focusedOu =
    getOuById(focusOuId) || getOuById("OU_CORP") || ous[0] || null;
  var focusedScope = safeScope(focusedOu);

  function ouLabel(ou) {
    return (
      (ou && ou.name ? ou.name : "Unit") +
      (ou && ou.type ? " (" + ou.type + ")" : "")
    );
  }

  // groupings for the canvas
  function byType(type) {
    return ous.filter(function (ou) {
      return ou && ou.type === type;
    });
  }

  /// Prefer game's own services list (wherever you store it), else fall back
  function getServiceAreasFromGame(_state) {
    // Try common places used in this codebase
    var cand =
      (_state && _state.serviceAreas) ||
      (_state && _state.services) ||
      (_state && _state.catalog && _state.catalog.teams) ||
      (_state && _state.meta && _state.meta.serviceAreas);

    // If it looks like an object with 'name' fields, map to strings
    if (Array.isArray(cand) && cand.length && typeof cand[0] === "object") {
      cand = cand.map(function (x) {
        return x && (x.name || x.title || x.id);
      });
    }

    // Fallback set that matches your program’s teams (no “Safety”)
    var fallback = [
      "Regulatory",
      "PV",
      "Medical Affairs",
      "Quality",
      "Clinical Services",
      "Finance",
      "BD",
      "Corp",
      "HR",
      "IT",
      "Ops & Delivery",
      "Legal",
      "Customer Service",
    ];

    // Clean + dedupe
    var seen = {},
      out = [];
    var src = Array.isArray(cand) && cand.length ? cand : fallback;
    for (var i = 0; i < src.length; i++) {
      var v = String(src[i] || "").trim();
      if (!v) continue;
      if (!seen[v]) {
        seen[v] = true;
        out.push(v);
      }
    }
    return out;
  }
  // ----- options lists used by the dropdowns
  var AREA_OPTIONS = getServiceAreasFromGame(state);

  // GEO_OPTIONS: Global/regions + any unlocked countries + all GEOS keys (fallback)
  var GEO_OPTIONS = (function (_state) {
    var base = ["Global", "EMEA", "AMER", "APAC"];
    var unlocked = Array.isArray(_state.unlockedGeos)
      ? _state.unlockedGeos.slice()
      : [];
    var fromConst =
      typeof GEOS !== "undefined" && Array.isArray(GEOS)
        ? GEOS.map(function (g) {
            return g.key;
          })
        : [];
    var all = base.concat(unlocked, fromConst);

    // normalize + dedupe using canonicalGeoName
    var seen = {};
    var out = [];
    for (var i = 0; i < all.length; i++) {
      var v = canonicalGeoName(all[i]);
      if (v && !seen[v]) {
        seen[v] = true;
        out.push(v);
      }
    }
    return out;
  })(state);

  // ----- local UI state (selection + merge form)
  var _sel = React.useState({});
  var selected = _sel[0];
  var setSelected = _sel[1];

  var _mName = React.useState("New BU");
  var mergeName = _mName[0];
  var setMergeName = _mName[1];

  var _mMgr = React.useState("");
  var mergeManagerId = _mMgr[0];
  var setMergeManagerId = _mMgr[1];

  // ----- helpers
  function getEmployees() {
    var t = (state && state.team) || [];
    return Array.isArray(t) ? t : [];
  }

  function addUnit(type) {
    setState(function (s) {
      var next = Object.assign({}, s);
      ensureOrgInit(next);
      var id = "OU_" + Math.random().toString(36).slice(2, 8).toUpperCase();
      (next.org.orgUnits || (next.org.orgUnits = [])).push({
        id: id,
        name: type === "SharedService" ? "New Shared Service" : "New BU",
        type: type, // "BU" | "Division" | "SharedService"
        scope: { areas: [], geos: ["Global"], clients: [] },
        managerId: null,
        parentId: null,
        policies: {},
        kpis: {},
      });
      recomputeOrgPnl(next);
      applyLeadershipPerks(next);
      return next;
    });
  }

  function patchOu(id, patch) {
    setState(function (s) {
      var next = Object.assign({}, s);
      ensureOrgInit(next);
      next.org.orgUnits = (next.org.orgUnits || []).map(function (ou) {
        return ou.id === id ? Object.assign({}, ou, patch) : ou;
      });
      recomputeOrgPnl(next);
      applyLeadershipPerks(next);
      return next;
    });
  }

  function removeOu(id) {
    if (id === "OU_CORP") return;
    setState(function (s) {
      var next = Object.assign({}, s);
      ensureOrgInit(next);
      next.org.orgUnits = (next.org.orgUnits || []).filter(function (ou) {
        return ou.id !== id;
      });
      var emps = getEmployees();
      for (var i = 0; i < emps.length; i++) {
        if (emps[i] && emps[i].orgUnitId === id) emps[i].orgUnitId = "OU_CORP";
      }
      var cs = next.contracts || [];
      for (var j = 0; j < cs.length; j++) {
        if (cs[j] && cs[j].orgUnitId === id) cs[j].orgUnitId = "OU_CORP";
      }
      recomputeOrgPnl(next);
      applyLeadershipPerks(next);
      return next;
    });
  }

  function toggleSelect(ouId) {
    setSelected(function (old) {
      var n = Object.assign({}, old);
      n[ouId] = !n[ouId];
      return n;
    });
  }

  function union(list) {
    var seen = {};
    var out = [];
    for (var i = 0; i < list.length; i++) {
      var v = String(list[i] || "").trim();
      if (!v) continue;
      if (!seen[v]) {
        seen[v] = true;
        out.push(v);
      }
    }
    return out;
  }

  // ----- MERGE selected OUs → new BU
  function mergeSelectedToBu() {
    var ids = Object.keys(selected).filter(function (k) {
      return selected[k];
    });
    var filtered = [];
    for (var x = 0; x < ids.length; x++)
      if (ids[x] !== "OU_CORP") filtered.push(ids[x]);
    if (filtered.length < 2) return;

    setState(function (s) {
      var next = Object.assign({}, s);
      ensureOrgInit(next);
      var arr = next.org.orgUnits || [];

      // gather scopes from picked OUs
      var areas = [];
      var geos = [];
      var clients = [];
      var i, ou;
      for (i = 0; i < arr.length; i++) {
        ou = arr[i];
        if (filtered.indexOf(ou.id) < 0) continue;
        if (ou.scope && Array.isArray(ou.scope.areas))
          areas = areas.concat(ou.scope.areas);
        if (ou.scope && Array.isArray(ou.scope.geos))
          geos = geos.concat(ou.scope.geos);
        if (ou.scope && Array.isArray(ou.scope.clients))
          clients = clients.concat(ou.scope.clients);
      }
      areas = union(areas);
      geos = union(geos.length ? geos : ["Global"]);
      clients = union(clients);

      var newId = "OU_" + Math.random().toString(36).slice(2, 8).toUpperCase();
      var newOU = {
        id: newId,
        name: String(mergeName || "Merged BU"),
        type: "BU",
        scope: { areas: areas, geos: geos, clients: clients },
        managerId: mergeManagerId || null,
        parentId: null,
        policies: {},
        kpis: {},
      };
      arr.push(newOU);

      // move employees & contracts
      var emps = getEmployees();
      for (i = 0; i < emps.length; i++) {
        if (filtered.indexOf(emps[i].orgUnitId) >= 0) emps[i].orgUnitId = newId;
      }
      var cs = next.contracts || [];
      for (i = 0; i < cs.length; i++) {
        if (filtered.indexOf(cs[i].orgUnitId) >= 0) cs[i].orgUnitId = newId;
      }

      // drop originals (keep CORP)
      next.org.orgUnits = arr.filter(function (u) {
        if (u.id === "OU_CORP") return true;
        return filtered.indexOf(u.id) < 0 || u.id === newId;
      });

      setSelected({});
      recomputeOrgPnl(next);
      return next;
    });
  }

  // ----- small UI primitives
  function MultiSelect(props) {
    // props: options[], value[], onChange(array), size, placeholder
    return React.createElement(
      "select",
      {
        multiple: true,
        size: props.size || 4,
        value: props.value || [],
        onChange: function (e) {
          var out = [];
          var opts = e.target.selectedOptions || [];
          for (var i = 0; i < opts.length; i++) out.push(opts[i].value);
          if (props.onChange) props.onChange(out);
        },
        style: {
          width: "100%",
          padding: "6px 8px",
          border: "1px solid #e2e8f0",
          borderRadius: 8,
          background: "#fff",
        },
      },
      (props.options || []).map(function (opt) {
        return React.createElement("option", { key: opt, value: opt }, opt);
      })
    );
  }

  // ----- card
  function OuCard(ou) {
    var k = ou.kpis || {};
    var isSelected = !!selected[ou.id];
    var areasVal =
      ou.scope && Array.isArray(ou.scope.areas) ? ou.scope.areas : [];
    var geosVal =
      ou.scope && Array.isArray(ou.scope.geos) ? ou.scope.geos : ["Global"];

    // all employees as leader candidates
    var emps = getAllEmployees(state);

    return React.createElement(
      "div",
      {
        key: ou.id,
        style: {
          border: isSelected ? "2px solid #0ea5e9" : "1px solid #e2e8f0",
          borderRadius: 12,
          padding: 10,
          background: "#fff",
          display: "grid",
          gap: 10,
        },
      },

      // row: select (merge), name, type, LEADER, delete
      React.createElement(
        "div",
        {
          style: {
            display: "flex",
            alignItems: "center",
            gap: 8,
            flexWrap: "wrap",
          },
        },
        ou.id !== "OU_CORP"
          ? React.createElement("input", {
              type: "checkbox",
              checked: isSelected,
              onChange: function () {
                toggleSelect(ou.id);
              },
              title: "Select for merge",
            })
          : React.createElement("div", { style: { width: 14 } }),

        // name
        React.createElement("input", {
          value: ou.name || "",
          onChange: function (e) {
            patchOu(ou.id, { name: e.target.value });
          },
          style: {
            flex: 1,
            minWidth: 160,
            padding: "6px 8px",
            border: "1px solid #e2e8f0",
            borderRadius: 8,
          },
        }),

        // type
        React.createElement(
          "select",
          {
            value: ou.type,
            onChange: function (e) {
              patchOu(ou.id, { type: e.target.value });
            },
            style: {
              padding: "6px 8px",
              border: "1px solid #e2e8f0",
              borderRadius: 8,
            },
          },
          React.createElement("option", { value: "BU" }, "BU"),
          React.createElement("option", { value: "Division" }, "Division"),
          React.createElement(
            "option",
            { value: "SharedService" },
            "Shared Service"
          )
        ),

        // LEADER picker

        // delete
        ou.id !== "OU_CORP"
          ? React.createElement(
              "button",
              {
                onClick: function () {
                  removeOu(ou.id);
                },
                style: {
                  padding: "6px 8px",
                  borderRadius: 8,
                  background: "#fee2e2",
                  border: "1px solid #fecaca",
                  cursor: "pointer",
                  fontWeight: 700,
                },
              },
              "Delete"
            )
          : null
      ),

      // scope editors — dropdowns (multi-select)
      React.createElement(
        "div",
        { style: { fontSize: 12, color: "rgba(148,163,184,0.85)" } },
        "Scope: Areas"
      ),
      React.createElement(MultiSelect, {
        options: AREA_OPTIONS,
        value: areasVal,
        size: 5,
        onChange: function (arr) {
          patchOu(ou.id, {
            scope: Object.assign({}, ou.scope || {}, { areas: arr }),
          });
        },
      }),
      React.createElement(
        "div",
        { style: { fontSize: 12, color: "#64748b" } },
        "Scope: Geographies"
      ),
      React.createElement(MultiSelect, {
        options: GEO_OPTIONS,
        value: geosVal,
        size: 6,
        onChange: function (arr) {
          if (!arr || arr.length === 0) arr = ["Global"];
          patchOu(ou.id, {
            scope: Object.assign({}, ou.scope || {}, { geos: arr }),
          });
        },
      }),

      // quick KPIs + leader label
      React.createElement(
        "div",
        {
          style: {
            display: "flex",
            gap: 12,
            color: "#475569",
            fontSize: 12,
            flexWrap: "wrap",
          },
        },
        React.createElement("div", null, "HC: ", k.headcount || 0),
        React.createElement(
          "div",
          null,
          "Rev (yr): €",
          (k.revenue || 0).toLocaleString()
        ),
        React.createElement(
          "div",
          null,
          "Cost: €",
          (k.directCost || 0).toLocaleString()
        ),
        React.createElement(
          "div",
          null,
          "Alloc: €",
          (k.sscAllocated || 0).toLocaleString()
        ),
        React.createElement(
          "div",
          null,
          "Margin: €",
          (k.margin || 0).toLocaleString()
        ),
        (function () {
          var chosen = null;
          for (var i = 0; i < emps.length; i++) {
            var ep = emps[i];
            var id = ep.id || ep.email || (ep.name ? "id:" + ep.name : "");
            if (id && id === (ou.managerId || "")) {
              chosen = ep;
              break;
            }
          }
          return React.createElement(
            "div",
            { style: { color: "#64748b" } },
            "Leader: ",
            chosen
              ? chosen.name || chosen.fullName || chosen.title || "Employee"
              : "—"
          );
        })()
      )
    );
  }

  function byType(type) {
    return ous.filter(function (ou) {
      return ou.type === type;
    });
  }

  var anySelectedCount = Object.keys(selected).filter(function (k) {
    return selected[k] && k !== "OU_CORP";
  }).length;

  // ----- layout (single column; no overlap)
  // ----- UI: selected org unit (inspector)
  var _focus = React.useState("OU_CORP");
  var focusOuId = _focus[0];
  var setFocusOuId = _focus[1];

  function getOuById(id) {
    for (var i = 0; i < ous.length; i++)
      if (ous[i] && ous[i].id === id) return ous[i];
    return null;
  }

  function updateOu(id, patch) {
    setState(function (prev) {
      var next = Object.assign({}, prev);
      ensureOrgInit(next);
      var list = next.org.orgUnits || [];
      for (var i = 0; i < list.length; i++) {
        if (list[i] && list[i].id === id) {
          list[i] = Object.assign({}, list[i], patch);
          break;
        }
      }
      next.org.orgUnits = list;
      try {
        recomputeOrgPnl(next);
      } catch (_e) {}
      return next;
    });
  }

  function toggleInArray(arr, value) {
    var a = Array.isArray(arr) ? arr.slice() : [];
    var idx = -1;
    for (var i = 0; i < a.length; i++)
      if (String(a[i]) === String(value)) {
        idx = i;
        break;
      }
    if (idx >= 0) a.splice(idx, 1);
    else a.push(value);
    return a;
  }

  function safeScope(ou) {
    var sc = ou && ou.scope ? ou.scope : {};
    return {
      areas: Array.isArray(sc.areas) ? sc.areas : [],
      geos: Array.isArray(sc.geos) ? sc.geos : [],
      clients: Array.isArray(sc.clients) ? sc.clients : [],
    };
  }

  var focusedOu =
    getOuById(focusOuId) || getOuById("OU_CORP") || ous[0] || null;
  var focusedScope = safeScope(focusedOu);

  function ouLabel(ou) {
    return (
      (ou && ou.name ? ou.name : "Unit") +
      (ou && ou.type ? " (" + ou.type + ")" : "")
    );
  }

  // groupings for the canvas
  function byType(type) {
    return ous.filter(function (ou) {
      return ou && ou.type === type;
    });
  }
}

// --- Company-type random events ---
const LAW_EVENTS = [
  {
    title: "Emergency injunction hearing",
    body: "Your litigation team is pulled into court. One pipeline case takes +3 weeks but win chance +8%.",
    effect: (s) => {
      if (!s.pipeline || !s.pipeline.length) return;
      const i = rand(0, s.pipeline.length - 1);
      const p = s.pipeline[i];
      s.pipeline[i] = {
        ...p,
        minDecisionWeeks: (p.minDecisionWeeks || 0) + 3,
        winChance: clamp((p.winChance || 0) + 8, 5, 95),
      };
    },
  },
  {
    title: "Surprise deposition",
    body: "A key witness flips. One active case loses 10% satisfaction, but reputation +15 for handling it well.",
    effect: (s) => {
      if (!s.contracts || !s.contracts.length) return;
      const i = rand(0, s.contracts.length - 1);
      s.contracts[i].satisfaction = clamp(
        (s.contracts[i].satisfaction || 60) - 10,
        0,
        100
      );
      s.reputation = (s.reputation || 0) + 15;
    },
  },
  {
    title: "Settlement offer",
    body: "A client wants to settle quickly. One active case ends early (+cash now, less future revenue).",
    effect: (s) => {
      if (!s.contracts || !s.contracts.length) return;
      const i = rand(0, s.contracts.length - 1);
      const c = s.contracts[i];
      // pay 6 weeks of revenue upfront, then shorten by 8 weeks
      s.cash = (s.cash || 0) + Math.round((c.weeklyRevenue || 0) * 6);
      c.remainingWeeks = Math.max(1, (c.remainingWeeks || 1) - 8);
    },
  },
  {
    title: "Opposing counsel delay tactics",
    body: "Pipeline decisions take longer this week (-10% decision speed).",
    effect: (s) => {
      s.pipeline = (s.pipeline || []).map((p) => ({
        ...p,
        minDecisionWeeks: (p.minDecisionWeeks || 0) + 2,
      }));
    },
  },
];

function eventsForType(companyType) {
  const t = companyTypeKey(companyType);
  if (t === "law") return LAW_EVENTS;
  return EVENTS;
}

/* =========================
   PEOPLE OPS (living org simulation)
   ========================= */

// Ensure employee has the fields we simulate.
function ensurePersonRecord(e) {
  var p = e && typeof e === "object" ? Object.assign({}, e) : {};
  p.morale =
    typeof p.morale === "number" ? clamp(p.morale, 0, 100) : rand(60, 78);
  p.burnout =
    typeof p.burnout === "number" ? clamp(p.burnout, 0, 100) : rand(10, 28);
  p.trust = typeof p.trust === "number" ? clamp(p.trust, 0, 100) : rand(50, 70);
  p.managerPref =
    p.managerPref || choice(["autonomy", "structure", "coaching"]);
  p.commStyle =
    p.commStyle || choice(["direct", "diplomatic", "async", "firefighter"]);
  p.temperament =
    p.temperament || choice(["steady", "ambitious", "anxious", "chaotic"]);
  p.relationships =
    p.relationships && typeof p.relationships === "object"
      ? p.relationships
      : {};
  p.lastOneOnOneWeek =
    typeof p.lastOneOnOneWeek === "number" ? p.lastOneOnOneWeek : 0;

  p.tenureWeeks =
    typeof p.tenureWeeks === "number" ? Math.max(0, p.tenureWeeks) : 0;

  p.skill =
    typeof p.skill === "number"
      ? clamp(p.skill, 0, 100)
      : p.seniority === "Intern"
      ? rand(18, 34)
      : p.seniority === "Junior"
      ? rand(35, 52)
      : p.seniority === "Senior"
      ? rand(55, 74)
      : rand(75, 90);

  p.potential =
    typeof p.potential === "number" ? clamp(p.potential, 0, 100) : rand(45, 95); // hidden upside

  p.salaryIndex =
    typeof p.salaryIndex === "number" ? Math.max(0.5, p.salaryIndex) : 1;

  p.flightRisk =
    typeof p.flightRisk === "number" ? clamp(p.flightRisk, 0, 100) : 0;

  p.canPromote = !!p.canPromote;

  p.flags = p.flags && typeof p.flags === "object" ? p.flags : {};
  return p;
}

function nextSeniority(sen) {
  return sen === "Intern"
    ? "Junior"
    : sen === "Junior"
    ? "Senior"
    : sen === "Senior"
    ? "VP"
    : "VP";
}

function monthlySalaryForEmployee(emp) {
  var r = findRole(emp && emp.role);
  var base = r ? r.baseMonthly : 2500;
  var mult = SENIORITY_MULT[(emp && emp.seniority) || "Junior"] || 1;
  var slt = emp && emp.inSLT ? 1.25 : 1;
  var idx = typeof (emp && emp.salaryIndex) === "number" ? emp.salaryIndex : 1;
  return Math.round(base * mult * slt * idx);
}

function talentPromotionReady(emp) {
  if (!emp || emp.seniority === "VP") return false;
  var tenure = valOr(emp.tenureWeeks, 0);
  var skill = valOr(emp.skill, 0);

  if (emp.seniority === "Intern") return tenure >= 12 && skill >= 34;
  if (emp.seniority === "Junior") return tenure >= 24 && skill >= 56;
  if (emp.seniority === "Senior") return tenure >= 40 && skill >= 78;
  return false;
}

function computeFlightRisk(emp, currentManagerStyle, currentWeek) {
  if (!emp) return 0;
  var risk = 0;

  risk += Math.max(0, 55 - valOr(emp.morale, 0)) * 0.8;
  risk += Math.max(0, valOr(emp.burnout, 0) - 55) * 0.9;
  risk += Math.max(0, 50 - valOr(emp.trust, 0)) * 0.7;

  if (
    emp.managerPref &&
    currentManagerStyle &&
    emp.managerPref !== currentManagerStyle
  ) {
    risk += 10;
  }

  if (
    talentPromotionReady(emp) &&
    !(emp.retainedUntilWeek && emp.retainedUntilWeek >= currentWeek)
  ) {
    risk += 12;
  }

  if (
    valOr(emp.skill, 0) >= 75 &&
    valOr(emp.tenureWeeks, 0) >= 24 &&
    !(emp.retainedUntilWeek && emp.retainedUntilWeek >= currentWeek)
  ) {
    risk += 8;
  }

  return clamp(Math.round(risk), 0, 100);
}

function canDoCheckIn(emp, currentWeek) {
  if (!emp) return false;
  var last = valOr(emp.lastOneOnOneWeek, -999);
  return currentWeek - last >= 4;
}

function doCheckInInState(state, empId) {
  if (!state || !empId) return;
  var currentWeek = valOr(state.week, 0);
  var touched = null;

  state.team = arr(state.team).map(function (raw) {
    if (!raw || raw.id !== empId) return raw;

    var p = ensurePersonRecord(raw);
    if (!canDoCheckIn(p, currentWeek)) return p;

    var highSkill = valOr(p.skill, 0) >= 60;
    var highRisk = valOr(p.flightRisk, 0) >= 60;

    var moraleBoost = 4;
    var trustBoost = 6;
    var burnoutDrop = 3;
    var riskDrop = 6;

    if (highSkill) {
      moraleBoost += 2;
      trustBoost += 1;
      riskDrop += 2;
    }

    if (highRisk) {
      moraleBoost += 2;
      trustBoost += 2;
      burnoutDrop += 2;
      riskDrop += 6;
    }

    p.morale = clamp(valOr(p.morale, 0) + moraleBoost, 0, 100);
    p.trust = clamp(valOr(p.trust, 0) + trustBoost, 0, 100);
    p.burnout = clamp(valOr(p.burnout, 0) - burnoutDrop, 0, 100);
    p.lastOneOnOneWeek = currentWeek;

    p.flightRisk = clamp(valOr(p.flightRisk, 0) - riskDrop, 0, 100);

    p.flags = p.flags || {};
    p.flags.flightRiskNotified = p.flightRisk >= 60;

    touched = {
      name: p.name,
      role: p.role,
      moraleBoost: moraleBoost,
      trustBoost: trustBoost,
      burnoutDrop: burnoutDrop,
    };

    return p;
  });

  if (touched) {
    pushHQ(state, {
      kind: "people",
      from: "People Ops",
      title: "Manager check-in completed",
      text:
        touched.name +
        " had a manager check-in in " +
        roleLabelForType(state.companyType, touched.role) +
        ". Morale improved and retention risk eased.",
      urgency: 1,
      unread: true,
    });
  }
}

function promoteEmployeeInState(state, empId) {
  if (!state || !empId) return;
  state.team = arr(state.team).map(function (raw) {
    if (!raw || raw.id !== empId) return raw;
    var p = ensurePersonRecord(raw);
    if (!talentPromotionReady(p)) return p;

    var fromSen = p.seniority;
    var toSen = nextSeniority(fromSen);
    if (toSen === fromSen) return p;

    p.seniority = toSen;
    p.salaryIndex = Math.round(p.salaryIndex * 1.12 * 1000) / 1000;
    p.morale = clamp(p.morale + 10, 0, 100);
    p.trust = clamp(p.trust + 8, 0, 100);
    p.burnout = clamp(p.burnout - 6, 0, 100);
    p.canPromote = false;
    p.flags = p.flags || {};
    p.flags.promoReadyNotified = false;

    pushHQ(state, {
      kind: "people",
      from: "People Ops",
      title: "Promotion completed",
      text:
        p.name +
        " was promoted from " +
        fromSen +
        " to " +
        toSen +
        " in " +
        roleLabelForType(state.companyType, p.role) +
        ".",
      urgency: 1,
      unread: true,
    });

    return p;
  });
}

function runTalentProgression(state, logs) {
  state.team = arr(state.team);

  var managerStyle = state.managerStyle || "autonomy";
  var pressure = orgPressure(state);
  var promoAlerts = [];
  var flightAlerts = [];

  state.team = state.team.map(function (raw) {
    var p = ensurePersonRecord(raw);

    p.tenureWeeks = valOr(p.tenureWeeks, 0) + 1;

    var fit = p.managerPref === managerStyle;
    var growthBase =
      p.seniority === "Intern"
        ? 0.75
        : p.seniority === "Junior"
        ? 0.5
        : p.seniority === "Senior"
        ? 0.28
        : 0.12;

    var potentialBoost = (valOr(p.potential, 50) - 50) / 100;
    var fitBoost = fit ? 0.18 : -0.05;
    var pressureDrag = pressure / 260;

    var skillGain = Math.max(
      0.05,
      growthBase + potentialBoost * 0.35 + fitBoost - pressureDrag
    );

    p.skill = clamp(
      Math.round((valOr(p.skill, 0) + skillGain) * 10) / 10,
      0,
      100
    );

    if (fit) {
      p.morale = clamp(valOr(p.morale, 0) + 0.4, 0, 100);
      p.trust = clamp(valOr(p.trust, 0) + 0.35, 0, 100);
    } else {
      p.morale = clamp(valOr(p.morale, 0) - 0.35, 0, 100);
      p.trust = clamp(valOr(p.trust, 0) - 0.3, 0, 100);
      p.burnout = clamp(valOr(p.burnout, 0) + 0.35, 0, 100);
    }

    if (pressure >= 70) {
      p.burnout = clamp(valOr(p.burnout, 0) + 1, 0, 100);
      p.morale = clamp(valOr(p.morale, 0) - 0.8, 0, 100);
    }

    if (p.tenureWeeks % 13 === 0) {
      var quarterlyRaise = 0.01 + Math.max(0, valOr(p.skill, 0) - 60) / 1000;
      p.salaryIndex =
        Math.round(p.salaryIndex * (1 + quarterlyRaise) * 1000) / 1000;
    }

    p.canPromote = talentPromotionReady(p);
    p.flightRisk = computeFlightRisk(p, managerStyle, valOr(state.week, 0));

    p.flags = p.flags || {};

    if (p.canPromote && !p.flags.promoReadyNotified) {
      p.flags.promoReadyNotified = true;
      promoAlerts.push(p.name);
    }

    if (
      p.flightRisk >= 72 &&
      !(p.retainedUntilWeek && p.retainedUntilWeek >= valOr(state.week, 0)) &&
      !p.flags.flightRiskNotified
    ) {
      p.flags.flightRiskNotified = true;
      flightAlerts.push(p.name);
    }

    if (p.flightRisk < 60) {
      p.flags.flightRiskNotified = false;
    }

    return p;
  });

  if (promoAlerts.length) {
    pushHQ(state, {
      kind: "people",
      from: "People Ops",
      title: "Promotion candidate ready",
      text: promoAlerts[0] + " is ready for internal promotion.",
      urgency: 1,
      unread: true,
    });
    if (logs) logs.push("Talent: " + promoAlerts[0] + " is promotion-ready.");
  }

  if (flightAlerts.length) {
    pushHQ(state, {
      kind: "people",
      from: "People Ops",
      title: "Flight risk rising",
      text: flightAlerts[0] + " is becoming a retention risk.",
      urgency: 2,
      unread: true,
    });
    if (logs) logs.push("Retention risk: " + flightAlerts[0] + " may leave.");
  }
}

function pushHQ(state, entry) {
  state.hqFeed = arr(state.hqFeed);
  var nowTs = valOr(state.currentDate, Date.now());
  var nowWeek = valOr(state.week, 0);
  state.hqFeed.push(
    Object.assign(
      {
        id: "hq_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
        ts: nowTs,
        week: nowWeek,
        kind: "ops",
        from: "",
        title: "Update",
        text: "",
        urgency: 1,
        unread: true,
      },
      entry || {}
    )
  );
  if (state.hqFeed.length > 100) state.hqFeed = state.hqFeed.slice(-100);
}

function pushPeopleMail(state, title, body, options) {
  var nowTs = valOr(state.currentDate, Date.now());
  state.mailbox = state.mailbox || [];
  state.mailbox.push({
    id:
      "mail_people_" +
      Date.now() +
      "_" +
      Math.random().toString(36).slice(2, 7),
    from: "People Ops",
    subject: title,
    body: body || "",
    createdAt: nowTs,
    resolved: false,
    options: options || [],
  });
  if (state.mailbox.length > 120) state.mailbox = state.mailbox.slice(-120);
}

function adjustPerson(state, personId, patch) {
  if (!personId) return;
  state.team = arr(state.team);
  state.team = state.team.map(function (e) {
    if (!e || e.id !== personId) return e;
    var p = ensurePersonRecord(e);
    if (patch) {
      if (typeof patch.morale === "number")
        p.morale = clamp(p.morale + patch.morale, 0, 100);
      if (typeof patch.burnout === "number")
        p.burnout = clamp(p.burnout + patch.burnout, 0, 100);
      if (typeof patch.trust === "number")
        p.trust = clamp(p.trust + patch.trust, 0, 100);
      if (typeof patch.oneOnOneWeek === "number")
        p.lastOneOnOneWeek = patch.oneOnOneWeek;
    }
    return p;
  });
}

function orgPressure(state) {
  var teamN = Math.max(1, arr(state.team).length);
  var work =
    arr(state.contracts).length +
    Math.round(arr(state.pipeline).length * 0.4) +
    Math.round(arr(state.leadsAvailable).length * 0.1);
  var util = work / teamN; // 0..?
  var pressure = clamp(Math.round(util * 35), 0, 100);
  if (valOr(state.cash, 0) < 0) pressure = clamp(pressure + 10, 0, 100);
  if (Array.isArray(state.competitors) && state.competitors.length) {
    var heat = state.competitors.reduce(function (a, c) {
      return a + valOr(c.score, 0);
    }, 0);
    if (heat > 0) pressure = clamp(pressure + 5, 0, 100);
  }
  return pressure;
}

function peopleOpsTick(state, logs) {
  state.team = arr(state.team).map(function (e) {
    return ensurePersonRecord(e);
  });
  if (!state.team.length) return;

  var activeContracts = arr(state.contracts).length;
  var pressure = orgPressure(state); // 0..100
  var raisePct =
    typeof state.annualRaisePct === "number" ? state.annualRaisePct : 0.02;
  var raiseSignal = clamp(Math.round((raisePct - 0.02) * 100), -10, 10); // -10..10

  state.team = state.team.map(function (e) {
    var p = ensurePersonRecord(e);
    var ceoWalk =
      state.ceoActions &&
      valOr(state.ceoActions.walk, 0) === valOr(state.week, 0);
    var ceoMemo =
      state.ceoActions &&
      valOr(state.ceoActions.memo, 0) === valOr(state.week, 0);

    var bUp = Math.round(pressure / 25) + (p.temperament === "anxious" ? 1 : 0);
    var bDown =
      Math.round((p.trust - 50) / 35) + (ceoWalk ? 1 : 0) + (ceoMemo ? 1 : 0);

    var dB = bUp - bDown + rand(-1, 1);

    // If you have ZERO active contracts, burnout must never creep up.
    // People can still be "busy" with pipeline / admin, but they should recover or stay flat.
    if (activeContracts === 0) dB = Math.min(dB, 0);

    p.burnout = clamp(p.burnout + dB, 0, 100);

    var mg = state.managerStyle || "autonomy";
    var mismatch = mg !== p.managerPref ? 1 : 0;
    var mDelta =
      Math.round(raiseSignal / 1.5) -
      Math.round(p.burnout / 50) -
      mismatch +
      rand(-1, 1);
    p.morale = clamp(p.morale + mDelta, 0, 100);

    var weeksSince1on1 = Math.max(
      0,
      valOr(state.week, 0) - valOr(p.lastOneOnOneWeek, 0)
    );
    var tDelta = 0;
    if (weeksSince1on1 > 6) tDelta -= 2;
    if (weeksSince1on1 <= 2) tDelta += 1;
    if (pressure >= 70) tDelta -= 1;
    if (ceoMemo) tDelta += 1;
    p.trust = clamp(p.trust + tDelta + rand(-1, 1), 0, 100);

    return p;
  });

  if (randChance(0.65)) {
    var who = choice(state.team);
    pushHQ(state, {
      kind: "slack",
      from: who.name,
      title: "#ops",
      text:
        who.commStyle === "direct"
          ? "Need a decision today. We're blocked on a client dependency."
          : who.commStyle === "firefighter"
          ? "Fire 🔥: something changed on the client side. Can we re-scope?"
          : who.commStyle === "async"
          ? "Quick heads-up: timeline risk if we don't get an answer by Friday."
          : "FYI: team is juggling priorities — can we align on what's #1?",
      urgency: pressure >= 75 ? 2 : 1,
      unread: true,
    });
  }

  if (randChance(0.25) && valOr(state.week, 0) > 4) {
    pushHQ(state, {
      kind: "market",
      from: "Market",
      title: "Competitor noise",
      text: "A competitor is pitching aggressively in one of your geos. Expect tougher pricing conversations.",
      urgency: 1,
      unread: true,
    });
  }

  var risky = state.team
    .filter(function (e) {
      return e.burnout >= 75 || e.morale <= 35 || e.trust <= 35;
    })
    .sort(function (a, b) {
      return b.burnout - a.burnout + (a.morale - b.morale);
    });

  if (risky.length && randChance(0.35)) {
    var p = risky[0];
    var kind = choice(["quitRisk", "conflict", "quality", "promotion"]);

    if (kind === "quitRisk") {
      var title = p.name + " is close to quitting";
      var body =
        p.name +
        " is showing clear exit signals (burnout " +
        p.burnout +
        ", morale " +
        p.morale +
        ", trust " +
        p.trust +
        "). They want less chaos and a concrete plan this week.";

      pushPeopleMail(state, title, body, [
        {
          label: "Do a 1:1 + reduce workload (−2% revenue for 4 weeks)",
          apply: function (s, L) {
            adjustPerson(s, p.id, {
              morale: 8,
              burnout: -10,
              trust: 6,
              oneOnOneWeek: valOr(s.week, 0),
            });
            applyInboxEffect(s, { revenueMult: 0.98 }, 4, L);
          },
        },
        {
          label: "Offer a retention bonus (−€25k cash; +trust)",
          apply: function (s, L) {
            s.cash = valOr(s.cash, 0) - 25000;
            adjustPerson(s, p.id, {
              morale: 4,
              burnout: -4,
              trust: 10,
              oneOnOneWeek: valOr(s.week, 0),
            });
          },
        },
        {
          label: "Ignore and push (short-term output; long-term risk)",
          apply: function (s, L) {
            adjustPerson(s, p.id, { morale: -6, burnout: 6, trust: -6 });
            s.peopleQuitRisk = s.peopleQuitRisk || {};
            s.peopleQuitRisk[p.id] = 2;
          },
        },
      ]);

      pushHQ(state, {
        kind: "people",
        from: "People Ops",
        title: "Escalation: quit risk",
        text: p.name + " needs attention. This is now in your Inbox.",
        urgency: 3,
        unread: true,
      });
      if (logs) logs.push("🔥 People escalation: " + p.name + " quit risk.");
    }

    if (kind === "conflict" && state.team.length >= 2) {
      var other =
        choice(
          state.team.filter(function (x) {
            return x.id !== p.id;
          })
        ) || p;
      var title2 = "Team conflict: " + p.name + " vs " + other.name;
      var body2 =
        "They are clashing on priorities. It's starting to slow delivery (pressure " +
        pressure +
        "). Left unmanaged, it spreads.";

      pushPeopleMail(state, title2, body2, [
        {
          label: "Mediate (cost: 1 hour; improves trust)",
          apply: function (s, L) {
            adjustPerson(s, p.id, {
              trust: 6,
              morale: 2,
              burnout: -2,
              oneOnOneWeek: valOr(s.week, 0),
            });
            adjustPerson(s, other.id, {
              trust: 6,
              morale: 2,
              burnout: -1,
              oneOnOneWeek: valOr(s.week, 0),
            });
          },
        },
        {
          label: "Pick a side (fast decision; one person gets salty)",
          apply: function (s, L) {
            adjustPerson(s, p.id, { morale: 4, trust: 2 });
            adjustPerson(s, other.id, { morale: -6, trust: -6, burnout: 4 });
          },
        },
        {
          label: "Tell them to 'figure it out' (no time)",
          apply: function (s, L) {
            adjustPerson(s, p.id, { morale: -4, trust: -4, burnout: 3 });
            adjustPerson(s, other.id, { morale: -4, trust: -4, burnout: 3 });
          },
        },
      ]);

      pushHQ(state, {
        kind: "people",
        from: "People Ops",
        title: "Escalation: conflict",
        text:
          "Conflict escalated to Inbox: " + p.name + " vs " + other.name + ".",
        urgency: 2,
        unread: true,
      });
      if (logs) logs.push("⚠️ People escalation: team conflict.");
    }

    if (kind === "quality") {
      var title3 = "Quality slip on a delivery";
      var body3 =
        "A reviewer flagged inconsistencies in an output. Root cause looks like overload and context switching.";

      pushPeopleMail(state, title3, body3, [
        {
          label: "Add QA buffer (−1% revenue for 6 weeks; +quality)",
          apply: function (s, L) {
            applyInboxEffect(s, { revenueMult: 0.99 }, 6, L);
            (s.team || []).forEach(function (e) {
              e.morale = clamp(valOr(e.morale, 70) + 1, 0, 100);
              e.burnout = clamp(valOr(e.burnout, 15) - 2, 0, 100);
            });
          },
        },
        {
          label: "Push faster anyway (+1% revenue for 4 weeks; +risk)",
          apply: function (s, L) {
            applyInboxEffect(s, { revenueMult: 1.01 }, 4, L);
            (s.team || []).forEach(function (e) {
              e.burnout = clamp(valOr(e.burnout, 15) + 2, 0, 100);
            });
          },
        },
      ]);

      pushHQ(state, {
        kind: "ops",
        from: "Delivery",
        title: "Escalation: quality slip",
        text: "A quality issue landed in your Inbox.",
        urgency: 2,
        unread: true,
      });
      if (logs) logs.push("⚠️ Ops escalation: quality slip.");
    }

    if (kind === "promotion") {
      var title4 = p.name + " asks for a promotion path";
      var body4 =
        p.name +
        " wants clarity on growth. If ignored, motivation drops. If promised too much, you pay later.";

      pushPeopleMail(state, title4, body4, [
        {
          label: "Define a path + 90-day goals (+morale; +trust)",
          apply: function (s, L) {
            adjustPerson(s, p.id, {
              morale: 6,
              trust: 6,
              oneOnOneWeek: valOr(s.week, 0),
            });
          },
        },
        {
          label: "Give a title bump (sets precedent; small rep boost)",
          apply: function (s, L) {
            adjustPerson(s, p.id, { morale: 4, trust: 3 });
            s.reputation = valOr(s.reputation, 0) + 1;
          },
        },
        {
          label: "Defer (short-term focus; motivation drops)",
          apply: function (s, L) {
            adjustPerson(s, p.id, { morale: -6, trust: -4, burnout: 3 });
          },
        },
      ]);

      pushHQ(state, {
        kind: "people",
        from: "People Ops",
        title: "Escalation: promotion ask",
        text: p.name + " wants a growth path. In Inbox now.",
        urgency: 2,
        unread: true,
      });
      if (logs) logs.push("📌 People escalation: promotion ask.");
    }
  }

  if (state.peopleQuitRisk && typeof state.peopleQuitRisk === "object") {
    Object.keys(state.peopleQuitRisk).forEach(function (pid) {
      state.peopleQuitRisk[pid] = valOr(state.peopleQuitRisk[pid], 0) - 1;
      if (state.peopleQuitRisk[pid] <= 0) {
        if (randChance(0.35)) {
          var quitter = state.team.find(function (x) {
            return x.id === pid;
          });
          state.team = state.team.filter(function (x) {
            return x.id !== pid;
          });
          pushHQ(state, {
            kind: "people",
            from: "People Ops",
            title: "Resignation",
            text:
              (quitter ? quitter.name : "An employee") +
              " resigned. You lost capacity.",
            urgency: 3,
            unread: true,
          });
          state.reputation = valOr(state.reputation, 0) - 8;
        }
        delete state.peopleQuitRisk[pid];
      }
    });
  }
}

const processWeek = (state) => {
  // ====== Inbox/effects housekeeping ======
  state.mailbox = state.mailbox || [];
  if (state.inboxEffects && typeof state.inboxEffects.ttl === "number") {
    state.inboxEffects.ttl = Math.max(0, state.inboxEffects.ttl - 1);
    if (state.inboxEffects.ttl === 0) {
      state.inboxEffects = null;
    }
  }

  const logs = [];
  // People Ops (living org)
  try {
    peopleOpsTick(state, logs);
  } catch (e) {}

  // If the player switched company type but still has old leads in the pool,
  // refresh them once so the gameplay matches the selected firm.
  try {
    const ct = companyTypeKey(state.companyType);
    const allowedAreas = serviceAreasForType(ct);
    if (
      state.hasStarted &&
      Array.isArray(state.leadsAvailable) &&
      state.leadsAvailable.length &&
      state.leadsAvailable.some((l) => !allowedAreas.includes(l.area))
    ) {
      const geos =
        state.unlockedGeos && state.unlockedGeos.length
          ? state.unlockedGeos
          : START_GEOS;
      state.leadsAvailable = state.leadsAvailable.map(() =>
        makeLead(geos, state.reputation || 0, { companyType: ct })
      );
      capLeads(state);
      logs.push("Refreshed leads to match your firm type.");
    }
  } catch (e) {}
  /* --- Competition system (multi-competitor) --- */
  /* --- Competition system (multi-competitor) --- */
  if (!Array.isArray(state.competitors) || state.competitors.length === 0) {
    // Start with rivals controlling ~90% so we begin around ~10%
    state.competitors = [
      {
        id: "pharmax",
        name: "PharmaX Partners",
        style: "Aggressive poacher",
        marketShare: 40,
      },
      {
        id: "insight",
        name: "InsightReg",
        style: "Spy network",
        marketShare: 29,
      },
      {
        id: "collab",
        name: "CollabWorks",
        style: "Collaborative",
        marketShare: 20,
      },
      { id: "steady", name: "SteadyLabs", style: "Neutral", marketShare: 10 },
    ];
  }

  // Rebalance very early to ensure a low starting share on existing saves
  if ((state.week || 0) <= 1 && Array.isArray(state.competitors)) {
    var targetCompTotal = 90; // competitors should control about 90% at start
    var currentCompTotal = state.competitors.reduce(function (a, c) {
      return a + (c.marketShare || 0);
    }, 0);
    if (currentCompTotal < targetCompTotal) {
      var factor = targetCompTotal / (currentCompTotal || 1);
      state.competitors = state.competitors.map(function (c) {
        return Object.assign({}, c, {
          marketShare: clamp((c.marketShare || 0) * factor, 0, 95),
        });
      });
    }
  }

  var compNotes = [];
  // =========================
  // NEW: Expansion shock (short-term chaos)
  // =========================
  if (state.expansionShock && state.expansionShock.weeks > 0) {
    state.expansionShock.weeks--;

    // store extra cost pressure into lastMonthlyCost so UI reflects it
    // (you compute monthlyCost from lastMonthlyCost.total if available) :contentReference[oaicite:5]{index=5}
    state.lastMonthlyCost = state.lastMonthlyCost || {
      total: 0,
      breakdown: {},
    };
    var baseTotal =
      typeof state.lastMonthlyCost.total === "number"
        ? state.lastMonthlyCost.total
        : 0;

    // if base is 0, let normal systems fill it later; otherwise apply penalty
    if (baseTotal > 0) {
      state.lastMonthlyCost.total = Math.round(
        baseTotal * (1 + (state.expansionShock.costPenalty || 0))
      );
    }

    // random delay
    if (Math.random() < (state.expansionShock.delayRisk || 0)) {
      delayRandomContract(state, 1);
      logs.push(
        "Expansion shock: delivery disruption (+1 week on a contract)."
      );
    }

    if (state.expansionShock.weeks === 0) {
      state.expansionShock = null;
      logs.push("Expansion shock has faded; operations stabilizing.");
    }
  }

  // =========================
  // NEW: Utilization & overload penalties
  // =========================
  state.utilization = computeUtilization(state);

  Object.keys(state.utilization || {}).forEach(function (role) {
    var u = state.utilization[role] || 0;
    if (u > 1) {
      // Reputation hit scales with overload
      var repLoss = Math.max(1, Math.round((u - 1) * 20));
      state.reputation = Math.max(0, (state.reputation || 0) - repLoss);

      // Delay risk scales with overload (soft but meaningful)
      var pDelay = Math.min(0.6, (u - 1) * 0.25);
      if (Math.random() < pDelay) {
        delayRandomContract(state, 1);
        logs.push(
          "Overload (" +
            role +
            " @ " +
            Math.round(u * 100) +
            "%): slipped delivery (+1 week) and -" +
            repLoss +
            " reputation."
        );
      } else {
        logs.push(
          "Overload (" +
            role +
            " @ " +
            Math.round(u * 100) +
            "%): -" +
            repLoss +
            " reputation."
        );
      }
    }
  });

  // 1) Rival drift (unchanged behavior)
  state.competitors.forEach(function (c) {
    var delta = (Math.random() - 0.5) * 0.08; // slow baseline drift: -0.04..+0.04 pp

    if (c.style === "Aggressive poacher") {
      delta += 0.06;
      if (Math.random() < 0.12) {
        delta += 0.2;
        compNotes.push(c.name + " won a visible client (+0.2pp).");
      }
    } else if (c.style === "Spy network") {
      delta += 0.04;
      if (Math.random() < 0.08) {
        compNotes.push(c.name + " used intel; our sales face headwinds.");
      }
    } else if (c.style === "Collaborative") {
      delta += 0.02; // slow gainer
      if (Math.random() < 0.12) {
        delta -= 0.1; // partnership -> they share
        compNotes.push(c.name + " partnered on a case (we gain share).");
      }
    } // Neutral: no extra bias

    c.marketShare = clamp((c.marketShare || 0) + delta, 0, 85);
  });

  // 2) Compute our performance-driven target delta
  var revNow = state.monthlyRevenue || state.monthRevenue || state.revenue || 0;
  var revPrev =
    typeof state._msPrevRevenue === "number" ? state._msPrevRevenue : revNow;
  var revGrow = revPrev > 0 ? (revNow - revPrev) / revPrev : 0; // e.g., 0.10 = +10%

  var pipelineCount = Array.isArray(state.pipeline) ? state.pipeline.length : 0;
  var contractsCount = Array.isArray(state.contracts)
    ? state.contracts.length
    : 0;

  // Performance → weekly share delta (percentage points).
  // Market share should move slowly. Winning a services market takes years, not weeks.
  var ourDelta =
    revGrow * 1.2 + // -20% → -0.24pp, +20% → +0.24pp
    Math.min(pipelineCount, 20) * 0.006 + // max +0.12pp
    Math.min(contractsCount, 10) * 0.012; // max +0.12pp
  ourDelta = clamp(ourDelta, -0.35, 0.35); // hard weekly cap before smoothing

  // 3) Rebalance competitors so our share moves by ourDelta (with smoothing)
  var currentCompTotal = state.competitors.reduce(function (a, c) {
    return a + (c.marketShare || 0);
  }, 0);

  var prevOurShare =
    typeof state.ourMarketShare === "number"
      ? state.ourMarketShare
      : clamp(100 - currentCompTotal, 0, 100);

  // Smooth the move (reduces jerkiness)
  var alpha = 0.28; // slow share movement; avoid unrealistic weekly jumps
  var targetOurShare = clamp(prevOurShare + ourDelta, 0, 100);
  var smoothedOurShare = prevOurShare + (targetOurShare - prevOurShare) * alpha;

  var targetCompTotal = clamp(100 - smoothedOurShare, 0, 100);
  var scale = currentCompTotal > 0 ? targetCompTotal / currentCompTotal : 1;

  state.competitors = state.competitors.map(function (c) {
    return Object.assign({}, c, {
      marketShare: clamp((c.marketShare || 0) * scale, 0, 95),
    });
  });

  // Finalize our share
  state.ourMarketShare = clamp(
    100 -
      state.competitors.reduce(function (a, c) {
        return a + (c.marketShare || 0);
      }, 0),
    0,
    100
  );

  // Remember revenue for next week’s trend calc
  state._msPrevRevenue = revNow;

  // Normalize: our share = 100 - competitors
  var sumComp = state.competitors.reduce(function (a, c) {
    return a + (c.marketShare || 0);
  }, 0);
  state.ourMarketShare = clamp(100 - sumComp, 0, 100);

  // Log leader
  var leader = state.competitors.slice().sort(function (a, b) {
    return (b.marketShare || 0) - (a.marketShare || 0);
  })[0];
  if (leader)
    logs.push(
      "Competition updated. Leader: " +
        leader.name +
        " at " +
        leader.marketShare.toFixed(1) +
        "%."
    );

  /* --- end competition system --- */

  /* People systems (NEW): seed + weekly updates */
  state.managerStyle = state.managerStyle || "autonomy";
  (state.team || []).forEach(function (e, _, arr) {
    if (!e.managerPref)
      e.managerPref = choice(["autonomy", "structure", "coaching"]);
    if (typeof e.morale !== "number") e.morale = rand(55, 75);
    e.relationships = e.relationships || {};
    arr.forEach(function (o) {
      if (o.id !== e.id && typeof e.relationships[o.id] !== "number")
        e.relationships[o.id] = 0;
    });
  });

  // Weekly morale drift by manager style alignment
  var __style = state.managerStyle || "autonomy";
  (state.team || []).forEach(function (e) {
    var delta = 0;
    if (e.managerPref === __style) delta += 2;
    else if (e.managerPref === "coaching" || __style === "coaching") delta += 1;
    else delta -= 1;
    // Slow morale drift down ~4x (staff leaves much less often)
    delta = delta / 4;
    e.morale = clamp((e.morale || 60) + delta, 0, 100);
  });

  // Pairwise relationship drift
  var __t = state.team || [];
  for (var i = 0; i < __t.length; i++) {
    for (var j = i + 1; j < __t.length; j++) {
      var a = __t[i],
        b = __t[j];
      if (!a || !b) continue;
      var d = 0;
      if (a.role === b.role) d += 1;
      if (a.managerPref === b.managerPref) d += 1;
      d += rand(-1, 1); // small random noise
      a.relationships[b.id] = clamp((a.relationships[b.id] || 0) + d, -10, 10);
      b.relationships[a.id] = clamp((b.relationships[a.id] || 0) + d, -10, 10);
    }
  }

  // --- Low-morale attrition (much rarer; morale must be very low) ---
  if (
    !state.pendingEventModal &&
    Array.isArray(state.team) &&
    state.team.length
  ) {
    var nowWeekLM = state.week || 0;

    // Check only monthly to avoid constant churn
    if (nowWeekLM % 4 === 0) {
      var candidates = (state.team || []).filter(function (e) {
        var shielded =
          e && e.retainedUntilWeek && nowWeekLM < e.retainedUntilWeek;
        return e && !shielded && typeof e.morale === "number" && e.morale < 10;
      });

      // ~15% chance per month if someone is truly miserable
      if (candidates.length && Math.random() < 0.15) {
        candidates.sort(function (a, b) {
          return (a.morale || 0) - (b.morale || 0);
        });
        var leaver = candidates[0];

        // Unreserve them everywhere (prevents "ghost reservations")
        state.fteReserved = state.fteReserved || {};
        Object.keys(state.fteReserved).forEach(function (role) {
          state.fteReserved[role] = (state.fteReserved[role] || []).filter(
            function (empId) {
              return empId !== leaver.id;
            }
          );
        });
        if (
          state.mnaActive &&
          state.mnaActive.reserved &&
          leaver.role === "corp"
        ) {
          state.mnaActive.reserved = (state.mnaActive.reserved || []).filter(
            function (eId) {
              return eId !== leaver.id;
            }
          );
        }

        // Remove immediately
        state.team = (state.team || []).filter(function (x) {
          return x.id !== leaver.id;
        });

        // Queue attrition modal WITH ROLE (consistent with random attrition)
        state.pendingEventModal = {
          type: "attrition",
          title: "Resignation",
          employeeName: leaver.name,
          empId: leaver.id,
          empName: leaver.name,
          name: leaver.name, // renderer fallback
          role: leaver.role,
          roleLabel: roleLabelForType(state.companyType, leaver.role),
          cover: "attrition",
          reason: "morale",
          subtitle:
            leaver.name + " has left the company due to low satisfaction.",
        };

        logs.push(
          "Attrition: " +
            leaver.name +
            " (" +
            roleLabelForType(state.companyType, leaver.role) +
            ") resigned due to low satisfaction."
        );
      }
    }
  }
  // --- end low-morale attrition ---

  // Competition + Funding housekeeping
  tickCompetition(state); // random tactic drift
  checkCovenants(state); // sets state.covenantBreachQueued

  // Satisfaction decay
  /* --- Inflation bump (NEW) --- */
  var yoy =
    typeof state.annualRaisePct === "number"
      ? state.annualRaisePct
      : BASELINE_SALARY_RAISE_PCT;
  var weekly = Math.pow(1 + yoy, 1 / 52) - 1;
  state.priceLevel =
    Math.round((state.priceLevel || 1) * (1 + weekly) * 1e6) / 1e6;

  // --- Compensation policy -> employee morale (monthly) ---
  // Baseline: 2% YoY. Above baseline: morale rises each month. Below: morale falls.
  if ((state.week || 0) > 0 && state.week % 4 === 0) {
    var chosen =
      typeof state.annualRaisePct === "number"
        ? state.annualRaisePct
        : BASELINE_SALARY_RAISE_PCT;
    var diffPp = Math.round((chosen - BASELINE_SALARY_RAISE_PCT) * 100); // percentage points
    var moraleDelta = clamp(diffPp, -3, 3); // cap monthly swing
    if (moraleDelta !== 0 && Array.isArray(state.team)) {
      state.team = state.team.map(function (e) {
        if (!e || typeof e.morale !== "number") return e;
        return Object.assign({}, e, {
          morale: clamp(e.morale + moraleDelta, 0, 100),
        });
      });
      logs.push(
        "Compensation policy: employee satisfaction " +
          (moraleDelta > 0 ? "+" : "") +
          moraleDelta +
          " this month (raise " +
          Math.round(chosen * 1000) / 10 +
          "%)."
      );
    }
  }

  // --- Office environment -> people metrics (monthly) ---
  if (
    (state.week || 0) > 0 &&
    state.week % 4 === 0 &&
    Array.isArray(state.team) &&
    state.team.length
  ) {
    state.office = ensureOfficeState(state);
    var officePulse = officeStats(state);
    var officeDelta = officeMonthlyMoraleDelta(state);
    if (officeDelta !== 0) {
      state.team = state.team.map(function (e) {
        if (!e) return e;
        return Object.assign({}, e, {
          morale: clamp(valOr(e.morale, 70) + officeDelta, 0, 100),
          burnout: clamp(
            valOr(e.burnout, 20) +
              (officeDelta < 0 ? Math.abs(officeDelta) : -1),
            0,
            100
          ),
        });
      });
      logs.push(
        "Office environment: morale " +
          (officeDelta > 0 ? "+" : "") +
          officeDelta +
          " this month (capacity " +
          officePulse.headcount +
          "/" +
          officePulse.capacity +
          ")."
      );
    }
  }

  state.clientSatisfaction = state.clientSatisfaction || {};
  const activeClients = new Set(state.contracts.map((c) => c.client));
  const execEff = getExecEffects(state); // NEW
  const csEff = csEffects(state.team); // NEW
  Object.keys(state.clientSatisfaction).forEach((cli) => {
    const baseDec = activeClients.has(cli)
      ? SAT_DECAY_IF_ACTIVE
      : SAT_DECAY_PER_WEEK;
    const dec = Math.round(
      baseDec * (execEff.satDecayMult || 1) * (csEff.satDecayMult || 1)
    ); // NEW
    state.clientSatisfaction[cli] = Math.max(
      0,
      state.clientSatisfaction[cli] - dec
    );
  });
  const hr = hrEffects(state.team);
  const fin = financeEffects(state.team);

  // New Year: clear inbox & reset email templates every 12 months (4 wks/mo → 48 wks/yr)
  if ((state.week || 0) > 0 && state.week % 48 === 0) {
    state.mailbox = [];
    state.mailSentKeys = {};
    logs.push("🎉 New year: inbox cleared and email topics reset.");
  }

  maybePushTeamEmails(state, logs);
  // ========= Funding / covenant helpers =========

  // ==== Unlock tabs based on VP presence (NEW) ====
  (function () {
    var team = Array.isArray(state.team) ? state.team : [];
    function hasVP(role) {
      return team.some(function (e) {
        return (
          e &&
          (e.role === role ||
            e.role === role + " Consultant" ||
            e.role === role + " Dev") &&
          e.seniority === "VP"
        );
      });
    }
    // Finance tab unlocks with a Finance VP
    if (!state.financeUnlocked && hasVP("Finance")) {
      state.financeUnlocked = true;
    }
    // Expansion tab unlocks with Corporate Dev VP (your “Corporate VP”)
    if (
      !state.expansionUnlocked &&
      (hasVP("Corporate Dev") ||
        hasVP("Corporate Development") ||
        hasVP("Corporate"))
    ) {
      state.expansionUnlocked = true;
    }
  })();

  maybePushTeamEmails(state, logs);

  // ========== Funding / covenant helpers ==========
  function ensureFundingState(state) {
    state.funding = state.funding || { stage: "bootstrapped", covenants: null };
    return state.funding;
  }

  // Evaluate covenants and set a flag for an alert email
  function checkCovenants(state) {
    var f = ensureFundingState(state);
    state.covenantBreachQueued = false;
    if (!f.covenants) return;

    var lastCost = (state.lastMonthlyCost && state.lastMonthlyCost.total) || 0;
    var weeklyBurn = lastCost > 0 ? Math.round(lastCost / 4) : 0;
    var burnOk =
      !f.covenants.maxWeeklyBurn || weeklyBurn <= f.covenants.maxWeeklyBurn;
    var cashOk =
      !f.covenants.minCash || (state.cash || 0) >= f.covenants.minCash;

    if (!burnOk || !cashOk) {
      state.covenantBreachQueued = true;
    }
  }

  // Initialize and randomize competitor tactic sometimes
  function tickCompetition(state) {
    state.competition = state.competition || {
      share: 0.25,
      tactic: "price_undercut",
      counter: "",
    };
    if (Math.random() < 0.1) {
      var pool = ["price_undercut", "spray_and_pray", "enterprise_focus"];
      state.competition.tactic = pool[Math.floor(Math.random() * pool.length)];
    }
  }

  // --- Geographic launches progress ---
  if (state.expansionQueue.length > 0) {
    state.expansionQueue = state.expansionQueue.reduce((arr, ex) => {
      const rem = ex.weeksRemaining - 1;
      if (rem <= 0) {
        if (state.unlockedGeos.indexOf(ex.key) === -1) {
          state.unlockedGeos.push(ex.key);
          logs.push("Geographic expansion complete: " + ex.key + " unlocked.");
          // board stat
          state.boardStats.geosUnlocked =
            (state.boardStats.geosUnlocked || 0) + 1;
        }
      } else {
        arr.push({ ...ex, weeksRemaining: rem });
      }
      return arr;
    }, []);
  }

  // --- M&A progress (single-threaded) ---
  if (state.mnaActive) {
    state.mnaActive.weeksRemaining -= 1;
    if (state.mnaActive.weeksRemaining <= 0) {
      const a = normalizeAcquisitionAsset(state.mnaActive.asset);
      const riskMult =
        state.integrationRiskMult !== undefined ? state.integrationRiskMult : 1;
      const adjRisk = clamp(Math.round(a.risk * riskMult), 1, 95);
      const failed = Math.random() * 100 < adjRisk;

      if (failed) {
        const hit = Math.round(a.purchasePrice * 0.3);
        state.cash -= hit;
        logs.push(
          "M&A failed integration: -" + hit.toLocaleString() + " € penalty."
        );
      } else {
        const synergy = rand(0, a.synergyPotential);
        const revBoosted = Math.round(a.revPerWeek * (1 + synergy / 100));
        state.assetsOwned.push({
          id: id(),
          name: a.name,
          sector: a.sector,
          archetype: a.archetype,
          capability: a.capability,
          geo: a.geo,
          clientCount: a.clientCount,
          employeeCount: a.employeeCount,
          revPerWeekBoosted: revBoosted,
          ebitdaPerWeek: a.ebitdaPerWeek,
          ebitdaMultiple:
            typeof a.ebitdaMultiple === "number" ? a.ebitdaMultiple : 16,
          synergyApplied: synergy,
        });

        state.acquiredHeadcount =
          (state.acquiredHeadcount || 0) + (a.employeeCount || 0);
        state.acquiredClients =
          (state.acquiredClients || 0) + (a.clientCount || 0);
        state.acquiredCapabilities = Array.from(
          new Set(
            (state.acquiredCapabilities || []).concat([
              a.capability || a.sector || "Specialist capability",
            ])
          )
        );
        if (
          a.geo &&
          Array.isArray(state.unlockedGeos) &&
          state.unlockedGeos.indexOf(a.geo) < 0 &&
          ["CEE", "Nordics", "MENA"].indexOf(a.geo) < 0
        ) {
          state.unlockedGeos.push(a.geo);
        }

        logs.push(
          "M&A closed: " +
            a.name +
            " now contributes €" +
            revBoosted.toLocaleString() +
            "/wk."
        );
      }

      if (state.mnaActive.req && state.mnaActive.req.corp) {
        state.fteReserved = releaseForLead(state.fteReserved, {
          corp: state.mnaActive.req.corp,
        });
      }
      state.mnaActive = null;
    }
  }

  // Keep the M&A market alive. If the player buys targets or uses an older save,
  // refresh a small list of acquisition opportunities over time.
  if (!Array.isArray(state.assetsForSale)) {
    state.assetsForSale = seedAssets();
  } else if (state.assetsForSale.length < 3) {
    var existingAssetNames = new Set(
      state.assetsForSale.map(function (a) {
        return a && a.name;
      })
    );
    var refillCandidates = seedAssets().filter(function (a) {
      return !existingAssetNames.has(a.name);
    });
    while (state.assetsForSale.length < 3 && refillCandidates.length) {
      state.assetsForSale.push(refillCandidates.shift());
    }
  }

  // --- IPO progress / pricing ---
  if (state.ipo) {
    // track run-rate while prepping the book
    const rr =
      state.contracts.reduce((s, c) => s + c.weeklyRevenue, 0) +
      state.assetsOwned.reduce((s, a) => s + a.revPerWeekBoosted, 0);
    state.ipo.last8RunRates = (state.ipo.last8RunRates || [])
      .concat([rr])
      .slice(-8);

    state.ipo.weeksRemaining -= 1;

    if (state.ipo.weeksRemaining <= 0) {
      // price & size
      const postVal = valuationFromState(state, state.ipo.last8RunRates);
      const offerPct =
        IPO_CFG.OFFER_PCT[0] +
        Math.random() * (IPO_CFG.OFFER_PCT[1] - IPO_CFG.OFFER_PCT[0]); // 18–26%

      // pick a price near target and back into share count
      const price = Math.max(0.5, IPO_CFG.TARGET_PRICE + rand(-200, 200) / 100); // ± €2
      const totalShares = Math.max(1, Math.round(postVal / price));
      const floatShares = Math.max(1, Math.floor(totalShares * offerPct));
      const founderShares = Math.max(0, totalShares - floatShares);

      // cash raised (net)
      const gross = Math.round(floatShares * price);
      const net = Math.round(gross * (1 - IPO_CFG.FEES_PCT));

      // allocate the float across funds; keep the rest as "You"
      const funds = allocateIPOFloat(floatShares);
      const you = { id: id(), name: "You", shares: founderShares };
      state.shareholders = [you, ...funds];

      // go public
      state.isPublic = true;
      state.sharesOutstanding = totalShares;
      state.sharePrice = Math.round(price * 100) / 100;
      state.cash += net;

      // release IPO-reserved FTE and clear IPO
      state.fteReserved = releaseForLead(
        state.fteReserved,
        state.ipo.reserved || {}
      );
      state.ipo = null;

      // seed price history
      state.marketHistory = [{ t: state.currentDate, p: state.sharePrice }];

      logs.push(
        `IPO priced at €${state.sharePrice.toFixed(2)}; floated ${Math.round(
          offerPct * 100
        )}% (${floatShares.toLocaleString()} shs) · net +€${net.toLocaleString()}.`
      );
    }
  }

  // --- Lead generation (harder) ---

  const { genChance, winBoost } = bdEffect(state.team);
  const scaledChance = Math.min(
    genChance * 0.15 * ((execEff && execEff.leadGenMult) || 1),
    0.4
  );
  const MAX_NEW_LEADS_PER_WEEK = 2;

  let generated = 0;
  const allowedGeos = state.unlockedGeos.length
    ? state.unlockedGeos
    : START_GEOS;

  for (
    let i = 0;
    i < serviceAreasForType(state.companyType).length &&
    generated < MAX_NEW_LEADS_PER_WEEK &&
    (state.leadsAvailable || []).length < LEADS_CAP;
    i++
  ) {
    if (Math.random() < scaledChance) {
      state.leadsAvailable = Array.isArray(state.leadsAvailable)
        ? state.leadsAvailable
        : [];
      if (state.leadsAvailable.length < LEADS_CAP) {
        state.leadsAvailable.push(
          makeLead(allowedGeos, state.reputation || 0, {
            companyType: state.companyType,
          })
        );
        generated++;
      }
    }
  }

  capLeads(state);

  if (generated > 0) {
    logs.push(
      "Generated " +
        generated +
        " new lead(s) across " +
        allowedGeos.join(", ") +
        "."
    );
  }

  // --- SLT automation by BU ---
  const sltAreas = new Set(
    state.team
      .filter((t) => t.inSLT)
      .map((t) => {
        const m = sltAreaMapForType(state.companyType);
        return m ? m[t.role] : null;
      })
      .filter(Boolean)
  );
  sltAreas.forEach((area) => {
    if (Math.random() < 0.75) {
      const pick = state.leadsAvailable.find((l) => l.area === area);
      if (pick) {
        const req = scaledReqForArea(
          pick.area,
          pick.tier || "small",
          state.companyType
        );
        const free = freeByRole(state.team, state.fteReserved);
        if (canStaff(free, req)) {
          state.leadsAvailable = state.leadsAvailable.filter(
            (l) => l.id !== pick.id
          );
          state.pipeline.push(makePipelineItemGlobal(pick, req));
          state.boardStats = state.boardStats || {};
          state.boardStats.pipelineAdded =
            (state.boardStats.pipelineAdded || 0) + 1;
          state.fteReserved = reserveForLead(
            state.team,
            state.fteReserved,
            req
          );
          logs.push(
            "Automation: " +
              displayAreaName(area, state.buMap) +
              ' SLT moved "' +
              pick.name +
              '" (' +
              pick.geo +
              ") to pipeline."
          );
        }
      }
    }
  });

  // --- Pipeline progress / wins & losses ---
  const discipline = sltEffect(state.team);
  const progressBonus =
    Math.round(discipline / 5) +
    Math.round(hr.prodBoost) +
    Math.round(fin.prodBoost || 0);

  state.pipeline = state.pipeline.reduce((arr, p) => {
    const weeksInPipeline = (p.weeksInPipeline || 0) + 1;
    const minDecisionWeeks =
      typeof p.minDecisionWeeks === "number"
        ? p.minDecisionWeeks
        : pipelineMinDecisionWeeks(p.tier || "small");

    const tier = p.tier || "small";
    const baseGain =
      tier === "large"
        ? rand(4, 8)
        : tier === "medium"
        ? rand(6, 10)
        : rand(8, 14);
    const progressGain = baseGain + Math.round(progressBonus / 4);
    const progress = clamp((p.progress || 0) + progressGain, 0, 100);
    const execEff = getExecEffects(state);
    const sltGen = sltGeneralEffects(state.team || []);
    const winMult =
      (state.winRateMult !== undefined ? state.winRateMult : 1) *
      ((execEff && execEff.winRateMult) || 1) *
      ((sltGen && sltGen.winRateMult) || 1);

    const effectiveWin = clamp(
      Math.round(
        (p.winChance + winBoost + Math.round(discipline / 2)) * winMult
      ),
      5,
      95
    );

    if (progress >= 100 && weeksInPipeline < minDecisionWeeks) {
      // Deal isn't mature yet — keep it in pipeline.
      arr.push({
        ...p,
        progress: 99,
        weeksInPipeline,
        minDecisionWeeks,
      });
      return arr;
    }

    if (progress >= 100) {
      if (Math.random() * 100 < effectiveWin) {
        var bdlSigningCashPaid = isBDLLicensingDeal(p)
          ? Math.max(
              0,
              valOr(
                p.bdlTerms && p.bdlTerms.signingCashOut,
                valOr(p.bdlTerms && p.bdlTerms.upfrontPayment, 0)
              )
            )
          : 0;
        var bdlUpfrontPaid = isBDLLicensingDeal(p)
          ? Math.max(0, valOr(p.bdlTerms && p.bdlTerms.upfrontPayment, 0))
          : 0;
        var bdlLaunchPaid = isBDLLicensingDeal(p)
          ? Math.max(0, valOr(p.bdlTerms && p.bdlTerms.launchCost, 0))
          : 0;
        if (bdlSigningCashPaid > 0) state.cash -= bdlSigningCashPaid;
        state.contracts.push({
          id: id(),
          client: p.client,
          name: p.name,
          area: p.area,
          geo: p.geo,
          remainingWeeks: p.durationWeeks,
          weeklyRevenue: p.estWeeklyRevenue,
          grossWeeklyRevenue: p.grossEstWeeklyRevenue || p.estWeeklyRevenue,
          tier: p.tier || "small",
          dealType: p.dealType || null,
          bdlTerms: p.bdlTerms || null,
          originalDurationWeeks: p.originalDurationWeeks || p.durationWeeks,
          bdlMilestonesPaid: false,
        });
        bumpClientSat(state, p.client, SAT_WIN_PIPELINE);
        logs.push(
          "Won: " +
            p.name +
            " (" +
            displayAreaName(p.area, state.buMap) +
            ") — client: " +
            p.client +
            " — " +
            p.geo +
            "." +
            (bdlSigningCashPaid > 0
              ? " Signing cash paid: €" +
                Math.round(bdlSigningCashPaid).toLocaleString() +
                " (upfront €" +
                Math.round(bdlUpfrontPaid).toLocaleString() +
                (bdlLaunchPaid > 0
                  ? ", launch €" + Math.round(bdlLaunchPaid).toLocaleString()
                  : "") +
                ")."
              : "")
        );

        // Inbox notifications for renewals / cross-sells
        if (p.source === "renewal") {
          pushInbox(
            state,
            `Contract renewed — ${p.client}`,
            `You renewed an existing client.\n\nClient: ${
              p.client
            }\nArea: ${displayAreaName(
              p.area,
              state.buMap
            )}\nWeekly revenue: €${Math.round(
              p.estWeeklyRevenue
            ).toLocaleString()}/wk\nDuration: ${p.durationWeeks} weeks`
          );
          pushEventMail(
            state,
            "Sales Ops",
            "Renewal signed — " + p.client,
            opportunityEventMailBody(state, "Renewal", "signed", {
              client: p.client,
              area: p.area,
              geo: p.geo,
              contractName: p.name,
              weeklyRevenue: p.estWeeklyRevenue,
              durationWeeks: p.durationWeeks,
            })
          );
        } else if (p.source === "cross_sell" || p.source === "crosssell") {
          pushInbox(
            state,
            `Cross-sell signed — ${p.client}`,
            `You signed an additional scope with an existing client.\n\nClient: ${
              p.client
            }\nArea: ${displayAreaName(
              p.area,
              state.buMap
            )}\nWeekly revenue: €${Math.round(
              p.estWeeklyRevenue
            ).toLocaleString()}/wk\nDuration: ${p.durationWeeks} weeks`
          );
          pushEventMail(
            state,
            "Sales Ops",
            "Cross-sell signed — " + p.client,
            opportunityEventMailBody(state, "Cross-sell", "signed", {
              client: p.client,
              area: p.area,
              geo: p.geo,
              contractName: p.name,
              weeklyRevenue: p.estWeeklyRevenue,
              durationWeeks: p.durationWeeks,
            })
          );
        }

        // board stat
        state.boardStats.contractsWon =
          (state.boardStats.contractsWon || 0) + 1;
      } else {
        bumpClientSat(state, p.client, SAT_LOSS_PIPELINE);
        logs.push(
          "Lost: " +
            p.name +
            " (" +
            displayAreaName(p.area, state.buMap) +
            ") — " +
            p.geo +
            "."
        );
      }
      state.fteReserved = releaseForLead(
        state.fteReserved,
        p.req || REQUIREMENTS[p.area] || {}
      );
      return arr;
    }

    arr.push({ ...p, progress, weeksInPipeline, minDecisionWeeks });
    return arr;
  }, []);

  // --- Revenue & payroll (GM-aware) ---
  let revenue = 0;
  const revByClient = {};
  const revByGeo = {};
  const revByBU = {};
  const { revBoostByGeo, payrollCutByGeo } = getGMEffects(state.team);
  // just above the contracts.reduce revenue loop
  const diffKey =
    (state.winRateMult || 1) > 1.05
      ? "Easy"
      : (state.winRateMult || 1) < 0.9
      ? "Hard"
      : "Normal";
  const REV_MULT =
    diffKey === "Easy" ? 1.08 : diffKey === "Normal" ? 1.04 : 1.0;

  state.contracts = state.contracts.reduce((arr, c) => {
    const geoKey = (c && c.geo) || "";
    const boost = revBoostByGeo[geoKey] || 0;
    const boostedMonthly = Math.round(
      c.weeklyRevenue *
        (1 + boost) *
        REV_MULT *
        ((execEff && execEff.revenueMult) || 1)
    );

    const boostedWeekly = Math.round(boostedMonthly / 4);
    revenue += boostedWeekly;
    revByClient[c.client] = (revByClient[c.client] || 0) + boostedWeekly;
    revByGeo[c.geo] = (revByGeo[c.geo] || 0) + boostedWeekly;
    revByBU[c.area] = (revByBU[c.area] || 0) + boostedWeekly;

    var milestonePaymentDue =
      isBDLLicensingDeal(c) && !(c && c.bdlMilestonesPaid)
        ? Math.max(0, valOr(c.bdlTerms && c.bdlTerms.milestonePayment, 0))
        : 0;
    var originalDuration = Math.max(
      1,
      valOr(
        c && c.originalDurationWeeks,
        valOr(c && c.durationWeeks, valOr(c && c.remainingWeeks, 1))
      )
    );
    var shouldPayMilestone =
      milestonePaymentDue > 0 &&
      valOr(c && c.remainingWeeks, originalDuration) <=
        Math.ceil(originalDuration / 2);
    var cAfterMilestone = c;
    if (shouldPayMilestone) {
      state.cash -= milestonePaymentDue;
      cAfterMilestone = Object.assign({}, c, { bdlMilestonesPaid: true });
      logs.push(
        "BD&L milestone paid: " +
          (c.client || "client") +
          " — €" +
          Math.round(milestonePaymentDue).toLocaleString() +
          "."
      );
    }

    const rem = cAfterMilestone.remainingWeeks - 1;
    if (rem > 0) {
      arr.push({ ...cAfterMilestone, remainingWeeks: rem });
    } else {
      // Reputation bump (use the contract’s own tier; supports mega)
      const tier =
        c.tier ||
        (c.weeklyRevenue >= TIER_BANDS.large.revMin
          ? "large"
          : c.weeklyRevenue >= TIER_BANDS.medium.revMin
          ? "medium"
          : "small");

      const repGain = tier === "large" ? 15 : tier === "medium" ? 6 : 2;

      state.reputation = clamp(
        (state.reputation || 0) + repGain,
        0,
        REPUTATION_MAX
      );

      // Satisfaction bonus on successful delivery
      const t =
        c.tier ||
        (c.weeklyRevenue >= TIER_BANDS.large.revMin ? "large" : "small");
      const satBonus =
        t === "large"
          ? SAT_COMPLETE_LARGE
          : t === "medium"
          ? SAT_COMPLETE_MED
          : SAT_COMPLETE_SMALL;
      // Higher-rank delivery increases satisfaction (VP-heavy teams deliver better)
      var qAdj = qualityAdjForArea((state && state.team) || [], c.area);
      var qualityBonus = Math.round(qAdj * 60); // approx −2..+9 depending on staffing seniority
      bumpClientSat(state, c.client, satBonus + qualityBonus);

      // Renewal / cross-sell now create DIRECT contracts (no leads/pipeline)
      // and only happen if you have enough free capacity to staff them.
      var renewChance = renewChanceFor(state, c.client, c.area);
      if (Math.random() < renewChance) {
        var nextTier =
          c.tier === "small"
            ? "medium"
            : c.tier === "medium"
            ? "large"
            : "large";
        var l = makeLead(state.geosUnlocked, state.reputation, {
          client: c.client,
          forceTier: nextTier,
          companyType: state.companyType,
        });
        l.area = c.area;
        l.geo = c.geo;
        l.name = "Renewal — " + l.type;
        l.title = l.name;
        l.source = "renewal";
        l.sourceCompletedArea = c.area;

        var reqR = scaledReqForArea(l.area, l.tier, state.companyType);
        var freeR = freeByRole(state.team, state.fteReserved || {});
        if (canStaff(freeR, reqR)) {
          state.contracts.push({
            id: id(),
            client: l.client,
            name: l.name,
            area: l.area,
            geo: l.geo,
            remainingWeeks: l.durationWeeks,
            weeklyRevenue: l.estWeeklyRevenue,
            tier: l.tier,
          });
          pushInbox(
            state,
            "Contract renewed — " + c.client,
            c.client +
              " renewed after delivery (" +
              displayAreaName(c.area, state.buMap) +
              "). New contract: " +
              l.name +
              "."
          );
          pushEventMail(
            state,
            "Sales Ops",
            "Renewal signed — " + c.client,
            opportunityEventMailBody(state, "Renewal", "signed", {
              client: c.client,
              area: c.area,
              geo: c.geo,
              contractName: l.name,
              weeklyRevenue: l.estWeeklyRevenue,
              durationWeeks: l.durationWeeks,
              req: reqR,
              free: freeR,
            })
          );
        } else {
          pushInbox(
            state,
            "Renewal missed — " + c.client,
            c.client +
              " wanted to renew (" +
              displayAreaName(c.area, state.buMap) +
              "), but you didn't have enough free capacity to staff it."
          );
          pushEventMail(
            state,
            "Sales Ops",
            "Renewal missed — " + c.client,
            opportunityEventMailBody(state, "Renewal", "missed", {
              client: c.client,
              area: c.area,
              geo: c.geo,
              contractName: l.name,
              weeklyRevenue: l.estWeeklyRevenue,
              durationWeeks: l.durationWeeks,
              req: reqR,
              free: freeR,
              fix: "Hire the missing roles or free capacity before the contract ends.",
            })
          );
        }
      }

      var crossChance = crossChanceFor(state, c.client, c.area);
      if (Math.random() < crossChance) {
        var areas = serviceAreasForType(state.companyType);
        var other = (areas || []).filter(function (a) {
          return a !== c.area;
        });
        if (other.length > 0) {
          var newArea = choice(other);
          var l2 = makeLead(state.geosUnlocked, state.reputation, {
            client: c.client,
            forceTier: c.tier || pickTierSmart(state.reputation || 0),
            companyType: state.companyType,
          });
          l2.area = newArea;
          l2.geo = c.geo;
          l2.name = "Cross-sell — " + l2.type;
          l2.title = l2.name;
          l2.source = "crosssell";
          l2.sourceCompletedArea = c.area;

          var reqC = scaledReqForArea(l2.area, l2.tier, state.companyType);
          var freeC = freeByRole(state.team, state.fteReserved || {});
          if (canStaff(freeC, reqC)) {
            state.contracts.push({
              id: id(),
              client: l2.client,
              name: l2.name,
              area: l2.area,
              geo: l2.geo,
              remainingWeeks: l2.durationWeeks,
              weeklyRevenue: l2.estWeeklyRevenue,
              tier: l2.tier,
            });
            pushInbox(
              state,
              "Cross-sell signed — " + c.client,
              c.client +
                " bought an additional service (" +
                displayAreaName(newArea, state.buMap) +
                "). New contract: " +
                l2.name +
                "."
            );
            pushEventMail(
              state,
              "Sales Ops",
              "Cross-sell signed — " + c.client,
              opportunityEventMailBody(state, "Cross-sell", "signed", {
                client: c.client,
                area: newArea,
                geo: c.geo,
                contractName: l2.name,
                weeklyRevenue: l2.estWeeklyRevenue,
                durationWeeks: l2.durationWeeks,
                req: reqC,
                free: freeC,
              })
            );
          } else {
            pushInbox(
              state,
              "Cross-sell missed — " + c.client,
              c.client +
                " was ready to cross-sell into " +
                displayAreaName(newArea, state.buMap) +
                ", but you didn't have enough free capacity to staff it."
            );
            pushEventMail(
              state,
              "Sales Ops",
              "Cross-sell missed — " + c.client,
              opportunityEventMailBody(state, "Cross-sell", "missed", {
                client: c.client,
                area: newArea,
                geo: c.geo,
                contractName: l2.name,
                weeklyRevenue: l2.estWeeklyRevenue,
                durationWeeks: l2.durationWeeks,
                req: reqC,
                free: freeC,
                fix: "Hire the missing roles or free capacity before the opportunity is lost.",
              })
            );
          }
        }
      }
    }
    return arr;
  }, []);

  state.revenueByClient = revByClient;
  state.revenueByGeo = revByGeo;
  state.revenueByBU = revByBU;

  // ---- ALL-time accumulator (never resets) ----
  if (!state.revALL) state.revALL = initRevYTD(0);
  state.revALL.clientsTotal = state.revALL.clientsTotal || {};
  state.revALL.buTotal = state.revALL.buTotal || {};
  state.revALL.geoTotal = state.revALL.geoTotal || {};

  {
    const mk = monthKey(state.currentDate);
    const prevAll = state.revALL.monthly[mk] || {};
    const allRec = {
      clients: prevAll.clients || {},
      bu: prevAll.bu || {},
      geo: prevAll.geo || {},
    };

    Object.entries(revByClient).forEach(([cli, val]) => {
      allRec.clients[cli] = (allRec.clients[cli] || 0) + val;
      state.revALL.clientsTotal[cli] =
        (state.revALL.clientsTotal[cli] || 0) + val;
    });

    Object.entries(revByBU).forEach(([bu, val]) => {
      allRec.bu[bu] = (allRec.bu[bu] || 0) + val;
      state.revALL.buTotal[bu] = (state.revALL.buTotal[bu] || 0) + val;
    });

    Object.entries(revByGeo).forEach(([country, val]) => {
      allRec.geo[country] = (allRec.geo[country] || 0) + val;
      state.revALL.geoTotal[country] =
        (state.revALL.geoTotal[country] || 0) + val;
    });

    state.revALL.monthly[mk] = allRec;
  }

  // Assets revenue (sector-aware)
  const assetsBySector = state.assetsOwned.reduce((acc, a) => {
    const sec = a.sector || "Assets";
    acc[sec] = (acc[sec] || 0) + a.revPerWeekBoosted;
    return acc;
  }, {});
  const assetsRev = Object.values(assetsBySector).reduce((s, v) => s + v, 0);
  revenue += assetsRev;
  // Add assets into BU buckets
  Object.entries(assetsBySector).forEach(([sec, v]) => {
    revByBU[sec] = (revByBU[sec] || 0) + v;
  });

  // ---- YTD monthly accumulation ----
  const cur = new Date(state.currentDate);
  const yr = cur.getFullYear();

  if (!state.revYTD || state.revYTD.year !== yr) {
    state.revYTD = initRevYTD(yr);
  }
  // MIGRATION for old saves: ensure totals exist
  state.revYTD.clientsTotal = state.revYTD.clientsTotal || {};
  state.revYTD.buTotal = state.revYTD.buTotal || {};
  state.revYTD.geoTotal = state.revYTD.geoTotal || {};

  const mk = monthKey(state.currentDate);

  // ensure month buckets exist (and have geo)
  const prevMonth = state.revYTD.monthly[mk] || {};
  const monthRec = {
    clients: prevMonth.clients || {},
    bu: prevMonth.bu || {},
    geo: prevMonth.geo || {},
  };

  // Clients
  Object.entries(revByClient).forEach(([cli, val]) => {
    monthRec.clients[cli] = (monthRec.clients[cli] || 0) + val;
    state.revYTD.clientsTotal[cli] =
      (state.revYTD.clientsTotal[cli] || 0) + val;
  });

  // BUs
  Object.entries(revByBU).forEach(([bu, val]) => {
    monthRec.bu[bu] = (monthRec.bu[bu] || 0) + val;
    state.revYTD.buTotal[bu] = (state.revYTD.buTotal[bu] || 0) + val;
  });

  // Countries
  Object.entries(revByGeo).forEach(([country, val]) => {
    monthRec.geo[country] = (monthRec.geo[country] || 0) + val;
    state.revYTD.geoTotal[country] =
      (state.revYTD.geoTotal[country] || 0) + val;
  });

  state.revYTD.monthly[mk] = monthRec;

  // --- Monthly cost run (week % 4 === 0) ---
  if (state.week % 4 === 0) {
    const mc = monthlyCostDetailed(state, revByGeo, payrollCutByGeo, fin);
    state.lastMonthlyCost = mc;
    state.costYTD = valOr(state.costYTD, 0) + valOr(mc.total, 0);

    // Taxes are accrued in the P&L monthly, but paid in cash only at year-end.
    // Use the same monthly tax-line logic as the income statement.
    const taxRate = TAX_RATES[state.difficulty || "Normal"] || 0.25;
    const monthRevenueForTax = Math.round(revenue * 4);
    const monthTaxableProfit = Math.max(
      0,
      monthRevenueForTax - valOr(mc.total, 0)
    );
    const monthTaxCharge = Math.round(monthTaxableProfit * taxRate);
    state.taxAccruedYTD = valOr(state.taxAccruedYTD, 0) + monthTaxCharge;
    state.lastMonthlyTax = monthTaxCharge;
    state.lastMonthlyTaxBase = monthTaxableProfit;

    state.cash += revenue - mc.total;
  } else {
    state.cash += revenue;
  }

  // --- loans: service weekly payments (after cash update)
  if (!Array.isArray(state.loans)) state.loans = [];
  if (state.loans.length) {
    state.loans.forEach((loan) => {
      const apr = valOr(loan.apr, 0);
      const r = apr / 52;
      const balance = valOr(loan.balance, valOr(loan.amount, 0));
      const interest = Math.round(balance * r);
      const due = Math.round(valOr(loan.weeklyPayment, 0));
      const remainingWeeks = valOr(loan.remainingWeeks, valOr(loan.weeks, 0));

      // initialize missing fields for older saves
      loan.balance = balance;
      loan.remainingWeeks = remainingWeeks;

      if (due > 0 && remainingWeeks > 0) {
        if (valOr(state.cash, 0) >= due) {
          // normal payment
          state.cash = Math.round(valOr(state.cash, 0) - due);
          state.interestPaidYTD =
            valOr(state.interestPaidYTD, 0) + Math.max(0, interest);
          const principalPay = Math.max(0, due - interest);
          loan.balance = Math.max(0, loan.balance - principalPay);
          loan.remainingWeeks = loan.remainingWeeks - 1;
        } else {
          // missed payment: interest accrues + reputation hit
          loan.balance = loan.balance + interest;
          loan.missed = valOr(loan.missed, 0) + 1;
          if (typeof state.reputation === "number") {
            state.reputation = Math.max(0, state.reputation - 10);
          }
        }
      }
    });

    // clear paid/expired loans
    state.loans = state.loans.filter(
      (l) => valOr(l.balance, 0) > 0 && valOr(l.remainingWeeks, 0) > 0
    );
  }

  // --- Random events ---
  if (Math.random() < 0.2) {
    const ev = choice(eventsForType(state.companyType));
    const skipAttrition =
      ev.title === "Unexpected attrition" &&
      Math.random() <
        clamp(
          0.75 + // baseline: attrition is much rarer now
            (((hr && hr.churnReduction) || 0) -
              ((execEff && execEff.attritionDelta) || 0)),
          0,
          0.95
        );

    if (!skipAttrition) {
      ev.effect(state);
      logs.push("Event — " + ev.title + ": " + ev.body);
    }
  }

  // --- HR auto-hire (biweekly, up to 2 hires, toward targets) ---
  if (state.week % 2 === 0 && hr.autoHire > 0) {
    // 3 per HR VP, 2 per Senior, 1 per Junior, 0 per Intern
    var hrTeam = (state.team || []).filter(function (p) {
      return p && p.role === "hr";
    });
    var maxHires = hrTeam.reduce(function (sum, p) {
      var s = String(p.seniority || "").toLowerCase();
      if (s === "vp" || s === "vice president") return sum + 3;
      if (s === "senior" || s === "sr") return sum + 2;
      if (s === "junior" || s === "jr") return sum + 1;
      return sum; // interns and others add 0
    }, 0);
    var hires = 0;

    while (hires < maxHires) {
      var targets = state.hiringTargets || {};
      var byRole = countByRole(state.team);

      // recompute deficits each hire
      var deficits = ROLES.map(function (r) {
        var want = targets[r.key] || 0;
        var have = byRole[r.key] || 0;
        return { key: r.key, need: Math.max(0, want - have) };
      })
        .filter(function (d) {
          return d.need > 0;
        })
        .sort(function (a, b) {
          // HR first (it increases capacity), then biggest gaps
          if (a.key === "hr" && b.key !== "hr") return -1;
          if (b.key === "hr" && a.key !== "hr") return 1;
          return b.need - a.need;
        });

      // If there are no deficits left, stop auto-hiring now.
      if (!deficits.length) break;

      var chosenRole = deficits[0].key;

      // If we're at capacity, always attempt HR first (so capacity can grow).
      var capNow = calcCapacity(state.team);
      var atCap = (state.team || []).length >= capNow;
      if (atCap) chosenRole = "hr";

      // pick candidate
      var pick = (state.applicants || []).find(function (a) {
        return a.role === chosenRole;
      });
      if (!pick) pick = makeApplicant(chosenRole);

      var newEmp = {
        id: id(),
        name: pick.name,
        role: pick.role,
        seniority: pick.seniority,
        inSLT: pick.inSLT,
        salaryIndex: state.salaryIndexGlobal || 1,
      };

      // If at cap, only allow the HR hire if it actually increases capacity.
      if (atCap) {
        var capAfter = calcCapacity((state.team || []).concat([newEmp]));
        if (capAfter <= capNow) break;
      }

      state.team.push(newEmp);
      state.applicants = (state.applicants || []).filter(function (a) {
        return a.id !== pick.id;
      });
      state.boardStats.hires = (state.boardStats.hires || 0) + 1;

      logs.push(
        "HR SLT auto-hired: " +
          pick.name +
          " (" +
          roleLabelForType(state.companyType, pick.role) +
          " — " +
          seniorityLabelForType(state.companyType, pick.seniority) +
          ")" +
          (chosenRole
            ? " toward plan for " + ROLE_LABEL(chosenRole) + "."
            : ".")
      );

      // update counts for next loop iteration
      byRole[pick.role] = (byRole[pick.role] || 0) + 1;
      hires++;
    }
  }

  // --- Week advance & fail checks ---
  // --- Week advance (already in your code) ---
  state.week += 1;

  // keep the previous date before bumping
  const prevD = new Date(state.currentDate || GAME_START_DATE);
  const prevQuarterKey = getQuarterKey(prevD);
  const prevYear = prevD.getUTCFullYear();

  // advance calendar by 7 days (you already do this, but keep prevD first)
  {
    const d = new Date(state.currentDate || GAME_START_DATE);
    state.currentDate = Date.UTC(
      d.getUTCFullYear(),
      d.getUTCMonth(),
      d.getUTCDate() + 7
    );
  }

  const nextD = new Date(state.currentDate);
  const nextQuarterKey = getQuarterKey(nextD);
  const nextYear = nextD.getUTCFullYear();

  /* ---------- QUARTER ROLLOVER: settle previous, spawn next ---------- */
  if (nextQuarterKey !== prevQuarterKey) {
    // 1) finalize the one that just ended
    finalizeQuarter(state);

    // 2) reset per-quarter counters
    state.boardStats = {
      contractsWon: 0,
      hires: 0,
      geosUnlocked: 0,
      pipelineAdded: 0,
    };

    // 3) spawn the new objective for the NEW current date
    var weeklyRunRate =
      state.contracts.reduce(function (s, c) {
        return s + Math.round(c.weeklyRevenue / 4);
      }, 0) +
      state.assetsOwned.reduce(function (s, a) {
        return s + a.revPerWeekBoosted;
      }, 0);

    var newObj = makeQuarterObjectiveFor(
      state.currentDate,
      weeklyRunRate,
      state
    );
    state.boardCurrent = newObj;
    state.board = { current: newObj, history: state.boardHistory };

    // 4) show modal with the outcome we just finalized
    var last =
      state.boardLastOutcome ||
      (state.boardHistory.length
        ? state.boardHistory[state.boardHistory.length - 1]
        : null);

    state.pendingBoardModal = {
      current: newObj,
      previousResult: last
        ? {
            success: !!last.success,
            score: last.score || (last.success ? 100 : 0),
            rating: last.rating || (last.success ? "Achieved" : "Missed"),
            reward: last.reward || 0,
            repLoss: last.repLoss || 0,
            cashPenalty: last.cashPenalty || 0,
            objectives: last.objectives || [],
          }
        : null,
    };
  }

  /* ---------- YEAR ROLLOVER: taxes & optional dividend ---------- */
  if (nextYear !== prevYear) {
    const rate = TAX_RATES[state.difficulty || "Normal"] || 0.25;
    const revenue = Math.round(state.revenueYTD || 0);
    const cost = Math.round(valOr(state.costYTD, 0));
    const interestPaid = Math.round(valOr(state.interestPaidYTD, 0));

    // Cash tax is paid at year-end and equals the sum of monthly P&L tax charges.
    const taxableBase = Math.max(0, revenue - cost - interestPaid);
    const accruedTax = Math.max(0, Math.round(valOr(state.taxAccruedYTD, 0)));
    const amount = accruedTax;

    state.cash -= amount;
    state.taxHistory = (state.taxHistory || []).concat([
      {
        year: prevYear,
        revenue,
        cost,
        interestPaid,
        taxableBase,
        accruedTax,
        rate,
        amount,
      },
    ]);
    state.pendingTaxModal = {
      year: prevYear,
      revenue,
      cost,
      interestPaid,
      taxableBase,
      accruedTax,
      rate,
      amount,
    };

    // optional dividend for public company
    if (
      state.isPublic &&
      state.sharesOutstanding > 0 &&
      (state.dividendPerShare || 0) > 0
    ) {
      const perShare = +state.dividendPerShare || 0;
      const total = Math.round(perShare * state.sharesOutstanding);
      if (total > 0) {
        state.cash -= total;
        state.dividendHistory = (state.dividendHistory || []).concat([
          { year: prevYear, perShare, total },
        ]);
        state.pendingDividendModal = { year: prevYear, perShare, total };
      }
    }

    // === Annual salary increase ===
    const defaultRaise = BASELINE_SALARY_RAISE_PCT;
    const pct =
      typeof state.annualRaisePct === "number"
        ? state.annualRaisePct
        : defaultRaise;

    // bump everyone’s salaryIndex and the market index for new hires
    state.team = state.team.map((e) => ({
      ...e,
      salaryIndex: Math.round((e.salaryIndex || 1) * (1 + pct) * 1000) / 1000,
    }));
    state.salaryIndexGlobal =
      Math.round((state.salaryIndexGlobal || 1) * (1 + pct) * 1000) / 1000;

    // reset YTD counters for the new year
    state.revenueYTD = 0;
    state.costYTD = 0;
    state.interestPaidYTD = 0;
    state.taxAccruedYTD = 0;
    state.lastMonthlyTax = 0;
    state.lastMonthlyTaxBase = 0;
  }

  if (state.cash < 0)
    state.consecutiveNegWeeks = (state.consecutiveNegWeeks || 0) + 1;
  else state.consecutiveNegWeeks = 0;

  if (state.consecutiveNegWeeks >= 8 && !state.gameOver) {
    state.gameOver = true;
    state.gameOverReason = {
      type: "insolvency",
      title: "Insolvent — Game Over",
      body: "Cash stayed negative for 8 straight weeks. The board removed you.",
    };
    logs.push(
      "⚠️ Insolvency: Cash negative for 8 straight weeks. Restart required."
    );
  }

  // === Public market accumulation (AI buyer) ===
  if (state.isPublic && !state.gameOver && state.sharesOutstanding > 0) {
    const ev = aiAccumulationTick(state);
    if (ev && ev.length) logs.push(...ev);
  }

  // === Ownership concentration warning (>= 45%) ===
  if (
    state.isPublic &&
    !state.pendingEventModal &&
    Array.isArray(state.shareholders) &&
    state.sharesOutstanding > 0
  ) {
    for (var i = 0; i < state.shareholders.length; i++) {
      var h = state.shareholders[i];
      if (!h || h.name === "You") continue;
      var pct = (h.shares / state.sharesOutstanding) * 100;
      if (pct >= 45 && !(state.warned45 && state.warned45[h.id])) {
        state.warned45 = Object.assign({}, state.warned45, { [h.id]: true });
        state.pendingEventModal = {
          type: "ownership",
          holderName: h.name,
          pct: pct.toFixed(1),
        };
        logs.push(
          "⚠️ Ownership concentration: " +
            h.name +
            " reached " +
            pct.toFixed(1) +
            "%."
        );
        break; // only warn for one holder per week
      }
    }
  }

  // === Weekly market tick (GBM) ===
  if (state.isPublic && state.sharePrice > 0) {
    const p0 = state.sharePrice;
    const p1 = nextMarketPrice(state, p0, null);
    state.sharePrice = Math.round(p1 * 100) / 100;
    state.marketHistory = (state.marketHistory || [])
      .concat([{ t: state.currentDate, p: state.sharePrice }])
      .slice(-104);
  }

  // --- Organization pass (weekly effects & KPIs) ---
  recomputeOrgPnl(state);
  applyOrgWeeklyEffects(state, logs);
  runTalentProgression(state, logs);

  // Compute this week's base revenue first
  const baseWeeklyRevenue =
    state.contracts.reduce((s, c) => s + Math.round(c.weeklyRevenue / 4), 0) +
    state.assetsOwned.reduce((s, a) => s + a.revPerWeekBoosted, 0);

  // --- Strategic Market Events (rare, lasting) ---
  rollStrategicMarketEvent(state, logs);
  const _mods = aggregateMarketModifiers(state);

  // Apply event modifiers
  const weeklyRevenue = Math.max(
    0,
    Math.round(baseWeeklyRevenue * ((_mods && _mods.revMult) || 1))
  );

  // Apply reputation & market share drift (bounded)
  // Spread yearly deltas over weeks, and don't grant positive rep when you have no revenue/contracts yet.
  const repDeltaWeekly = Math.round(
    ((_mods && _mods.reputationDelta) || 0) / 52
  );
  if (typeof state.reputation === "number" && repDeltaWeekly !== 0) {
    const hasSignedContracts =
      (state.contracts && state.contracts.length > 0) ||
      state.contractsSigned > 0;
    const allowPositiveRep =
      repDeltaWeekly > 0 ? state.contracts && state.contracts.length > 0 : true;
    if (allowPositiveRep) {
      state.reputation = Math.max(0, state.reputation + repDeltaWeekly);
    }
  }

  const msDeltaWeekly = ((_mods && _mods.marketShareDelta) || 0) / 52;
  if (typeof state.marketShare === "number" && msDeltaWeekly !== 0) {
    state.marketShare = clamp01((state.marketShare || 0) + msDeltaWeekly);
  }
  if (typeof state.marketShare === "number") {
    state.marketShare = clamp01(
      (state.marketShare || 0) + ((_mods && _mods.marketShareDelta) || 0)
    );
  }

  // --- Footer log line ---

  const monthlyRunRate = weeklyRevenue * 4;
  const nextPayrollIn = (4 - ((state.week - 1) % 4)) % 4 || 4;

  logs.push(
    "Run-rate: €" +
      monthlyRunRate.toLocaleString() +
      "/mo · Cash: €" +
      state.cash.toLocaleString() +
      " · Next monthly cost in " +
      nextPayrollIn +
      "w"
  );

  recordTeamMetricSnapshot(state);

  return { events: logs, weeklyRevenueTotal: weeklyRevenue };
};

/* =========================
   Storage
   ========================= */
// Multi-slot save system
const SAVE_KEY_PREFIX = "clinigen_tycoon_save_";
const MAX_SAVE_SLOTS = 6; // Slot 0 = auto-save, slots 1-5 = manual saves

const getSaveMetadata = (state) => ({
  week: state.week || 0,
  cash: state.cash || 0,
  companyName: state.companyName || "Unnamed Company",
  difficulty: state.difficulty || "Normal",
  timestamp: Date.now(),
  hasStarted: state.hasStarted || false,
});

const saveToSlot = (state, slot = 0) => {
  try {
    // Save a capped copy so old runaway lead pools do not come back after reload.
    const cappedState = Object.assign({}, state || {}, {
      leadsAvailable: capLeadArray((state && state.leadsAvailable) || []),
    });
    const saveData = {
      state: cappedState,
      metadata: getSaveMetadata(cappedState),
    };
    localStorage.setItem(`${SAVE_KEY_PREFIX}${slot}`, JSON.stringify(saveData));
    return true;
  } catch (e) {
    console.error("Save failed:", e);
    return false;
  }
};

const loadFromSlot = (slot = 0) => {
  try {
    const raw = localStorage.getItem(`${SAVE_KEY_PREFIX}${slot}`);
    if (!raw) return null;
    const saveData = JSON.parse(raw);
    return saveData.state || null;
  } catch (e) {
    console.error("Load failed:", e);
    return null;
  }
};

const getSaveSlotMetadata = (slot) => {
  try {
    const raw = localStorage.getItem(`${SAVE_KEY_PREFIX}${slot}`);
    if (!raw) return null;
    const saveData = JSON.parse(raw);
    return saveData.metadata || null;
  } catch (e) {
    return null;
  }
};

const getAllSaveSlots = () => {
  const slots = [];
  for (let i = 0; i < MAX_SAVE_SLOTS; i++) {
    const metadata = getSaveSlotMetadata(i);
    slots.push({
      slot: i,
      exists: !!metadata,
      metadata: metadata,
      isAutoSave: i === 0,
    });
  }
  return slots;
};

const deleteSaveSlot = (slot) => {
  if (slot === 0) return false; // Don't delete auto-save
  try {
    localStorage.removeItem(`${SAVE_KEY_PREFIX}${slot}`);
    return true;
  } catch (e) {
    return false;
  }
};

// Backward compatibility - auto-save to slot 0
const save = (state) => saveToSlot(state, 0);

// Backward compatibility - load from auto-save
const load = () => {
  // Try new multi-slot system first
  const newSave = loadFromSlot(0);
  if (newSave) return newSave;

  // Fall back to old save key
  const raw = localStorage.getItem(
    "clinigen_tycoon_monthly_geo_v2_board_hr_dates"
  );
  if (!raw) return null;
  try {
    const oldState = JSON.parse(raw);
    // Migrate old save to new slot 0
    if (oldState) {
      saveToSlot(oldState, 0);
      localStorage.removeItem("clinigen_tycoon_monthly_geo_v2_board_hr_dates");
    }
    return oldState;
  } catch (e) {
    return null;
  }
};

const migrateState = (s) => {
  if (!s || typeof s !== "object") return s;

  // Company type (menu added later; old saves won't have it)
  if (!s.companyType) s.companyType = "biotech";
  s.companyType = companyTypeKey(s.companyType);
  s.office = ensureOfficeState(s);

  // Board / objectives 2.0 migration.
  s.board = s.board || {};
  s.boardHistory = Array.isArray(s.boardHistory)
    ? s.boardHistory
    : Array.isArray(s.board.history)
    ? s.board.history
    : [];
  s.boardStats = Object.assign(
    { contractsWon: 0, hires: 0, geosUnlocked: 0, pipelineAdded: 0 },
    s.boardStats || {}
  );
  var existingBoard =
    s.boardCurrent || s.board.current || s.board.currentObjective;
  if (!existingBoard || !Array.isArray(existingBoard.objectives)) {
    existingBoard = makeQuarterObjectiveFor(
      s.currentDate || GAME_START_DATE,
      Math.round(boardMonthlyRevenue(s) / 4),
      s
    );
  }
  s.boardCurrent = existingBoard;
  s.board = { current: existingBoard, history: s.boardHistory };
  if (typeof s.boardPressure !== "number") s.boardPressure = 70;
  // --- add-on: loans
  if (!Array.isArray(s.loans)) s.loans = [];
  if (typeof s._loanLastId !== "number") s._loanLastId = 0; // HQ / People Ops (safe defaults for older saves)
  s.hqFeed = arr(s.hqFeed);
  s.hqFeedSeenAt = typeof s.hqFeedSeenAt === "number" ? s.hqFeedSeenAt : 0;
  s.ceoActions = s.ceoActions || { walk: 0, memo: 0 };
  s.peopleQuitRisk =
    s.peopleQuitRisk && typeof s.peopleQuitRisk === "object"
      ? s.peopleQuitRisk
      : {};
  s.team = arr(s.team).map(function (e) {
    return ensurePersonRecord(e);
  });

  // Migration safety: old saves may have accumulated hundreds of active leads.
  // Trim once on load so the UI stays responsive immediately.
  capLeads(s);

  return s;
};

