function GMRow({ emp, state, setState, toggleSLT, fire }) {
  const scope = emp.gmScope || "geo";
  const target =
    emp.gmTarget ||
    (scope === "geo" ? state.unlockedGeos[0] || "" : REGIONS[0] || "");

  const setGM = (next) =>
    setState((s) => ({
      ...s,
      team: s.team.map((e) => (e.id === emp.id ? { ...e, ...next } : e)),
    }));

  // --- salary calc (monthly) for GM row ---
  var __gmRole = findRole(emp.role) || {};
  var __gmBaseMonthly =
    typeof __gmRole.baseMonthly === "number" ? __gmRole.baseMonthly : 2500;
  var __gmMult = (SENIORITY_MULT[emp.seniority] || 1) * (emp.inSLT ? 1.25 : 1);
  var __gmIdx = typeof emp.salaryIndex === "number" ? emp.salaryIndex : 1;
  var __gmMonthly = Math.round(
    __gmBaseMonthly * __gmMult * __gmIdx * (state.priceLevel || 1)
  ); // NEW

  return (
    <div style={styles.gmCard}>
      {/* TOP ROW */}
      <div style={styles.gmTopRow}>
        <div style={{ minWidth: 0, paddingRight: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={styles.personAvatarSm}>
              {(emp && emp.avatar) || "👤"}
            </div>
            <div style={styles.gmName}>
              {emp.name}{" "}
              {emp.inSLT ? <span style={styles.sltPill}>SLT</span> : null}
            </div>
          </div>
          <div style={styles.meta}>
            {emp.seniority} {" · €"}
            {__gmMonthly.toLocaleString()}/mo
          </div>
        </div>

        <button onClick={() => toggleSLT(emp.id)} style={styles.btnGhostSmall}>
          {emp.inSLT ? "Un-SLT" : "SLT"}
        </button>
      </div>

      {/* BOTTOM ROW */}
      <div style={styles.gmBottomRow}>
        <select
          value={scope}
          onChange={(e) => {
            const nextScope = e.target.value;
            const nextTarget =
              nextScope === "geo"
                ? state.unlockedGeos[0] || ""
                : REGIONS[0] || "";
            setGM({ gmScope: nextScope, gmTarget: nextTarget });
          }}
          style={{ ...styles.select, minWidth: 0 }}
        >
          <option value="geo" style={{ color: "#111827", background: "#fff" }}>
            Country
          </option>
          <option
            value="region"
            style={{ color: "#111827", background: "#fff" }}
          >
            Region
          </option>
        </select>

        {scope === "geo" ? (
          <select
            value={target}
            onChange={(e) => setGM({ gmTarget: e.target.value })}
            style={{ ...styles.select, minWidth: 0 }}
          >
            {state.unlockedGeos.map((g) => (
              <option key={g} value={g}>
                {g}
              </option>
            ))}
          </select>
        ) : (
          <select
            value={target}
            onChange={(e) => setGM({ gmTarget: e.target.value })}
            style={{ ...styles.select, minWidth: 0 }}
          >
            {REGIONS.map((r) => (
              <option key={r} value={r}>
                {r}
              </option>
            ))}
          </select>
        )}

        <button
          onClick={() => fire(emp.id)}
          style={{
            ...styles.btnDangerRight,
            gridColumn: "1 / -1",
            justifySelf: "end",
          }}
        >
          Fire
        </button>
      </div>
    </div>
  );
}

