function tutorialLangValue(step, key, language) {
  if (!step) return "";
  if (language === "fr") {
    if (key === "title" && step.frTitle) return step.frTitle;
    if (key === "summary" && step.frSummary) return step.frSummary;
    if (key === "detail" && step.frDetail) return step.frDetail;
    if (key === "body" && step.frBody) return step.frBody;
    if (key === "loop" && step.frLoop) return step.frLoop;
    if (key === "guide" && step.frGuide) return step.frGuide;
  }
  return step[key];
}

function tutorialCategoryMeta(id) {
  return (
    GAME_TUTORIAL_CATEGORIES.find(function (c) {
      return c.id === id;
    }) || GAME_TUTORIAL_CATEGORIES[0]
  );
}

function tutorialCategoryLabel(id, language) {
  var meta = tutorialCategoryMeta(id);
  return language === "fr" ? meta.frLabel || meta.label : meta.label;
}

