  function financeRowsForecast() {
    return [1, 2, 3, 4, 5, 6].map(function (m) {
      var ramp = Math.min(1, m / 6);
      var rev = Math.round(
        monthlyRevenue * Math.pow(1.015, m) +
          pipelineExpectedMonthly * 0.55 * ramp
      );
      var cost = Math.round(
        monthlyCost * Math.pow(1.012, m) +
          Math.max(0, rev - monthlyRevenue) * 0.12
      );
      var profit = rev - cost;
      return financeLine(
        "forecast_m" + m,
        "Forecast",
        "Month +" + m,
        profit,
        null,
        null,
        rev,
        "This row estimates next-period profit using current run-rate, conservative pipeline conversion, and modest cost growth. It is a planning view, not a guarantee.",
        "Forecast Revenue = current revenue growth + weighted pipeline ramp. Forecast Profit = Forecast Revenue − Forecast Cost.",
        [
          ["Forecast revenue", euro(rev)],
          ["Forecast cost", euro(cost)],
          ["Forecast profit", euro(profit)],
          [
            "Pipeline contribution",
            euro(Math.round(pipelineExpectedMonthly * 0.55 * ramp)),
          ],
        ]
      );
    });
  }
