                  var s = JSON.parse(JSON.stringify(prev || {}));
                  s.loans = arrSafe(s.loans);
                  var idx = s.loans.findIndex(function (x) {
                    return (x.id || x._id) === key;
                  });
                  if (idx < 0) return prev;
                  s.loans[idx].balance = Math.max(
                    0,
                    safeNum(s.loans[idx].balance, s.loans[idx].amount) -
                      repayAmt
                  );
                  s.cash = Math.max(0, safeNum(s.cash) - repayAmt);
                  if (s.loans[idx].balance <= 0) s.loans.splice(idx, 1);
                  return s;
