/* ---------- SAVES PAGE ---------- */
function SavesPage({ state, setState, setTab }) {
  const [selectedSlot, setSelectedSlot] = React.useState(null);
  const [saveSlots, setSaveSlots] = React.useState(getAllSaveSlots());
  const [showConfirm, setShowConfirm] = React.useState(null);

  const refreshSlots = () => {
    setSaveSlots(getAllSaveSlots());
  };

  const handleSave = (slot) => {
    if (saveToSlot(state, slot)) {
      refreshSlots();
      alert(`Game saved to slot ${slot}!`);
    } else {
      alert("Save failed!");
    }
  };

  const handleLoad = (slot) => {
    const loadedState = loadFromSlot(slot);
    if (loadedState) {
      setState(migrateState(loadedState));
      alert(`Game loaded from slot ${slot}!`);
      setTab("hq");
    } else {
      alert("Load failed!");
    }
  };

  const handleDelete = (slot) => {
    if (deleteSaveSlot(slot)) {
      refreshSlots();
      setShowConfirm(null);
      alert(`Save slot ${slot} deleted!`);
    } else {
      alert("Delete failed!");
    }
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return "Never";
    const date = new Date(timestamp);
    return date.toLocaleString();
  };

  const formatCash = (cash) => {
    if (cash >= 1000000) return `€${(cash / 1000000).toFixed(1)}M`;
    if (cash >= 1000) return `€${(cash / 1000).toFixed(0)}k`;
    return `€${cash}`;
  };

  return React.createElement(
    "div",
    { style: { maxWidth: 900, margin: "0 auto", padding: "0 16px" } },
    React.createElement(
      "div",
      { style: { marginBottom: 24 } },
      React.createElement(
        "h2",
        { style: { fontSize: 24, fontWeight: 900, marginBottom: 8 } },
        "Save & Load Game"
      ),
      React.createElement(
        "p",
        { style: { fontSize: 14, color: "#94a3b8" } },
        "Manage your save slots. Slot 0 is auto-save (saved every change)."
      )
    ),
    React.createElement(
      "div",
      { style: { display: "grid", gap: 12 } },
      saveSlots.map((slot) =>
        React.createElement(
          "div",
          {
            key: slot.slot,
            style: {
              background: "#fff",
              border: slot.isAutoSave
                ? "2px solid #3b82f6"
                : "1px solid #e5e7eb",
              borderRadius: 12,
              padding: 16,
              display: "grid",
              gridTemplateColumns: "1fr auto",
              gap: 12,
              alignItems: "center",
            },
          },
          React.createElement(
            "div",
            null,
            React.createElement(
              "div",
              {
                style: {
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  marginBottom: 6,
                },
              },
              React.createElement(
                "span",
                { style: { fontSize: 16, fontWeight: 900, color: "#0f172a" } },
                slot.isAutoSave ? "Auto-Save" : `Save Slot ${slot.slot}`
              ),
              slot.isAutoSave &&
                React.createElement(
                  "span",
                  {
                    style: {
                      fontSize: 11,
                      padding: "2px 8px",
                      background: "#dbeafe",
                      color: "#1e40af",
                      borderRadius: 999,
                      fontWeight: 700,
                    },
                  },
                  "CURRENT"
                )
            ),
            slot.exists
              ? React.createElement(
                  "div",
                  {
                    style: {
                      display: "grid",
                      gridTemplateColumns: "repeat(4, 1fr)",
                      gap: 12,
                      fontSize: 13,
                    },
                  },
                  React.createElement(
                    "div",
                    null,
                    React.createElement(
                      "div",
                      { style: { color: "#64748b", fontSize: 11 } },
                      "Company"
                    ),
                    React.createElement(
                      "div",
                      { style: { fontWeight: 700 } },
                      slot.metadata.companyName || "Unnamed"
                    )
                  ),
                  React.createElement(
                    "div",
                    null,
                    React.createElement(
                      "div",
                      { style: { color: "#64748b", fontSize: 11 } },
                      "Week"
                    ),
                    React.createElement(
                      "div",
                      { style: { fontWeight: 700 } },
                      slot.metadata.week || 0
                    )
                  ),
                  React.createElement(
                    "div",
                    null,
                    React.createElement(
                      "div",
                      { style: { color: "#64748b", fontSize: 11 } },
                      "Cash"
                    ),
                    React.createElement(
                      "div",
                      { style: { fontWeight: 700 } },
                      formatCash(slot.metadata.cash || 0)
                    )
                  ),
                  React.createElement(
                    "div",
                    null,
                    React.createElement(
                      "div",
                      { style: { color: "#64748b", fontSize: 11 } },
                      "Difficulty"
                    ),
                    React.createElement(
                      "div",
                      { style: { fontWeight: 700 } },
                      slot.metadata.difficulty || "Normal"
                    )
                  )
                )
              : React.createElement(
                  "div",
                  {
                    style: {
                      color: "#94a3b8",
                      fontSize: 13,
                      fontStyle: "italic",
                    },
                  },
                  "Empty slot"
                ),
            slot.exists &&
              React.createElement(
                "div",
                { style: { fontSize: 12, color: "#64748b", marginTop: 6 } },
                "Last saved: ",
                formatDate(slot.metadata.timestamp)
              )
          ),
          React.createElement(
            "div",
            { style: { display: "flex", flexDirection: "column", gap: 6 } },
            !slot.isAutoSave &&
              React.createElement(
                "button",
                {
                  onClick: () => handleSave(slot.slot),
                  style: {
                    padding: "8px 16px",
                    borderRadius: 8,
                    border: "1px solid #cbd5e1",
                    background: "#f1f5f9",
                    color: "#0f172a",
                    fontWeight: 700,
                    fontSize: 13,
                    cursor: "pointer",
                  },
                },
                slot.exists ? "Overwrite" : "Save Here"
              ),
            slot.exists &&
              React.createElement(
                "button",
                {
                  onClick: () => handleLoad(slot.slot),
                  style: {
                    padding: "8px 16px",
                    borderRadius: 8,
                    border: "1px solid #3b82f6",
                    background: "#3b82f6",
                    color: "#fff",
                    fontWeight: 700,
                    fontSize: 13,
                    cursor: "pointer",
                  },
                },
                "Load"
              ),
            slot.exists &&
              !slot.isAutoSave &&
              React.createElement(
                "button",
                {
                  onClick: () => setShowConfirm(slot.slot),
                  style: {
                    padding: "8px 16px",
                    borderRadius: 8,
                    border: "1px solid #ef4444",
                    background: "#fff",
                    color: "#ef4444",
                    fontWeight: 700,
                    fontSize: 13,
                    cursor: "pointer",
                  },
                },
                "Delete"
              )
          )
        )
      )
    ),
    showConfirm !== null &&
      React.createElement(
        "div",
        {
          style: {
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.5)",
            display: "grid",
            placeItems: "center",
            zIndex: 9999,
          },
          onClick: () => setShowConfirm(null),
        },
        React.createElement(
          "div",
          {
            style: {
              background: "#fff",
              borderRadius: 16,
              padding: 24,
              maxWidth: 400,
              textAlign: "center",
            },
            onClick: (e) => e.stopPropagation(),
          },
          React.createElement(
            "h3",
            { style: { fontSize: 18, fontWeight: 900, marginBottom: 12 } },
            "Delete Save?"
          ),
          React.createElement(
            "p",
            { style: { fontSize: 14, color: "#64748b", marginBottom: 20 } },
            `Are you sure you want to delete save slot ${showConfirm}? This cannot be undone.`
          ),
          React.createElement(
            "div",
            { style: { display: "flex", gap: 12, justifyContent: "center" } },
            React.createElement(
              "button",
              {
                onClick: () => setShowConfirm(null),
                style: {
                  padding: "10px 20px",
                  borderRadius: 8,
                  border: "1px solid #cbd5e1",
                  background: "#f1f5f9",
                  color: "#0f172a",
                  fontWeight: 700,
                  cursor: "pointer",
                },
              },
              "Cancel"
            ),
            React.createElement(
              "button",
              {
                onClick: () => handleDelete(showConfirm),
                style: {
                  padding: "10px 20px",
                  borderRadius: 8,
                  border: "1px solid #ef4444",
                  background: "#ef4444",
                  color: "#fff",
                  fontWeight: 700,
                  cursor: "pointer",
                },
              },
              "Delete"
            )
          )
        )
      )
  );
}

