function translateDynamicFrenchPhrases(core) {
  var out = String(core || "");

  // Idempotent pluralisation. The old replacement could repeatedly append "(s)"
  // because the MutationObserver re-runs after every render. These replacements
  // consume any previously duplicated suffixes and output a stable French phrase.
  out = out.replace(/(\d+)\s+lead\(s\)\s+visible(?:\(s\))*/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "lead visible" : "leads visibles");
  });
  out = out.replace(/(\d+)\s+new lead\(s\)/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "nouveau lead" : "nouveaux leads");
  });
  out = out.replace(/(\d+)\s+lead\(s\) to pipeline/g, function (_, n) {
    return (
      n +
      " " +
      (Number(n) === 1
        ? "lead ajouté au pipeline"
        : "leads ajoutés au pipeline")
    );
  });
  out = out.replace(/(\d+)\s+candidate\(s\)/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "candidat" : "candidats");
  });
  out = out.replace(/(\d+)\s+decision option\(s\)/g, function (_, n) {
    return (
      n + " " + (Number(n) === 1 ? "option de décision" : "options de décision")
    );
  });
  out = out.replace(/(\d+)\s+decision thread\(s\)/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "fil de décision" : "fils de décision");
  });
  out = out.replace(/(\d+)\s+future gap\(s\)/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "gap futur" : "gaps futurs");
  });
  out = out.replace(/(\d+)\s+active loan\(s\)/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "prêt actif" : "prêts actifs");
  });
  out = out.replace(/(\d+)\s+week\(s\) remaining/g, function (_, n) {
    return (
      n + " " + (Number(n) === 1 ? "semaine restante" : "semaines restantes")
    );
  });
  out = out.replace(/(\d+)\s+active market\(s\)/g, function (_, n) {
    return n + " " + (Number(n) === 1 ? "marché actif" : "marchés actifs");
  });

  // Defensive cleanup for already-mutated DOM text: "(s)(s)(s)" -> "(s)".
  out = out.replace(/(\(s\))(?:\1)+/g, "$1");
  return out;
}

function translateGameTextToFrench(raw) {
  if (raw == null) return raw;
  var text = String(raw);
  if (!text.trim()) return text;
  var leading = text.match(/^\s*/)[0];
  var trailing = text.match(/\s*$/)[0];
  var core = text.trim();
  var exact = FR_EXACT[core];
  if (exact) return leading + exact + trailing;
  var out = translateDynamicFrenchPhrases(core);
  FR_REPLACEMENTS.forEach(function (pair) {
    out = out.replace(pair[0], pair[1]);
  });
  out = translateDynamicFrenchPhrases(out);
  return leading + out + trailing;
}

function applyFrenchGameTranslations(root) {
  if (typeof document === "undefined" || typeof window === "undefined") return;
  root = root || document.body;
  if (!root) return;
  var rejectTags = {
    SCRIPT: true,
    STYLE: true,
    NOSCRIPT: true,
    TEXTAREA: true,
    INPUT: true,
  };
  var walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode: function (node) {
      if (!node || !node.nodeValue || !node.nodeValue.trim())
        return NodeFilter.FILTER_REJECT;
      var p = node.parentElement;
      if (!p || rejectTags[p.tagName]) return NodeFilter.FILTER_REJECT;
      if (p.closest && p.closest("[data-no-i18n]"))
        return NodeFilter.FILTER_REJECT;
      return NodeFilter.FILTER_ACCEPT;
    },
  });
  var nodes = [];
  var n;
  while ((n = walker.nextNode())) nodes.push(n);
  nodes.forEach(function (node) {
    var next = translateGameTextToFrench(node.nodeValue);
    if (next !== node.nodeValue) node.nodeValue = next;
  });
  Array.prototype.forEach.call(
    document.querySelectorAll("input[placeholder], textarea[placeholder]"),
    function (el) {
      var p = el.getAttribute("placeholder");
      var next = translateGameTextToFrench(p);
      if (next !== p) el.setAttribute("placeholder", next);
    }
  );
  Array.prototype.forEach.call(
    document.querySelectorAll("[title]"),
    function (el) {
      var t = el.getAttribute("title");
      var next = translateGameTextToFrench(t);
      if (next !== t) el.setAttribute("title", next);
    }
  );
}

function useGameLanguage(language) {
  React.useEffect(function () {
    if (typeof document === "undefined") return;
    document.documentElement.lang = language === "fr" ? "fr" : "en";
    if (language !== "fr") return;
    var run = function () {
      applyFrenchGameTranslations(document.body);
    };
    run();
    var raf = window.requestAnimationFrame
      ? window.requestAnimationFrame(run)
      : setTimeout(run, 0);
    var timer = setTimeout(run, 80);
    var obs = new MutationObserver(function () {
      if (obs._pending) return;
      obs._pending = true;
      setTimeout(function () {
        obs._pending = false;
        run();
      }, 60);
    });
    obs.observe(document.body, {
      childList: true,
      subtree: true,
      characterData: true,
      attributes: true,
      attributeFilter: ["placeholder", "title"],
    });
    return function () {
      obs.disconnect();
      clearTimeout(timer);
      if (window.cancelAnimationFrame) window.cancelAnimationFrame(raf);
    };
  });
}

