  // ---- Team capacity (NEW): base 10 + HR adds slots by seniority
  var capacity = useMemo(
    function () {
      var cap = 10;
      var hrs = (state.team || []).filter(function (e) {
        return e.role === "hr";
      });
      for (var i = 0; i < hrs.length; i++) {
        var sen = hrs[i].seniority;
        cap +=
          sen === "Intern"
            ? 5
            : sen === "Junior"
            ? 10
            : sen === "Senior"
            ? 15
            : 25;
      }
      return cap;
    },
    [state.team]
  );
  var atCapacity = ((state.team && state.team.length) || 0) >= capacity;

  // === Applicants helpers (NEW) ===
  function teamCapacity(s) {
    var cap = 10; // base
    var hrs = (s.team || []).filter(function (e) {
      return e.role === "hr";
    });
    for (var i = 0; i < hrs.length; i++) {
      var sen = hrs[i].seniority;
      cap +=
        sen === "Intern"
          ? 5
          : sen === "Junior"
          ? 10
          : sen === "Senior"
          ? 15
          : 25;
    }
    return cap;
  }

  function hire(app) {
    if (!app) return;
    var capNow = teamCapacity(state);
    var teamLenNow = (state.team && state.team.length) || 0;
    if (teamLenNow >= capNow) {
      showEmployeeCapacityPopup(capNow);
      setState(function (s) {
        return Object.assign({}, s, {
          lastToast:
            "Headcount cap reached (" + capNow + "). Hire HR to expand.",
        });
      });
      return;
    }
    setState(function (s) {
      var cap = teamCapacity(s);
      var teamLen = (s.team && s.team.length) || 0;
      if (teamLen >= cap) {
        setTimeout(function () {
          showEmployeeCapacityPopup(cap);
        }, 0);
        return Object.assign({}, s, {
          lastToast: "Headcount cap reached (" + cap + "). Hire HR to expand.",
        });
      }

      // avoid duplicates
      var already = (s.team || []).some(function (e) {
        return e.id === app.id;
      });
      if (already) return s;

      var newHire = ensurePersonRecord({
        id: app.id,
        name: app.name,
        role: app.role,
        seniority: app.seniority,
        avatar: app.avatar,
        inSLT: false,
        managerPref: app.managerPref,
        commStyle: app.commStyle,
        temperament: app.temperament,
        morale: app.morale,
        burnout: app.burnout,
        trust: app.trust,
        relationships: app.relationships,
      });

      var nextTeam = (s.team || []).concat([newHire]);
      var nextApplicants = (s.applicants || []).filter(function (a) {
        return a.id !== app.id;
      });

      // HQ feed: hiring feels alive
      var nextFeed = arr(s.hqFeed).slice();
      nextFeed.push({
        id: "hq_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
        ts: valOr(s.currentDate, Date.now()),
        week: valOr(s.week, 0),
        kind: "people",
        from: "People Ops",
        title: "New hire onboarded",
        text:
          newHire.name +
          " joined as " +
          newHire.seniority +
          " " +
          roleLabelForType(s.companyType, newHire.role) +
          ".",
        urgency: 1,
        unread: true,
      });
      if (nextFeed.length > 100) nextFeed = nextFeed.slice(-100);

      return Object.assign({}, s, {
        team: nextTeam,
        applicants: nextApplicants,
        hqFeed: nextFeed,
        boardStats: Object.assign({}, s.boardStats || {}, {
          hires: valOr(s.boardStats && s.boardStats.hires, 0) + 1,
        }),
      });
    });
  }

