  function contractMonthlyRevenue(c) {
    if (!c) return 0;
    if (typeof c.monthlyRevenue === "number") return c.monthlyRevenue;
    if (typeof c.weeklyRevenue === "number") return c.weeklyRevenue; // your code often treats this as monthly already
    if (typeof c.estWeeklyRevenue === "number") return c.estWeeklyRevenue;
    return 0;
  }

  var contractsToShow = (state && state.contracts ? state.contracts : [])
    .filter(function (c) {
      var q = (contractSearch || "").trim().toLowerCase();
      if (!q) return true;
      return (
        String(c.name || "")
          .toLowerCase()
          .includes(q) ||
        String(c.client || "")
          .toLowerCase()
          .includes(q) ||
        String(c.geo || "")
          .toLowerCase()
          .includes(q)
      );
    })
    .slice()
    .sort(function (a, b) {
      if (contractSort === "revenue_desc") {
        return contractMonthlyRevenue(b) - contractMonthlyRevenue(a);
      }
      // weeks_asc default
      return valOr(a.remainingWeeks, 0) - valOr(b.remainingWeeks, 0);
    });

