  /* Finance */
  var [financeView, setFinanceView] = useState("overview");
  var [buybackBudgetInput, setBuybackBudgetInput] = useState("");
  var [loanAmountInput, setLoanAmountInput] = useState("");
  var [loanRepayInputs, setLoanRepayInputs] = useState({});
  var budgetNum = Math.max(0, parseFloat(buybackBudgetInput || "0") || 0);
  var [buybackTarget, setBuybackTarget] = useState("pro-rata");
  var [splitScope, setSplitScope] = useState("ytd"); // "ytd" | "all"
  var [splitGroup, setSplitGroup] = useState("region"); // "region" | "country"
  var [splitRegionFilter, setSplitRegionFilter] = useState("all"); // "all" | region key

  useEffect(
    function () {
      try {
        save(state);
      } catch (e) {}
    },
    [state]
  );

  /* --- Deriveds --- */
  var payroll = useMemo(
    function () {
      return monthlyPayroll(state.team);
    },
    [state.team]
  );
  var weeklyRevenue = useMemo(
    function () {
      var a = state.contracts.reduce(function (s, c) {
        return s + Math.round(c.weeklyRevenue / 4); // convert monthly → weekly
      }, 0);
      var b = state.assetsOwned.reduce(function (s, x) {
        return s + x.revPerWeekBoosted; // assets already /wk
      }, 0);
      return a + b;
    },
    [state.contracts, state.assetsOwned]
  );

  var monthlyRevenue = useMemo(
    function () {
      return weeklyRevenue * 4;
    },
    [weeklyRevenue]
  );

  // Derived: monthly cost + net profit (gross)
  var monthlyCost = React.useMemo(
    function () {
      var hist =
        state.lastMonthlyCost && typeof state.lastMonthlyCost.total === "number"
          ? state.lastMonthlyCost.total
          : null;
      var employees = state.team.length || 0;
      var countries = Math.max(0, (state.unlockedGeos || []).length - 1);
      var officeRun = officeStats(state);
      var estRent = Math.round(
        BASE_RENT +
          employees * RENT_PER_EMPLOYEE +
          countries * RENT_PER_COUNTRY +
          valOr(officeRun && officeRun.rent, 0)
      );
      var runRate =
        monthlyPayroll(state.team) +
        employees * OVERHEAD_PER_EMPLOYEE +
        estRent;

      return typeof hist === "number" ? hist : runRate;
    },
    [state.lastMonthlyCost, state.team, state.rent]
  );

  var monthlyTaxRate = TAX_RATES[state.difficulty || "Normal"] || 0.25;
  var monthlyOperatingProfit = React.useMemo(
    function () {
      return monthlyRevenue - monthlyCost;
    },
    [monthlyRevenue, monthlyCost]
  );
  var monthlyTaxExpense = React.useMemo(
    function () {
      return monthlyOperatingProfit > 0
        ? Math.round(monthlyOperatingProfit * monthlyTaxRate)
        : 0;
    },
    [monthlyOperatingProfit, monthlyTaxRate]
  );
  var netMonthlyIncome = React.useMemo(
    function () {
      return monthlyOperatingProfit - monthlyTaxExpense;
    },
    [monthlyOperatingProfit, monthlyTaxExpense]
  );

  var netMonthlyIncomeMargin = React.useMemo(
    function () {
      return monthlyRevenue > 0 ? (netMonthlyIncome / monthlyRevenue) * 100 : 0;
    },
    [netMonthlyIncome, monthlyRevenue]
  );

  function formatKpiPercent(value) {
    var n = Number.isFinite(value) ? value : 0;
    return n.toLocaleString(undefined, { maximumFractionDigits: 1 }) + "%";
  }

  var previousKpis = state.previousKpis || null;
  function trendFromPrevious(key, current, opts) {
    opts = opts || {};
    if (
      !previousKpis ||
      typeof previousKpis[key] !== "number" ||
      !Number.isFinite(previousKpis[key])
    )
      return null;
    var prev = previousKpis[key];
    var delta = opts.percentChange
      ? prev === 0
        ? 0
        : ((current - prev) / Math.abs(prev)) * 100
      : current - prev;
    return {
      delta: delta,
      suffix: opts.suffix || (opts.percentChange ? "%" : ""),
      isPercent: !!opts.percentChange,
    };
  }

  var financeUnlocked = useMemo(
    function () {
      return isUnlocked(state, "finance"); // VP in Finance OR CFO nominated
    },
    [state.team, state.executives]
  );

  var corpDevExpansionUnlocked = useMemo(
    function () {
      return isUnlocked(state, "corp"); // VP in Corp Dev OR Head of Growth nominated
    },
    [state.team, state.executives]
  );

  var capacity = useMemo(
    function () {
      return calcCapacity(state.team);
    },
    [state.team]
  );

  /* Charts scope (kept simple) */
  var currentYear = new Date(
    valOr(state.currentDate, START_DATE_ISO)
  ).getFullYear();
  var activeAgg =
    financeView === "history"
      ? state.revALL || initRevYTD(0)
      : state.revYTD || initRevYTD(currentYear);
  var allMonths = Object.keys(valOr(activeAgg.monthly, {})).sort();
  var scopeMonths =
    financeView === "history"
      ? allMonths
      : allMonths.filter(function (mk) {
          return mk.indexOf(String(currentYear) + "-") === 0;
        });

  var scopeClientTotals = useMemo(
    function () {
      var obj = valOr(activeAgg.clientsTotal, {});
      var entries = Object.keys(obj).map(function (k) {
        return [k, obj[k]];
      });
      entries.sort(function (a, b) {
        return b[1] - a[1];
      });
      return entries;
    },
    [activeAgg]
  );

  var currentDateObj = new Date(valOr(state.currentDate, GAME_START_DATE));
  var quarterKey = getQuarterKey(currentDateObj);

  /* ---------- Gameplay actions already present elsewhere ---------- */
  // keep your existing big gameplay functions: startIPO, cancelIPO, executeBuyback, processWeek, advanceWeek, resetGame, etc.
  // They should remain identical; we just call them from the new UI.
  // ====== BEGIN: minimal bindings to existing functions you already defined above ======
  function startIPO() {
    setState(function (s) {
      if (s.isPublic || s.ipo || s.cash < IPO_CFG.MIN_CASH) return s;
      var free = freeByRole(s.team, s.fteReserved);
      for (var k in IPO_CFG.REQUIRE) {
        if ((free[k] || 0) < IPO_CFG.REQUIRE[k]) return s;
      }
      var reserved = reserveForLead(s.team, s.fteReserved, IPO_CFG.REQUIRE);
      var rr = annualizedRevenue(s);
      return Object.assign({}, s, {
        cash: s.cash - IPO_CFG.RETAINER,
        fteReserved: reserved,
        ipo: {
          weeksRemaining: IPO_CFG.DURATION_WEEKS,
          reserved: Object.assign({}, IPO_CFG.REQUIRE),
          last8RunRates: [rr],
        },
        lastToast: "IPO kick-off: advisors engaged, team reserved.",
      });
    });
  }

  function cancelIPO() {
    setState(function (s) {
      if (!s.ipo) return s;
      var nextRes = releaseForLead(s.fteReserved, s.ipo.reserved || {});
      return Object.assign({}, s, {
        fteReserved: nextRes,
        ipo: null,
        lastToast: "IPO cancelled. Retainer lost.",
      });
    });
  }

  function executeBuyback() {
    var summary = null;
    setState(function (s) {
      if (!s.isPublic || !s.sharePrice)
        return Object.assign({}, s, { lastToast: "Not public yet." });
      var price = s.sharePrice || 0;
      var budget = Math.max(0, +budgetNum || 0);
      var estShares = price > 0 ? Math.floor(budget / price) : 0;
      if (budget <= 0 || estShares <= 0)
        return Object.assign({}, s, { lastToast: "Enter a positive budget." });
      if (budget > s.cash)
        return Object.assign({}, s, {
          lastToast: "Insufficient cash for buyback.",
        });

      var holders = arr(s.shareholders).slice();
      var sellersPool = holders.filter(function (h) {
        return h.name !== "You" && (h.shares || 0) > 0;
      });
      if (!sellersPool.length)
        return Object.assign({}, s, {
          lastToast: "No market float to buy from.",
        });

      var takes = [];
      var taken = 0;

      if (buybackTarget && buybackTarget !== "pro-rata") {
        var target = sellersPool.find(function (h) {
          return h.id === buybackTarget;
        });
        if (!target)
          return Object.assign({}, s, {
            lastToast: "Selected holder not found.",
          });
        taken = Math.min(target.shares, estShares);
        if (taken <= 0)
          return Object.assign({}, s, { lastToast: "Nothing to repurchase." });
        takes = [{ id: target.id, amount: taken }];
      } else {
        var avail = sellersPool.reduce(function (a, b) {
          return a + (b.shares || 0);
        }, 0);
        taken = Math.min(estShares, avail);
        if (taken <= 0)
          return Object.assign({}, s, { lastToast: "Nothing to repurchase." });
        var split = splitProRata(sellersPool, taken);
        takes = split.takes;
      }

      var takeMap = new Map(
        takes.map(function (t) {
          return [t.id, t.amount];
        })
      );
      for (var i = 0; i < holders.length; i++) {
        var h = holders[i];
        var amt = valOr(takeMap.get(h.id), 0);
        if (amt > 0)
          holders[i] = Object.assign({}, h, {
            shares: Math.max(0, (h.shares || 0) - amt),
          });
      }

      var newOut = Math.max(0, (s.sharesOutstanding || 0) - taken);
      var cost = Math.round(taken * price);
      summary = { taken: taken, price: price, cost: cost };

      var hostile = null;
      if (newOut > 0) {
        var found = holders.find(function (h) {
          return h.name !== "You" && (h.shares || 0) / newOut > 0.7;
        });
        if (found) hostile = found;
      }
      return Object.assign({}, s, {
        shareholders: holders,
        sharesOutstanding: newOut,
        cash: s.cash - cost,
        lastToast: hostile
          ? "Hostile takeover triggered."
          : "Buyback executed.",
        gameOver: hostile ? true : s.gameOver,
        gameOverReason: hostile
          ? {
              type: "hostile",
              title: "Hostile Takeover — Game Over",
              body: hostile.name + " exceeded 70% of outstanding shares.",
            }
          : s.gameOverReason,
      });
    });
    if (summary) {
      setLog(function (l) {
        var line =
          "Buyback: repurchased " +
          summary.taken.toLocaleString() +
          " shares @ €" +
          summary.price.toFixed(2) +
          " → -€" +
          summary.cost.toLocaleString();
        var next = [line].concat(l);
        return next.slice(0, 300);
      });
    }
  }

  function advanceWeek() {
    setState(function (prev) {
      if (prev.gameOver || !prev.hasStarted) return prev;
      var cloned = JSON.parse(JSON.stringify(prev));
      var prevWeeklyRevenue =
        arr(prev.contracts).reduce(function (sum, c) {
          return sum + Math.round(valOr(c && c.weeklyRevenue, 0) / 4);
        }, 0) +
        arr(prev.assetsOwned).reduce(function (sum, x) {
          return sum + valOr(x && x.revPerWeekBoosted, 0);
        }, 0);
      var prevMonthlyRevenue = prevWeeklyRevenue * 4;
      var prevMonthlyCost =
        prev.lastMonthlyCost && typeof prev.lastMonthlyCost.total === "number"
          ? prev.lastMonthlyCost.total
          : monthlyPayroll(arr(prev.team)) +
            arr(prev.team).length * OVERHEAD_PER_EMPLOYEE +
            Math.round(
              BASE_RENT +
                arr(prev.team).length * RENT_PER_EMPLOYEE +
                Math.max(0, arr(prev.unlockedGeos).length - 1) *
                  RENT_PER_COUNTRY
            );
      var prevOperatingProfit = prevMonthlyRevenue - prevMonthlyCost;
      var prevTaxRate = TAX_RATES[prev.difficulty || "Normal"] || 0.25;
      var prevTaxExpense =
        prevOperatingProfit > 0
          ? Math.round(prevOperatingProfit * prevTaxRate)
          : 0;
      var prevNet = prevOperatingProfit - prevTaxExpense;
      cloned.previousKpis = {
        cash: valOr(prev.cash, 0),
        monthlyRevenue: prevMonthlyRevenue,
        monthlyCost: prevMonthlyCost,
        netProfit: prevNet,
        netMargin: prevMonthlyRevenue
          ? (prevNet / prevMonthlyRevenue) * 100
          : 0,
      };
      refreshApplicantsWeekly(cloned);
      var r = processWeek(cloned);
      var events = r.events || [];
      cloned.revenueYTD =
        valOr(cloned.revenueYTD, 0) + valOr(r.weeklyRevenueTotal, 0);

      /* IPO market move handled in processWeek; keep log feed */
      setLog(function (l) {
        var next = ["Week " + (cloned.week - 1) + " → " + cloned.week]
          .concat(events)
          .concat(l);
        return next.slice(0, 300);
      });
      return cloned;
    });
  }

