  /* ---------- Bulk actions you asked for ---------- */

  // Compute free-by-role using a temp reserved map (no ??, no ?.)
  function tempFreeByRole(team, reservedMap) {
    var totals = countByRole(team);
    var free = {};
    Object.keys(totals).forEach(function (k) {
      var used = arr(reservedMap[k]).length;
      free[k] = Math.max(0, totals[k] - used);
    });
    for (var i = 0; i < ROLES.length; i++) {
      var rk = ROLES[i].key;
      if (!(rk in free)) free[rk] = 0;
    }
    return free;
  }

  function bulkAddStaffableLeads() {
    setState(function (s) {
      var leads = s.leadsAvailable.slice();
      var pipeline = s.pipeline.slice();
      var reserved = Object.assign({}, s.fteReserved);
      var team = s.team.slice();
      var added = 0;

      for (var i = 0; i < leads.length; i++) {
        var l = leads[i];
        if (!l) continue;
        if (s.unlockedGeos.indexOf(l.geo) === -1) continue;

        var req =
          l.req || scaledReqForArea(l.area, l.tier || "small", s.companyType);
        var free = tempFreeByRole(team, reserved);
        if (!canStaff(free, req)) continue;

        reserved = reserveForLead(team, reserved, req);
        pipeline.push(makePipelineItemGlobal(l, req));
        leads[i] = null;
        added += 1;
      }

      var newLeads = leads.filter(function (x) {
        return !!x;
      });
      if (added === 0)
        return Object.assign({}, s, {
          lastToast: "No staffable leads right now.",
        });
      return Object.assign({}, s, {
        leadsAvailable: newLeads,
        pipeline: pipeline,
        fteReserved: reserved,
        lastToast: "Added " + added + " lead(s) to pipeline.",
      });
    });
  }

