  // Create a pipeline item from a lead (BD cycle tracked over weeks)

  function makePipelineItem(lead, req) {
    var l = lead || {};
    var _req = req || l.req || {};
    var minDecisionWeeks =
      typeof l.minDecisionWeeks === "number"
        ? l.minDecisionWeeks
        : minDecisionWeeksFromReq(_req);
    var decisionAtWeeks =
      typeof l.decisionAtWeeks === "number"
        ? l.decisionAtWeeks
        : minDecisionWeeks + Math.floor(Math.random() * 6) + 2;

    // Make sure the pipeline item always has the fields the UI + simulation expects.
    var estWeeklyRevenue = valOr(
      l.estWeeklyRevenue,
      l.monthly ? Math.round(l.monthly / 4) : 0
    );
    var durationWeeks = valOr(l.durationWeeks, 8);
    var winChance = valOr(
      l.winChance,
      l.winRateBase ? Math.round(l.winRateBase * 100) : 12
    );

    return Object.assign({}, l, {
      req: _req,
      estWeeklyRevenue: estWeeklyRevenue,
      durationWeeks: durationWeeks,
      winChance: winChance,
      dealType: l.dealType || null,
      bdlTerms: l.bdlTerms || null,
      grossEstWeeklyRevenue: l.grossEstWeeklyRevenue || null,
      progressWeeks: 0,
      weeksInPipeline: 0,
      minDecisionWeeks: minDecisionWeeks,
      decisionAtWeeks: decisionAtWeeks,
    });
  }

  function addLeadToPipeline(leadId) {
    var previewLead = arr(state.leadsAvailable).find(function (l) {
      return l.id === leadId;
    });
    if (previewLead && isBDLLicensingDeal(previewLead)) {
      setBdlDealModal({
        leadId: leadId,
        upfrontPayment: valOr(
          previewLead.suggestedUpfront,
          bdlSuggestedUpfront(previewLead)
        ),
        royaltyRate: valOr(previewLead.suggestedRoyalty, 15),
      });
      return;
    }

    setState(function (s) {
      var lead = s.leadsAvailable.find(function (l) {
        return l.id === leadId;
      });
      if (!lead) return s;
      if (s.unlockedGeos.indexOf(lead.geo) === -1) return s;
      var req =
        lead.req ||
        scaledReqForArea(lead.area, valOr(lead.tier, "small"), s.companyType);
      var free = freeByRole(s.team, s.fteReserved);
      if (!canStaff(free, req)) return s;
      var rest = s.leadsAvailable.filter(function (l) {
        return l.id !== leadId;
      });
      var pi = makePipelineItem(lead, req);

      var bs = Object.assign({}, s.boardStats || {});
      bs.pipelineAdded = (bs.pipelineAdded || 0) + 1;

      return Object.assign({}, s, {
        leadsAvailable: rest,
        pipeline: s.pipeline.concat([pi]),
        fteReserved: reserveForLead(s.team, s.fteReserved, req),
        boardStats: bs,
      });
    });
  }

  function confirmBDLLicensingDeal(leadId, terms) {
    setState(function (s) {
      var lead = arr(s.leadsAvailable).find(function (l) {
        return l.id === leadId;
      });
      if (!lead) return s;
      if (arr(s.unlockedGeos).indexOf(lead.geo) === -1) {
        return Object.assign({}, s, {
          lastToast: "Unlock " + lead.geo + " before adding this BD&L deal.",
        });
      }
      var req =
        lead.req ||
        scaledReqForArea(lead.area, valOr(lead.tier, "small"), s.companyType);
      var free = freeByRole(s.team, s.fteReserved);
      if (!canStaff(free, req)) {
        return Object.assign({}, s, {
          lastToast: "Not enough team capacity for this BD&L deal.",
        });
      }
      var normalizedTerms = bdlNormalizeTerms(lead, terms || {});
      var econ = bdlDealEconomics(lead, normalizedTerms);
      var effectiveWin = bdlWinChanceFromTerms(lead, normalizedTerms);
      var storedTerms = Object.assign({}, normalizedTerms, {
        paidOnWin: true,
        launchCost: econ.launchCost,
        signingCashOut: econ.signingCashOut,
        milestonePayment: econ.milestonePayment,
        milestonePaid: false,
        grossMonthlyAtSigning: econ.grossMonthly,
        netMonthlyAtSigning: econ.netMonthly,
        approxNetValue: econ.approxNetValue,
        risk: econ.risk,
      });
      var structuredLead = Object.assign({}, lead, {
        dealType: "bdl_licensing",
        title: lead.title || lead.name,
        name: lead.name || lead.title,
        baseWinChance: valOr(lead.baseWinChance, lead.winChance),
        grossEstWeeklyRevenue: econ.grossMonthly,
        estWeeklyRevenue: econ.netMonthly,
        winChance: effectiveWin,
        bdlTerms: storedTerms,
      });
      var rest = arr(s.leadsAvailable).filter(function (l) {
        return l.id !== leadId;
      });
      var pi = makePipelineItem(structuredLead, req);
      pi.originalDurationWeeks = pi.durationWeeks;
      var bs = Object.assign({}, s.boardStats || {});
      bs.pipelineAdded = (bs.pipelineAdded || 0) + 1;
      return Object.assign({}, s, {
        leadsAvailable: rest,
        pipeline: arr(s.pipeline).concat([pi]),
        fteReserved: reserveForLead(s.team, s.fteReserved, req),
        boardStats: bs,
        lastToast:
          "BD&L deal added: " +
          bdlTermsSummary(pi.bdlTerms) +
          " · win chance " +
          effectiveWin +
          "%.",
      });
    });
    setBdlDealModal(null);
  }

